"use client";

import { useState, useMemo, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { emisAPI } from "@/services/api";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Input, Badge, Progress } from "@/components/ui";
import { Calculator, Plus, CreditCard, Calendar, IndianRupee, TrendingDown, X } from "lucide-react";
import toast from "react-hot-toast";

interface EMI {
  id: string;
  cardId: string;
  description: string;
  totalAmount: number;
  emiAmount: number;
  tenure: number;
  monthsPaid: number;
  interestRate: number;
  startDate: string;
}

export default function EMIsPage() {
  const { creditCards } = useData();
  const queryClient = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({
    cardId: "",
    description: "",
    totalAmount: "",
    emiAmount: "",
    tenure: "",
    monthsPaid: "",
    interestRate: "",
    startDate: new Date().toISOString().split("T")[0],
  });

  // Fetch EMIs from Firestore
  const { data: emisData, isLoading } = useQuery({
    queryKey: ["emis"],
    queryFn: async () => {
      const res = await emisAPI.list();
      return (res.emis || []) as EMI[];
    },
  });

  const emis = emisData || [];

  // One-time migration from localStorage ΓåÆ Firestore
  useEffect(() => {
    if (isLoading) return;
    try {
      const stored = localStorage.getItem("wf_emis");
      if (!stored) return;
      const localEMIs: EMI[] = JSON.parse(stored);
      if (localEMIs.length === 0) return;
      // Only migrate if Firestore is empty (avoid duplicates)
      if (emis.length > 0) {
        localStorage.removeItem("wf_emis");
        return;
      }
      // Migrate each
      Promise.all(
        localEMIs.map((emi) =>
          emisAPI.create({
            cardId: emi.cardId,
            description: emi.description,
            totalAmount: emi.totalAmount,
            emiAmount: emi.emiAmount,
            tenure: emi.tenure,
            monthsPaid: emi.monthsPaid,
            interestRate: emi.interestRate,
            startDate: emi.startDate,
          })
        )
      ).then(() => {
        localStorage.removeItem("wf_emis");
        queryClient.invalidateQueries({ queryKey: ["emis"] });
        toast.success("EMIs migrated to cloud sync");
      });
    } catch { /* ignore */ }
  }, [isLoading, emis.length, queryClient]);

  // Set default cardId when creditCards load
  useEffect(() => {
    if (creditCards.length > 0 && !form.cardId) {
      setForm((f) => ({ ...f, cardId: creditCards[0].id }));
    }
  }, [creditCards, form.cardId]);

  const createMutation = useMutation({
    mutationFn: (data: Record<string, unknown>) => emisAPI.create(data),
    onSuccess: () => {
      toast.success("EMI added");
      setShowAdd(false);
      setForm({ cardId: creditCards[0]?.id || "", description: "", totalAmount: "", emiAmount: "", tenure: "", monthsPaid: "", interestRate: "", startDate: new Date().toISOString().split("T")[0] });
      queryClient.invalidateQueries({ queryKey: ["emis"] });
    },
    onError: (err: Error) => toast.error(err.message),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Record<string, unknown> }) => emisAPI.update(id, data),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["emis"] }),
    onError: (err: Error) => toast.error(err.message),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => emisAPI.delete(id),
    onSuccess: () => {
      toast.success("Deleted");
      queryClient.invalidateQueries({ queryKey: ["emis"] });
    },
    onError: (err: Error) => toast.error(err.message),
  });

  const addEMI = () => {
    createMutation.mutate({
      cardId: form.cardId,
      description: form.description,
      totalAmount: parseFloat(form.totalAmount) || 0,
      emiAmount: parseFloat(form.emiAmount) || 0,
      tenure: parseInt(form.tenure) || 0,
      monthsPaid: parseInt(form.monthsPaid) || 0,
      interestRate: parseFloat(form.interestRate) || 0,
      startDate: form.startDate,
    });
  };

  const deleteEMI = (id: string) => deleteMutation.mutate(id);

  const incrementMonth = (id: string) => {
    const emi = emis.find((e) => e.id === id);
    if (!emi) return;
    updateMutation.mutate({ id, data: { monthsPaid: Math.min(emi.monthsPaid + 1, emi.tenure) } });
  };

  // Summary
  const summary = useMemo(() => {
    const active = emis.filter((e) => e.monthsPaid < e.tenure);
    const totalMonthlyOutflow = active.reduce((s, e) => s + e.emiAmount, 0);
    const totalOutstanding = active.reduce((s, e) => s + (e.emiAmount * (e.tenure - e.monthsPaid)), 0);
    const totalInterest = active.reduce((s, e) => {
      const principal = e.totalAmount;
      const totalPay = e.emiAmount * e.tenure;
      return s + (totalPay - principal);
    }, 0);
    const closestClosure = active.reduce((closest, e) => {
      const remaining = e.tenure - e.monthsPaid;
      return remaining < closest ? remaining : closest;
    }, 999);
    return { active: active.length, totalMonthlyOutflow, totalOutstanding, totalInterest, closestClosure };
  }, [emis]);

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex justify-between items-center">
        <p className="text-sm text-muted-foreground">{summary.active} active EMIs</p>
        <Button onClick={() => setShowAdd(!showAdd)} className="gap-1.5">
          <Plus className="w-4 h-4" /> Add EMI
        </Button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <IndianRupee className="w-3.5 h-3.5 text-danger" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Monthly Outflow</span>
            </div>
            <p className="text-lg font-bold text-danger">{fmt(summary.totalMonthlyOutflow)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <TrendingDown className="w-3.5 h-3.5 text-warning" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Outstanding</span>
            </div>
            <p className="text-lg font-bold text-warning">{fmt(summary.totalOutstanding)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <Calculator className="w-3.5 h-3.5 text-accent" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Total Interest</span>
            </div>
            <p className="text-lg font-bold text-accent">{fmt(summary.totalInterest)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <Calendar className="w-3.5 h-3.5 text-info" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Next Closure</span>
            </div>
            <p className="text-lg font-bold text-info">{summary.closestClosure < 999 ? `${summary.closestClosure} mo` : "ΓÇö"}</p>
          </CardContent>
        </Card>
      </div>

      {/* Add EMI Form */}
      {showAdd && (
        <Card className="border-brand/20">
          <CardContent className="p-5 space-y-3">
            <h3 className="text-sm font-semibold text-foreground">New EMI</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <select
                value={form.cardId}
                onChange={(e) => setForm({ ...form, cardId: e.target.value })}
                className="h-9 px-3 rounded-lg border border-input bg-card text-sm text-foreground"
              >
                {creditCards.map((cc) => (
                  <option key={cc.id} value={cc.id}>{cc.account_name}</option>
                ))}
              </select>
              <Input value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="Description (e.g. iPhone 15)" />
              <Input type="number" value={form.totalAmount} onChange={(e) => setForm({ ...form, totalAmount: e.target.value })} placeholder="Total Amount (Γé╣)" />
              <Input type="number" value={form.emiAmount} onChange={(e) => setForm({ ...form, emiAmount: e.target.value })} placeholder="EMI Amount/month (Γé╣)" />
              <Input type="number" value={form.tenure} onChange={(e) => setForm({ ...form, tenure: e.target.value })} placeholder="Tenure (months)" />
              <Input type="number" value={form.monthsPaid} onChange={(e) => setForm({ ...form, monthsPaid: e.target.value })} placeholder="Months already paid" />
              <Input type="number" value={form.interestRate} onChange={(e) => setForm({ ...form, interestRate: e.target.value })} placeholder="Interest rate % (0 for no-cost)" />
              <Input type="date" value={form.startDate} onChange={(e) => setForm({ ...form, startDate: e.target.value })} />
            </div>
            <div className="flex gap-2">
              <Button size="sm" onClick={addEMI}>Add EMI</Button>
              <Button variant="ghost" size="sm" onClick={() => setShowAdd(false)}>Cancel</Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Active EMIs */}
      {emis.filter((e) => e.monthsPaid < e.tenure).length > 0 && (
        <div className="space-y-3">
          <h3 className="text-[11px] font-semibold uppercase text-muted-foreground">Active EMIs</h3>
          {emis.filter((e) => e.monthsPaid < e.tenure).map((emi) => {
            const card = creditCards.find((c) => c.id === emi.cardId);
            const remaining = emi.tenure - emi.monthsPaid;
            const progressPct = (emi.monthsPaid / emi.tenure) * 100;
            const outstandingAmt = emi.emiAmount * remaining;
            const totalInterest = (emi.emiAmount * emi.tenure) - emi.totalAmount;
            const closureDate = new Date(emi.startDate);
            closureDate.setMonth(closureDate.getMonth() + emi.tenure);

            return (
              <Card key={emi.id} className="group">
                <CardContent className="p-4">
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-lg bg-accent/10 flex items-center justify-center">
                        <CreditCard className="w-4.5 h-4.5 text-accent" />
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-foreground">{emi.description}</p>
                        <p className="text-[11px] text-muted-foreground">{card?.account_name || "Unknown Card"} ┬╖ {emi.interestRate > 0 ? `${emi.interestRate}% p.a.` : "No-cost"}</p>
                      </div>
                    </div>
                    <div className="flex gap-1">
                      <Button variant="outline" size="sm" className="h-7 text-[10px]" onClick={() => incrementMonth(emi.id)}>+1 month</Button>
                      <button onClick={() => deleteEMI(emi.id)} className="p-1.5 text-danger/50 hover:text-danger transition-colors opacity-0 group-hover:opacity-100"><X className="w-3.5 h-3.5" /></button>
                    </div>
                  </div>

                  {/* Progress */}
                  <div className="mb-3">
                    <div className="flex justify-between text-[10px] text-muted-foreground mb-1">
                      <span>{emi.monthsPaid}/{emi.tenure} months</span>
                      <span>{remaining} remaining</span>
                    </div>
                    <Progress value={progressPct} className="h-2" indicatorClassName={progressPct > 75 ? "bg-success" : progressPct > 40 ? "bg-brand" : "bg-warning"} />
                  </div>

                  {/* Stats */}
                  <div className="grid grid-cols-4 gap-2">
                    <div className="text-center">
                      <p className="text-[10px] text-muted-foreground uppercase">EMI</p>
                      <p className="text-xs font-bold text-foreground">{fmt(emi.emiAmount)}</p>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] text-muted-foreground uppercase">Outstanding</p>
                      <p className="text-xs font-bold text-danger">{fmt(outstandingAmt)}</p>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] text-muted-foreground uppercase">Interest</p>
                      <p className="text-xs font-bold text-warning">{fmt(totalInterest)}</p>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] text-muted-foreground uppercase">Closes</p>
                      <p className="text-xs font-bold text-info">{closureDate.toLocaleDateString("en-IN", { month: "short", year: "numeric" })}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Completed EMIs */}
      {emis.filter((e) => e.monthsPaid >= e.tenure).length > 0 && (
        <div className="space-y-2">
          <h3 className="text-[11px] font-semibold uppercase text-muted-foreground">Completed</h3>
          {emis.filter((e) => e.monthsPaid >= e.tenure).map((emi) => (
            <Card key={emi.id} className="opacity-60">
              <CardContent className="p-3 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Badge variant="success" className="text-[9px]">Done</Badge>
                  <span className="text-sm font-medium text-foreground">{emi.description}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-xs text-muted-foreground">{fmt(emi.totalAmount)}</span>
                  <button onClick={() => deleteEMI(emi.id)} className="p-1 text-muted-foreground hover:text-danger"><X className="w-3.5 h-3.5" /></button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Empty State */}
      {emis.length === 0 && !showAdd && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-16">
            <Calculator className="w-12 h-12 text-muted-foreground/50 mb-4" />
            <p className="text-lg font-semibold text-foreground">No EMIs Tracked</p>
            <p className="text-sm text-muted-foreground mt-1">Add your credit card EMIs to track tenure, outflow, and closure timeline.</p>
            <Button onClick={() => setShowAdd(true)} variant="outline" className="mt-4 gap-1.5">
              <Plus className="w-4 h-4" /> Add EMI
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { calculateCreditCardHealth } from "@/utils/calculations";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Badge, Progress } from "@/components/ui";
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";
import { Lightbulb, TrendingUp, AlertTriangle, CreditCard } from "lucide-react";

export default function CCInsightsPage() {
  const { creditCards, transactions, cycleStartDay } = useData();

  const cycles = useMemo(() => getRecentFinancialMonths(6, new Date(), cycleStartDay), [cycleStartDay]);

  // CC spending trend over last 6 cycles
  const spendingTrend = useMemo(() => {
    return cycles.map((c) => {
      const cycleSpend = transactions
        .filter((t) => t.date >= c.startDate && t.date <= c.endDate && (t.payment_type === "Credit Card" || creditCards.some((cc) => cc.id === t.account_id)) && t.amount < 0)
        .reduce((s, t) => s + Math.abs(t.amount), 0);
      return { label: c.label.split(" ")[0].slice(0, 3), spend: cycleSpend };
    }).reverse();
  }, [transactions, creditCards, cycles]);

  // Per-card utilization insights
  const cardInsights = useMemo(() => {
    return creditCards.map((cc) => {
      const health = calculateCreditCardHealth(cc, creditCards);
      const limit = parseFloat(String(cc.credit_limit || 0));
      const outstanding = parseFloat(String(cc.liability || cc.balance || 0));
      return {
        name: cc.account_name,
        utilization: health.utilization,
        outstanding,
        limit,
        risk: health.utilization > 30,
      };
    });
  }, [creditCards]);

  // Generate insight messages
  const insights = useMemo(() => {
    const msgs: Array<{ type: "warning" | "success" | "info"; message: string }> = [];
    const totalUtil = creditCards.reduce((s, c) => s + parseFloat(String(c.liability || c.balance || 0)), 0) /
      Math.max(1, creditCards.reduce((s, c) => s + parseFloat(String(c.credit_limit || 0)), 0)) * 100;

    if (totalUtil > 30) msgs.push({ type: "warning", message: `Overall utilization is ${totalUtil.toFixed(0)}%. Aim to keep it below 30% for a healthy credit score.` });
    else msgs.push({ type: "success", message: `Good job! Your overall CC utilization is a healthy ${totalUtil.toFixed(0)}%.` });

    cardInsights.forEach((c) => {
      if (c.utilization > 70) msgs.push({ type: "warning", message: `${c.name} is at ${c.utilization.toFixed(0)}% utilization. Consider paying it down.` });
    });

    if (spendingTrend.length >= 2) {
      const last = spendingTrend[spendingTrend.length - 1].spend;
      const prev = spendingTrend[spendingTrend.length - 2].spend;
      if (prev > 0 && last > prev * 1.2) msgs.push({ type: "warning", message: "CC spending increased 20%+ vs last cycle." });
      else if (prev > 0 && last < prev * 0.8) msgs.push({ type: "success", message: "CC spending decreased significantly. Well done!" });
    }

    if (msgs.length === 0) msgs.push({ type: "info", message: "Your credit card usage looks healthy." });
    return msgs;
  }, [creditCards, cardInsights, spendingTrend]);

  return (
    <div className="space-y-4">
      {/* Insights */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Lightbulb className="w-4 h-4 text-brand" /> Insights
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          {insights.map((insight, i) => (
            <div key={i} className={cn("flex items-start gap-2 p-3 rounded-lg border", insight.type === "success" ? "bg-success/5 border-success/20" : insight.type === "warning" ? "bg-warning/5 border-warning/20" : "bg-info/5 border-info/20")}>
              {insight.type === "warning" ? <AlertTriangle className="w-4 h-4 text-warning mt-0.5" /> : <TrendingUp className="w-4 h-4 text-success mt-0.5" />}
              <p className="text-sm text-foreground">{insight.message}</p>
            </div>
          ))}
        </CardContent>
      </Card>

      {/* Spending Trend */}
      <Card>
        <CardHeader>
          <CardTitle>CC Spending Trend</CardTitle>
        </CardHeader>
        <CardContent>
          {spendingTrend.some((s) => s.spend > 0) ? (
            <div className="h-[200px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={spendingTrend}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis dataKey="label" tick={{ fontSize: 11 }} className="fill-muted-foreground" />
                  <YAxis tick={{ fontSize: 11 }} className="fill-muted-foreground" tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
                  <Tooltip formatter={(value) => fmt(Number(value))} />
                  <Bar dataKey="spend" fill="hsl(var(--brand))" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <p className="text-sm text-muted-foreground text-center py-8">No CC spending data yet</p>
          )}
        </CardContent>
      </Card>

      {/* Per-Card Utilization */}
      <Card>
        <CardHeader>
          <CardTitle>Card Utilization</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {cardInsights.map((card) => (
            <div key={card.name} className="flex items-center gap-3">
              <CreditCard className="w-4 h-4 text-muted-foreground flex-shrink-0" />
              <div className="flex-1 min-w-0">
                <div className="flex justify-between text-sm mb-1">
                  <span className="font-medium text-foreground truncate">{card.name}</span>
                  <span className={cn("text-xs font-semibold", card.utilization > 50 ? "text-danger" : card.utilization > 30 ? "text-warning" : "text-success")}>
                    {card.utilization.toFixed(0)}%
                  </span>
                </div>
                <Progress value={card.utilization} className="h-1.5" indicatorClassName={card.utilization > 50 ? "bg-danger" : card.utilization > 30 ? "bg-warning" : "bg-success"} />
              </div>
            </div>
          ))}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getFinancialCycle, getRecentFinancialMonths } from "@/utils/financialMonth";
import { calculateCreditCardHealth } from "@/utils/calculations";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Badge, Progress } from "@/components/ui";
import { CreditCard, AlertTriangle, Calendar, TrendingUp } from "lucide-react";
import { BarChart, Bar, XAxis, ResponsiveContainer, Tooltip } from "recharts";

export default function CreditCardsOverview() {
  const { creditCards, transactions, cycleStartDay } = useData();
  const currentCycle = useMemo(() => getFinancialCycle(new Date(), cycleStartDay), [cycleStartDay]);

  const totalLimit = creditCards.reduce((s, c) => s + parseFloat(String(c.credit_limit || 0)), 0);
  const totalOutstanding = creditCards.reduce((s, c) => s + parseFloat(String(c.liability || c.balance || 0)), 0);
  const totalAvailable = totalLimit - totalOutstanding;
  const overallUtilization = totalLimit > 0 ? (totalOutstanding / totalLimit) * 100 : 0;

  // Per-card stats
  const cardStats = useMemo(() => {
    return creditCards.map((cc) => {
      const health = calculateCreditCardHealth(cc, creditCards);
      const limit = parseFloat(String(cc.credit_limit || 0));
      const outstanding = parseFloat(String(cc.liability || cc.balance || 0));
      const available = limit - outstanding;

      // Cycle spending for this card
      const cycleSpend = transactions
        .filter((t) => t.account_id === cc.id && t.date >= currentCycle.startDate && t.date <= currentCycle.endDate && t.amount < 0)
        .reduce((s, t) => s + Math.abs(t.amount), 0);

      return {
        ...cc,
        limit,
        outstanding,
        available,
        utilization: health.utilization,
        cycleSpend,
        dueDate: (cc as unknown as Record<string, unknown>).due_days_after ? `${(cc as unknown as Record<string, unknown>).due_days_after} days after billing` : "N/A",
      };
    });
  }, [creditCards, transactions, currentCycle]);

  // Monthly CC spend trend
  const spendTrend = useMemo(() => {
    const cycles = getRecentFinancialMonths(6, new Date(), cycleStartDay);
    return cycles.map((cycle) => {
      const spend = transactions
        .filter((t) => creditCards.some((c) => c.id === t.account_id) && t.amount < 0 && t.date >= cycle.startDate && t.date <= cycle.endDate && t.category !== "Credit Card Payment")
        .reduce((s, t) => s + Math.abs(t.amount), 0);
      return { label: cycle.label.split(" ")[0], spend };
    }).reverse();
  }, [transactions, creditCards, cycleStartDay]);

  if (creditCards.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center justify-center py-16">
          <CreditCard className="w-12 h-12 text-muted-foreground/50 mb-4" />
          <p className="text-lg font-semibold text-foreground">No Credit Cards</p>
          <p className="text-sm text-muted-foreground mt-1">Add a credit card from Settings to get started.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Total Limit</span>
            <p className="text-xl font-bold text-foreground mt-1">{fmt(totalLimit)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Outstanding</span>
            <p className="text-xl font-bold text-danger mt-1">{fmt(totalOutstanding)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Available</span>
            <p className="text-xl font-bold text-success mt-1">{fmt(totalAvailable)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Utilization</span>
            <p className={cn("text-xl font-bold mt-1", overallUtilization > 50 ? "text-danger" : overallUtilization > 30 ? "text-warning" : "text-success")}>
              {overallUtilization.toFixed(1)}%
            </p>
            <Progress
              value={overallUtilization}
              className="mt-2 h-1.5"
              indicatorClassName={overallUtilization > 50 ? "bg-danger" : overallUtilization > 30 ? "bg-warning" : "bg-success"}
            />
          </CardContent>
        </Card>
      </div>

      {/* Per-Card Details */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {cardStats.map((card) => (
          <Card key={card.id} className="group hover:border-brand/30 transition-colors">
            <CardContent className="p-5">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-brand to-accent flex items-center justify-center">
                    <CreditCard className="w-5 h-5 text-white" />
                  </div>
                  <div>
                    <p className="font-semibold text-foreground">{card.account_name}</p>
                    <p className="text-[11px] text-muted-foreground">Limit: {fmt(card.limit)}</p>
                  </div>
                </div>
                <Badge variant={card.utilization > 50 ? "danger" : card.utilization > 30 ? "warning" : "success"}>
                  {card.utilization.toFixed(0)}%
                </Badge>
              </div>

              {/* Usage bar */}
              <div className="mb-4">
                <div className="flex justify-between text-xs text-muted-foreground mb-1">
                  <span>Used: {fmt(card.outstanding)}</span>
                  <span>Available: {fmt(card.available)}</span>
                </div>
                <Progress
                  value={card.utilization}
                  className="h-2.5 rounded-full"
                  indicatorClassName={cn("rounded-full", card.utilization > 50 ? "bg-danger" : card.utilization > 30 ? "bg-warning" : "bg-success")}
                />
              </div>

              {/* Stats */}
              <div className="grid grid-cols-3 gap-2">
                <div className="rounded-lg bg-muted/50 p-2.5 text-center">
                  <p className="text-[10px] text-muted-foreground uppercase">This Cycle</p>
                  <p className="text-sm font-semibold text-foreground">{fmt(card.cycleSpend)}</p>
                </div>
                <div className="rounded-lg bg-muted/50 p-2.5 text-center">
                  <p className="text-[10px] text-muted-foreground uppercase">Outstanding</p>
                  <p className="text-sm font-semibold text-danger">{fmt(card.outstanding)}</p>
                </div>
                <div className="rounded-lg bg-muted/50 p-2.5 text-center">
                  <p className="text-[10px] text-muted-foreground uppercase">Due</p>
                  <p className="text-sm font-semibold text-foreground">{card.dueDate}</p>
                </div>
              </div>

              {/* Alerts */}
              {card.utilization > 50 && (
                <div className="mt-3 flex items-center gap-2 text-[11px] text-warning bg-warning/5 p-2 rounded-lg border border-warning/20">
                  <AlertTriangle className="w-3.5 h-3.5" />
                  <span>High utilization ΓÇö consider paying down to reduce credit score impact</span>
                </div>
              )}
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Monthly CC Spend Trend */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm flex items-center gap-2">
            <TrendingUp className="w-4 h-4 text-muted-foreground" /> CC Spend Trend (6 Cycles)
          </CardTitle>
        </CardHeader>
        <CardContent className="p-4 pt-0">
          <div className="h-[140px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={spendTrend}>
                <XAxis dataKey="label" tick={{ fontSize: 11 }} axisLine={false} tickLine={false} />
                <Tooltip formatter={(v) => fmt(Number(v))} />
                <Bar dataKey="spend" fill="var(--color-accent)" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Badge } from "@/components/ui";
import { Gift, CreditCard, TrendingUp, Sparkles, IndianRupee } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Tooltip } from "recharts";

// Reward rate assumptions (typical Indian CC market)
const DEFAULT_REWARD_RATE = 0.01; // 1 point per Γé╣100 = ~0.25% value
const CATEGORY_MULTIPLIERS: Record<string, number> = {
  Food: 2, Travel: 5, Shopping: 2, Entertainment: 3,
  Petrol: 2, Utilities: 1, Bills: 1, Subscription: 1,
};
const POINT_VALUE = 0.25; // Γé╣0.25 per reward point

export default function RewardsPage() {
  const { creditCards, transactions, cycleStartDay } = useData();
  const [selectedCardId, setSelectedCardId] = useState<string>("all");

  const recentCycles = useMemo(() => getRecentFinancialMonths(6, new Date(), cycleStartDay), [cycleStartDay]);

  // Calculate rewards per card
  const rewardData = useMemo(() => {
    const cards = selectedCardId === "all" ? creditCards : creditCards.filter((c) => c.id === selectedCardId);

    // Per category spending and estimated rewards
    const categorySpend: Record<string, { spend: number; points: number }> = {};
    const cycleRewards: { label: string; points: number; cashback: number }[] = [];

    recentCycles.forEach((cycle) => {
      let cyclePoints = 0;
      cards.forEach((cc) => {
        const txns = transactions.filter(
          (t) => t.account_id === cc.id && t.amount < 0 && t.date >= cycle.startDate && t.date <= cycle.endDate && t.category !== "Credit Card Payment"
        );
        txns.forEach((t) => {
          const amount = Math.abs(t.amount);
          const multiplier = CATEGORY_MULTIPLIERS[t.category] || 1;
          const points = Math.floor((amount / 100) * multiplier);
          cyclePoints += points;

          if (!categorySpend[t.category]) categorySpend[t.category] = { spend: 0, points: 0 };
          categorySpend[t.category].spend += amount;
          categorySpend[t.category].points += points;
        });
      });
      cycleRewards.push({ label: cycle.label.split(" ")[0], points: cyclePoints, cashback: cyclePoints * POINT_VALUE });
    });

    const totalPoints = Object.values(categorySpend).reduce((s, c) => s + c.points, 0);
    const totalSpend = Object.values(categorySpend).reduce((s, c) => s + c.spend, 0);
    const totalCashback = totalPoints * POINT_VALUE;
    const effectiveRate = totalSpend > 0 ? (totalCashback / totalSpend) * 100 : 0;

    // Best categories for rewards
    const categoryRanking = Object.entries(categorySpend)
      .map(([cat, data]) => ({
        category: cat,
        spend: data.spend,
        points: data.points,
        cashback: data.points * POINT_VALUE,
        rate: data.spend > 0 ? ((data.points * POINT_VALUE) / data.spend) * 100 : 0,
      }))
      .sort((a, b) => b.points - a.points);

    return { totalPoints, totalSpend, totalCashback, effectiveRate, categoryRanking, cycleRewards: cycleRewards.reverse() };
  }, [creditCards, transactions, recentCycles, selectedCardId]);

  // Card optimization tips
  const tips = useMemo(() => {
    const suggestions: { category: string; tip: string }[] = [];
    rewardData.categoryRanking.slice(0, 5).forEach((cat) => {
      const multiplier = CATEGORY_MULTIPLIERS[cat.category] || 1;
      if (multiplier >= 3) {
        suggestions.push({ category: cat.category, tip: `Great! ${cat.category} earns ${multiplier}x points. Keep using CC here.` });
      } else if (cat.spend > 5000 && multiplier === 1) {
        suggestions.push({ category: cat.category, tip: `${cat.category} has standard rewards. Consider a card with better rates for this category.` });
      }
    });
    return suggestions;
  }, [rewardData]);

  return (
    <div className="space-y-4">
      {/* Card Selector */}
      <div className="flex flex-wrap items-center gap-2">
        <button
          onClick={() => setSelectedCardId("all")}
          className={cn("px-3 py-1.5 rounded-lg text-xs font-medium border transition-all", selectedCardId === "all" ? "bg-brand/10 text-brand border-brand/30" : "border-border text-muted-foreground hover:bg-muted")}
        >
          All Cards
        </button>
        {creditCards.map((cc) => (
          <button key={cc.id} onClick={() => setSelectedCardId(cc.id)} className={cn("px-3 py-1.5 rounded-lg text-xs font-medium border transition-all", selectedCardId === cc.id ? "bg-brand/10 text-brand border-brand/30" : "border-border text-muted-foreground hover:bg-muted")}>
            {cc.account_name}
          </button>
        ))}
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card className="border-brand/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <Sparkles className="w-3.5 h-3.5 text-brand" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Total Points</span>
            </div>
            <p className="text-lg font-bold text-brand">{rewardData.totalPoints.toLocaleString("en-IN")}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <IndianRupee className="w-3.5 h-3.5 text-success" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Cashback Value</span>
            </div>
            <p className="text-lg font-bold text-success">{fmt(rewardData.totalCashback)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <TrendingUp className="w-3.5 h-3.5 text-info" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Effective Rate</span>
            </div>
            <p className="text-lg font-bold text-info">{rewardData.effectiveRate.toFixed(2)}%</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <CreditCard className="w-3.5 h-3.5 text-muted-foreground" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">CC Spend</span>
            </div>
            <p className="text-lg font-bold text-foreground">{fmt(rewardData.totalSpend)}</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Points Earned Over Time */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">Points Earned (Last 6 Cycles)</CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <div className="h-[200px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={rewardData.cycleRewards}>
                  <XAxis dataKey="label" tick={{ fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fontSize: 10 }} axisLine={false} tickLine={false} />
                  <Tooltip formatter={(v) => Number(v).toLocaleString("en-IN")} />
                  <Bar dataKey="points" fill="var(--color-brand)" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Category-wise Rewards */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">Rewards by Category</CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0 space-y-2 max-h-[280px] overflow-y-auto">
            {rewardData.categoryRanking.slice(0, 10).map((cat) => (
              <div key={cat.category} className="flex items-center gap-3 p-2 rounded-lg hover:bg-muted/30 transition-colors">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="text-sm font-medium text-foreground">{cat.category}</p>
                    {(CATEGORY_MULTIPLIERS[cat.category] || 1) > 1 && (
                      <Badge variant="secondary" className="text-[9px] px-1.5">
                        {CATEGORY_MULTIPLIERS[cat.category]}x
                      </Badge>
                    )}
                  </div>
                  <p className="text-[11px] text-muted-foreground">Spent: {fmt(cat.spend)} ┬╖ Rate: {cat.rate.toFixed(2)}%</p>
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-brand">{cat.points.toLocaleString("en-IN")} pts</p>
                  <p className="text-[10px] text-success">Γëê {fmt(cat.cashback)}</p>
                </div>
              </div>
            ))}
            {rewardData.categoryRanking.length === 0 && (
              <p className="text-sm text-muted-foreground text-center py-8">No CC spending data yet</p>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Optimization Tips */}
      {tips.length > 0 && (
        <Card className="border-brand/20">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2">
              <Gift className="w-4 h-4 text-brand" /> Card Optimization Tips
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0 space-y-2">
            {tips.map((t, i) => (
              <div key={i} className="flex items-start gap-3 p-2.5 rounded-lg bg-muted/30 border border-border/50">
                <Sparkles className="w-4 h-4 text-brand mt-0.5 flex-shrink-0" />
                <div>
                  <p className="text-xs font-medium text-foreground">{t.category}</p>
                  <p className="text-[11px] text-muted-foreground">{t.tip}</p>
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { creditCardsAPI } from "@/services/api";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Badge, Progress } from "@/components/ui";
import { FileText, CheckCircle2, AlertTriangle, Clock, CreditCard, IndianRupee } from "lucide-react";
import toast from "react-hot-toast";

interface StatementCycle {
  cycleKey: string;
  label: string;
  startDate: string;
  endDate: string;
}

export default function StatementsPage() {
  const queryClient = useQueryClient();
  const { creditCards, transactions, accounts, cycleStartDay } = useData();
  const [selectedCardId, setSelectedCardId] = useState<string>("all");
  const [payingCardId, setPayingCardId] = useState<string | null>(null);
  const [payAmount, setPayAmount] = useState("");
  const [payFromAccount, setPayFromAccount] = useState("");

  const recentCycles = useMemo(() => getRecentFinancialMonths(6, new Date(), cycleStartDay), [cycleStartDay]);
  const bankAccounts = useMemo(() => accounts.filter((a) => a.type !== "credit"), [accounts]);

  // Generate statement data for each card per cycle
  const statements = useMemo(() => {
    const cards = selectedCardId === "all" ? creditCards : creditCards.filter((c) => c.id === selectedCardId);

    return recentCycles.map((cycle) => {
      const cardStatements = cards.map((cc) => {
        const cycleTxns = transactions.filter(
          (t) => t.account_id === cc.id && t.date >= cycle.startDate && t.date <= cycle.endDate
        );
        const totalSpend = cycleTxns.filter((t) => t.amount < 0).reduce((s, t) => s + Math.abs(t.amount), 0);
        const payments = cycleTxns.filter((t) => t.category === "Credit Card Payment" && t.amount > 0).reduce((s, t) => s + t.amount, 0);
        const outstanding = totalSpend - payments;
        const limit = parseFloat(String(cc.credit_limit || 0));
        const minDue = Math.max(totalSpend * 0.05, 200); // 5% or Γé╣200 min

        // Payment status
        let status: "paid" | "partial" | "pending" | "overdue" = "pending";
        if (payments >= totalSpend && totalSpend > 0) status = "paid";
        else if (payments >= minDue && payments < totalSpend) status = "partial";
        else if (payments > 0 && payments < minDue) status = "overdue";

        return {
          cardId: cc.id,
          cardName: cc.account_name,
          totalSpend,
          payments,
          outstanding: Math.max(0, outstanding),
          minDue: totalSpend > 0 ? minDue : 0,
          status,
          txnCount: cycleTxns.filter((t) => t.amount < 0).length,
          limit,
        };
      });

      return { cycle, cardStatements };
    });
  }, [recentCycles, creditCards, transactions, selectedCardId]);

  const payMutation = useMutation({
    mutationFn: (data: Record<string, unknown>) => creditCardsAPI.payBill(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["transactions"] });
      queryClient.invalidateQueries({ queryKey: ["accounts"] });
      toast.success("Payment recorded!");
      setPayingCardId(null);
      setPayAmount("");
      setPayFromAccount("");
    },
    onError: () => toast.error("Payment failed"),
  });

  const handlePay = (cardId: string) => {
    const amount = parseFloat(payAmount);
    if (!amount || amount <= 0) { toast.error("Enter a valid amount"); return; }
    if (!payFromAccount) { toast.error("Select source account"); return; }
    payMutation.mutate({ credit_card_id: cardId, amount, from_account_id: payFromAccount, date: new Date().toISOString().split("T")[0] });
  };

  const statusConfig = {
    paid: { label: "Paid", icon: CheckCircle2, color: "text-success", bg: "bg-success/10" },
    partial: { label: "Partial", icon: Clock, color: "text-warning", bg: "bg-warning/10" },
    pending: { label: "Pending", icon: Clock, color: "text-muted-foreground", bg: "bg-muted" },
    overdue: { label: "Overdue", icon: AlertTriangle, color: "text-danger", bg: "bg-danger/10" },
  };

  return (
    <div className="space-y-4">
      {/* Card Selector */}
      <div className="flex flex-wrap items-center gap-2">
        <button
          onClick={() => setSelectedCardId("all")}
          className={cn(
            "px-3 py-1.5 rounded-lg text-xs font-medium border transition-all",
            selectedCardId === "all" ? "bg-brand/10 text-brand border-brand/30" : "border-border text-muted-foreground hover:bg-muted"
          )}
        >
          All Cards
        </button>
        {creditCards.map((cc) => (
          <button
            key={cc.id}
            onClick={() => setSelectedCardId(cc.id)}
            className={cn(
              "px-3 py-1.5 rounded-lg text-xs font-medium border transition-all",
              selectedCardId === cc.id ? "bg-brand/10 text-brand border-brand/30" : "border-border text-muted-foreground hover:bg-muted"
            )}
          >
            {cc.account_name}
          </button>
        ))}
      </div>

      {/* Statement Cards by Cycle */}
      <div className="space-y-4">
        {statements.map(({ cycle, cardStatements }) => {
          const hasActivity = cardStatements.some((cs) => cs.totalSpend > 0);
          if (!hasActivity) return null;

          return (
            <Card key={cycle.cycleKey}>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm flex items-center gap-2">
                  <FileText className="w-4 h-4 text-muted-foreground" />
                  {cycle.label}
                  <span className="text-xs text-muted-foreground font-normal ml-auto">
                    {cycle.startDate} ΓåÆ {cycle.endDate}
                  </span>
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 pt-0 space-y-3">
                {cardStatements.filter((cs) => cs.totalSpend > 0).map((cs) => {
                  const sc = statusConfig[cs.status];
                  const StatusIcon = sc.icon;
                  return (
                    <div key={cs.cardId} className="border border-border/50 rounded-lg p-4">
                      <div className="flex items-center justify-between mb-3">
                        <div className="flex items-center gap-2">
                          <CreditCard className="w-4 h-4 text-accent" />
                          <span className="text-sm font-semibold text-foreground">{cs.cardName}</span>
                          <span className="text-[10px] text-muted-foreground">({cs.txnCount} txns)</span>
                        </div>
                        <div className={cn("flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded-full", sc.bg, sc.color)}>
                          <StatusIcon className="w-3 h-3" />
                          {sc.label}
                        </div>
                      </div>

                      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-3">
                        <div>
                          <p className="text-[10px] text-muted-foreground uppercase">Statement Amount</p>
                          <p className="text-sm font-bold text-foreground">{fmt(cs.totalSpend)}</p>
                        </div>
                        <div>
                          <p className="text-[10px] text-muted-foreground uppercase">Paid</p>
                          <p className="text-sm font-bold text-success">{fmt(cs.payments)}</p>
                        </div>
                        <div>
                          <p className="text-[10px] text-muted-foreground uppercase">Outstanding</p>
                          <p className={cn("text-sm font-bold", cs.outstanding > 0 ? "text-danger" : "text-success")}>{fmt(cs.outstanding)}</p>
                        </div>
                        <div>
                          <p className="text-[10px] text-muted-foreground uppercase">Min Due</p>
                          <p className="text-sm font-bold text-warning">{fmt(cs.minDue)}</p>
                        </div>
                      </div>

                      {/* Payment progress */}
                      {cs.totalSpend > 0 && (
                        <div className="mb-3">
                          <div className="flex justify-between text-[10px] text-muted-foreground mb-1">
                            <span>Payment Progress</span>
                            <span>{Math.min(100, Math.round((cs.payments / cs.totalSpend) * 100))}%</span>
                          </div>
                          <Progress
                            value={Math.min(100, (cs.payments / cs.totalSpend) * 100)}
                            className="h-1.5"
                            indicatorClassName={cs.status === "paid" ? "bg-success" : cs.status === "partial" ? "bg-warning" : "bg-muted-foreground"}
                          />
                        </div>
                      )}

                      {/* Pay button for current cycle */}
                      {cs.outstanding > 0 && cycle.cycleKey === recentCycles[0]?.cycleKey && (
                        <div>
                          {payingCardId === cs.cardId ? (
                            <div className="flex flex-wrap items-center gap-2 mt-2 pt-2 border-t border-border/50">
                              <input
                                type="number"
                                value={payAmount}
                                onChange={(e) => setPayAmount(e.target.value)}
                                placeholder={`Γé╣${cs.outstanding}`}
                                className="h-8 w-24 px-2 rounded-lg text-xs border border-border bg-card text-foreground"
                              />
                              <select
                                value={payFromAccount}
                                onChange={(e) => setPayFromAccount(e.target.value)}
                                className="h-8 px-2 rounded-lg text-xs border border-border bg-card text-foreground"
                              >
                                <option value="">Pay from...</option>
                                {bankAccounts.map((a) => (
                                  <option key={a.id} value={a.id}>{a.account_name}</option>
                                ))}
                              </select>
                              <Button size="sm" className="h-8 text-xs" onClick={() => handlePay(cs.cardId)}>
                                <IndianRupee className="w-3 h-3 mr-1" /> Pay
                              </Button>
                              <button onClick={() => setPayingCardId(null)} className="text-xs text-muted-foreground hover:text-foreground">Cancel</button>
                            </div>
                          ) : (
                            <Button variant="outline" size="sm" className="text-xs mt-2" onClick={() => { setPayingCardId(cs.cardId); setPayAmount(String(cs.outstanding)); }}>
                              Pay Bill ({fmt(cs.outstanding)})
                            </Button>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </CardContent>
            </Card>
          );
        })}
      </div>

      {creditCards.length === 0 && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-16">
            <FileText className="w-12 h-12 text-muted-foreground/50 mb-4" />
            <p className="text-lg font-semibold text-foreground">No Credit Cards</p>
            <p className="text-sm text-muted-foreground mt-1">Add a credit card from Settings to track statements.</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { transactionsAPI } from "@/services/api";
import { getFinancialCycle, getRecentFinancialMonths } from "@/utils/financialMonth";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Badge, Input } from "@/components/ui";
import { Plus, Search, ArrowDownRight, X } from "lucide-react";
import toast from "react-hot-toast";
import QuickAddTransaction from "@/components/QuickAddTransaction";

export default function CCTransactionsPage() {
  const queryClient = useQueryClient();
  const { creditCards, transactions, categories, accounts, cycleStartDay } = useData();
  const [selectedCard, setSelectedCard] = useState<string>("all");
  const [showAdd, setShowAdd] = useState(false);
  const [searchText, setSearchText] = useState("");
  const [filterCategory, setFilterCategory] = useState("");

  const currentCycle = useMemo(() => getFinancialCycle(new Date(), cycleStartDay), [cycleStartDay]);

  const ccTransactions = useMemo(() => {
    let txns = transactions.filter((t) =>
      t.payment_type === "Credit Card" || creditCards.some((cc) => cc.id === t.account_id)
    );
    if (selectedCard !== "all") txns = txns.filter((t) => t.account_id === selectedCard);
    txns = txns.filter((t) => t.date >= currentCycle.startDate && t.date <= currentCycle.endDate);
    if (searchText.trim()) {
      const s = searchText.toLowerCase();
      txns = txns.filter((t) => t.category?.toLowerCase().includes(s) || t.notes?.toLowerCase().includes(s));
    }
    if (filterCategory) txns = txns.filter((t) => t.category === filterCategory);
    return txns.sort((a, b) => b.date.localeCompare(a.date));
  }, [transactions, creditCards, selectedCard, currentCycle, searchText, filterCategory]);

  const totalSpend = ccTransactions.filter((t) => t.amount < 0).reduce((s, t) => s + Math.abs(t.amount), 0);

  const addMutation = useMutation({
    mutationFn: (data: unknown) => transactionsAPI.create(data as Parameters<typeof transactionsAPI.create>[0]),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["transactions"] }); toast.success("CC transaction added!"); },
    onError: () => toast.error("Failed"),
  });

  return (
    <div className="space-y-4">
      {/* Card Selector */}
      <div className="flex flex-wrap items-center gap-2">
        <button
          onClick={() => setSelectedCard("all")}
          className={cn("px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors", selectedCard === "all" ? "bg-brand/10 text-brand border-brand/30" : "text-muted-foreground border-border hover:bg-muted")}
        >
          All Cards
        </button>
        {creditCards.map((cc) => (
          <button
            key={cc.id}
            onClick={() => setSelectedCard(cc.id)}
            className={cn("px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors", selectedCard === cc.id ? "bg-brand/10 text-brand border-brand/30" : "text-muted-foreground border-border hover:bg-muted")}
          >
            {cc.account_name}
          </button>
        ))}
        <Button onClick={() => setShowAdd(true)} size="sm" className="ml-auto gap-1">
          <Plus className="w-3.5 h-3.5" /> Add CC Transaction
        </Button>
      </div>

      {/* Summary */}
      <Card>
        <CardContent className="p-4 flex items-center justify-between">
          <div>
            <span className="text-xs text-muted-foreground">This cycle CC spending</span>
            <p className="text-lg font-bold text-foreground">{fmt(totalSpend)}</p>
          </div>
          <Badge variant="secondary">{ccTransactions.length} transactions</Badge>
        </CardContent>
      </Card>

      {/* Filters */}
      <div className="flex gap-2">
        <div className="relative flex-1 max-w-xs">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input value={searchText} onChange={(e) => setSearchText(e.target.value)} placeholder="Search..." className="pl-9 h-8" />
        </div>
        <select value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)} className="h-8 px-2 rounded-lg text-xs border border-border bg-card text-foreground">
          <option value="">All Categories</option>
          {categories.map((c) => <option key={c.id || c.name} value={c.name}>{c.name}</option>)}
        </select>
      </div>

      {/* Transactions List */}
      <Card>
        <CardContent className="p-0">
          {ccTransactions.length > 0 ? (
            <div className="divide-y divide-border">
              {ccTransactions.map((t) => (
                <div key={t.id} className="flex items-center justify-between px-4 py-3 hover:bg-muted/50 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-danger/10 flex items-center justify-center">
                      <ArrowDownRight className="w-4 h-4 text-danger" />
                    </div>
                    <div>
                      <p className="text-sm font-medium text-foreground">{t.category}</p>
                      <p className="text-[11px] text-muted-foreground">{t.date} {t.notes ? `┬╖ ${t.notes}` : ""}</p>
                    </div>
                  </div>
                  <span className="text-sm font-semibold text-foreground">{fmt(Math.abs(t.amount))}</span>
                </div>
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
              <p className="text-sm">No CC transactions this cycle</p>
            </div>
          )}
        </CardContent>
      </Card>

      {showAdd && (
        <QuickAddTransaction
          isOpen={showAdd}
          onClose={() => setShowAdd(false)}
          onSubmit={(data) => addMutation.mutate(data)}
          accounts={accounts}
          creditCards={creditCards}
          categories={categories}
          allowCreditCard={true}
        />
      )}
    </div>
  );
}

