"use client";

import { useState, useMemo, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { accountsAPI, transactionsAPI } from "@/services/api";
import TransactionTable from "@/components/TransactionTable";
import ConfirmDialog from "@/components/ConfirmDialog";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Input } from "@/components/ui";
import { Wallet, CreditCard, Plus, ArrowUpRight, ArrowDownRight, Pencil, Trash2, Banknote, PiggyBank, Landmark } from "lucide-react";
import toast from "react-hot-toast";
import EmptyState from "@/components/EmptyState";
import { SkeletonCard } from "@/components/SkeletonLoader";

type AccountType = "savings" | "current" | "wallet" | "credit";
const ACCOUNT_TYPES: { value: AccountType; label: string; icon: typeof Wallet }[] = [
  { value: "savings", label: "Savings", icon: PiggyBank },
  { value: "current", label: "Current", icon: Banknote },
  { value: "wallet", label: "Wallet", icon: Wallet },
  { value: "credit", label: "Credit Card", icon: CreditCard },
];

function AccountModal({ open, onClose, onSubmit, initial }: {
  open: boolean;
  onClose: () => void;
  onSubmit: (data: Record<string, unknown>) => void;
  initial?: Record<string, unknown> | null;
}) {
  const [name, setName] = useState((initial?.account_name as string) || "");
  const [type, setType] = useState<AccountType>((initial?.type as AccountType) || "savings");
  const [balance, setBalance] = useState(String(initial?.balance ?? "0"));

  useEffect(() => {
    setName((initial?.account_name as string) || "");
    setType((initial?.type as AccountType) || "savings");
    setBalance(String(initial?.balance ?? "0"));
  }, [initial, open]);

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={onClose}>
      <div className="bg-card border border-border rounded-xl p-6 w-full max-w-md space-y-4" onClick={(e) => e.stopPropagation()}>
        <h2 className="text-lg font-bold text-foreground">{initial ? "Edit Account" : "Add Account"}</h2>
        <div className="space-y-3">
          <div>
            <label className="text-xs font-medium text-muted-foreground mb-1 block">Account Name</label>
            <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. HDFC Savings" autoFocus />
          </div>
          <div>
            <label className="text-xs font-medium text-muted-foreground mb-1 block">Type</label>
            <div className="grid grid-cols-4 gap-2">
              {ACCOUNT_TYPES.map((t) => (
                <button
                  key={t.value}
                  onClick={() => setType(t.value)}
                  className={cn(
                    "flex flex-col items-center gap-1 p-2 rounded-lg border text-xs font-medium transition-all",
                    type === t.value ? "border-brand bg-brand/10 text-brand" : "border-border text-muted-foreground hover:bg-muted"
                  )}
                >
                  <t.icon className="w-4 h-4" />
                  {t.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="text-xs font-medium text-muted-foreground mb-1 block">
              {type === "credit" ? "Outstanding Balance" : "Current Balance"}
            </label>
            <Input type="number" value={balance} onChange={(e) => setBalance(e.target.value)} placeholder="0" />
          </div>
        </div>
        <div className="flex justify-end gap-2 pt-2">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button
            onClick={() => {
              if (!name.trim()) { toast.error("Name required"); return; }
              onSubmit({ account_name: name.trim(), type, balance: parseFloat(balance) || 0 });
              onClose();
            }}
          >
            {initial ? "Save" : "Create"}
          </Button>
        </div>
      </div>
    </div>
  );
}

export default function AccountsPage() {
  const queryClient = useQueryClient();
  const { accounts, creditCards, transactions, categories, cycleStartDay, dataReady } = useData();
  const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);
  const [showAccountModal, setShowAccountModal] = useState(false);
  const [editAccount, setEditAccount] = useState<Record<string, unknown> | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

  if (!dataReady) {
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <SkeletonCard lines={2} />
          <SkeletonCard lines={2} />
          <SkeletonCard lines={2} />
        </div>
      </div>
    );
  }

  const bankAccounts = useMemo(() => accounts.filter((a) => a.type !== "credit").sort((a, b) => (b.balance || 0) - (a.balance || 0)), [accounts]);
  const allAccounts = useMemo(() => [...bankAccounts, ...creditCards], [bankAccounts, creditCards]);

  const totalLiquidCash = useMemo(() => bankAccounts.reduce((sum, a) => sum + (a.balance || 0), 0), [bankAccounts]);
  const totalCCOutstanding = useMemo(() => creditCards.reduce((sum, c) => sum + (c.liability || c.balance || 0), 0), [creditCards]);

  useEffect(() => {
    if (!selectedAccountId && allAccounts.length > 0) setSelectedAccountId(allAccounts[0].id);
  }, [allAccounts, selectedAccountId]);

  const selectedAccount = useMemo(() => allAccounts.find((a) => a.id === selectedAccountId) || allAccounts[0] || null, [selectedAccountId, allAccounts]);

  const accountStats = useMemo(() => {
    if (!selectedAccount) return { income: 0, expense: 0, recentTxns: [] as typeof transactions, lastTxnDate: "" };
    const txns = transactions.filter((t) => t.account_id === selectedAccount.id);
    let income = 0, expense = 0;
    txns.forEach((t) => { if (t.amount > 0) income += t.amount; else expense += Math.abs(t.amount); });
    return { income, expense, recentTxns: txns.slice(0, 30), lastTxnDate: txns[0]?.date || "" };
  }, [selectedAccount, transactions]);

  // Group bank accounts by type
  const groupedAccounts = useMemo(() => {
    const groups: Record<string, typeof bankAccounts> = {};
    bankAccounts.forEach((acc) => {
      const key = acc.type || "savings";
      if (!groups[key]) groups[key] = [];
      groups[key].push(acc);
    });
    return groups;
  }, [bankAccounts]);

  const createMutation = useMutation({
    mutationFn: (data: Record<string, unknown>) => accountsAPI.create(data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["accounts"] }); toast.success("Account created!"); },
    onError: () => toast.error("Failed to create account"),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Record<string, unknown> }) => accountsAPI.update(id, data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["accounts"] }); toast.success("Account updated!"); },
    onError: () => toast.error("Failed to update"),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => accountsAPI.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["accounts"] });
      toast.success("Account deleted!");
      if (selectedAccountId === confirmDelete) setSelectedAccountId(null);
    },
    onError: () => toast.error("Failed to delete"),
  });

  const handleSubmitAccount = (data: Record<string, unknown>) => {
    if (editAccount?.id) {
      updateMutation.mutate({ id: editAccount.id as string, data });
    } else {
      createMutation.mutate(data);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <div>
          <p className="text-sm text-muted-foreground mt-0.5">
            {bankAccounts.length} accounts ┬╖ {creditCards.length} credit cards
          </p>
        </div>
        <Button onClick={() => { setEditAccount(null); setShowAccountModal(true); }} className="gap-1.5">
          <Plus className="w-4 h-4" /> Add Account
        </Button>
      </div>

      {/* Summary Bar */}
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        <Card className="border-success/20">
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Liquid Cash</span>
            <p className="text-xl font-bold text-success mt-1">{fmt(totalLiquidCash)}</p>
          </CardContent>
        </Card>
        <Card className="border-danger/20">
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">CC Outstanding</span>
            <p className="text-xl font-bold text-danger mt-1">{fmt(totalCCOutstanding)}</p>
          </CardContent>
        </Card>
        <Card className="hidden sm:block">
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Net Position</span>
            <p className={cn("text-xl font-bold mt-1", totalLiquidCash - totalCCOutstanding >= 0 ? "text-success" : "text-danger")}>
              {fmt(totalLiquidCash - totalCCOutstanding)}
            </p>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Account List */}
        <Card>
          <CardContent className="p-4 space-y-1 max-h-[calc(100vh-320px)] overflow-y-auto">
            {Object.entries(groupedAccounts).map(([type, accs]) => (
              <div key={type}>
                <h3 className="text-[11px] font-semibold uppercase text-muted-foreground mb-2 mt-3 first:mt-0">
                  {ACCOUNT_TYPES.find((t) => t.value === type)?.label || type}
                </h3>
                {accs.map((acc) => (
                  <button
                    key={acc.id}
                    onClick={() => setSelectedAccountId(acc.id)}
                    className={cn(
                      "flex items-center gap-3 w-full p-3 rounded-xl text-left transition-all border-l-4",
                      selectedAccountId === acc.id
                        ? "bg-brand/5 border-l-brand"
                        : "border-l-transparent hover:bg-muted/50"
                    )}
                  >
                    <div className="w-8 h-8 rounded-lg bg-success/10 flex items-center justify-center">
                      <Wallet className="w-4 h-4 text-success" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-semibold text-foreground truncate">{acc.account_name}</p>
                      <p className="text-xs text-muted-foreground">{fmt(acc.balance || 0)}</p>
                    </div>
                  </button>
                ))}
              </div>
            ))}

            {creditCards.length > 0 && (
              <div>
                <h3 className="text-[11px] font-semibold uppercase text-muted-foreground mt-4 mb-2">Credit Cards</h3>
                {creditCards.map((cc) => (
                  <button
                    key={cc.id}
                    onClick={() => setSelectedAccountId(cc.id)}
                    className={cn(
                      "flex items-center gap-3 w-full p-3 rounded-xl text-left transition-all border-l-4",
                      selectedAccountId === cc.id
                        ? "bg-accent/5 border-l-accent"
                        : "border-l-transparent hover:bg-muted/50"
                    )}
                  >
                    <div className="w-8 h-8 rounded-lg bg-accent/10 flex items-center justify-center">
                      <CreditCard className="w-4 h-4 text-accent" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-semibold text-foreground truncate">{cc.account_name}</p>
                      <p className="text-xs text-danger">Outstanding: {fmt(cc.liability || cc.balance || 0)}</p>
                    </div>
                  </button>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Account Details */}
        <div className="lg:col-span-2 space-y-4">
          {selectedAccount && (
            <>
              {/* Account header with actions */}
              <Card>
                <CardContent className="p-4 flex items-center justify-between">
                  <div>
                    <h2 className="text-base font-bold text-foreground">{selectedAccount.account_name}</h2>
                    <p className="text-xs text-muted-foreground capitalize">{selectedAccount.type || "savings"} ┬╖ Last txn: {accountStats.lastTxnDate || "ΓÇö"}</p>
                  </div>
                  <div className="flex gap-1.5">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => { setEditAccount(selectedAccount as unknown as Record<string, unknown>); setShowAccountModal(true); }}
                    >
                      <Pencil className="w-3.5 h-3.5" />
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setConfirmDelete(selectedAccount.id)}
                      className="text-danger border-danger/30 hover:bg-danger/10"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </Button>
                  </div>
                </CardContent>
              </Card>

              <div className="grid grid-cols-2 gap-3">
                <Card>
                  <CardContent className="p-4">
                    <div className="flex items-center gap-2 mb-1">
                      <ArrowUpRight className="w-4 h-4 text-success" />
                      <span className="text-[11px] font-medium text-muted-foreground uppercase">Income</span>
                    </div>
                    <p className="text-xl font-bold text-success">{fmt(accountStats.income)}</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardContent className="p-4">
                    <div className="flex items-center gap-2 mb-1">
                      <ArrowDownRight className="w-4 h-4 text-danger" />
                      <span className="text-[11px] font-medium text-muted-foreground uppercase">Expenses</span>
                    </div>
                    <p className="text-xl font-bold text-danger">{fmt(accountStats.expense)}</p>
                  </CardContent>
                </Card>
              </div>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm">Recent Transactions ΓÇö {selectedAccount.account_name}</CardTitle>
                </CardHeader>
                <CardContent className="p-0">
                  <TransactionTable
                    transactions={accountStats.recentTxns}
                    categories={categories}
                    accounts={accounts}
                    creditCards={creditCards}
                    maxHeight="calc(100vh - 520px)"
                  />
                </CardContent>
              </Card>
            </>
          )}
        </div>
      </div>

      <AccountModal
        open={showAccountModal}
        onClose={() => { setShowAccountModal(false); setEditAccount(null); }}
        onSubmit={handleSubmitAccount}
        initial={editAccount}
      />

      <ConfirmDialog
        open={!!confirmDelete}
        title="Delete Account?"
        message="All associated transactions will be unlinked. This cannot be undone."
        confirmLabel="Delete"
        confirmColor="danger"
        onConfirm={() => { if (confirmDelete) deleteMutation.mutate(confirmDelete); setConfirmDelete(null); }}
        onCancel={() => setConfirmDelete(null)}
      />
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui";
import { ArrowUpRight, ArrowDownRight, TrendingUp, Calendar } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Tooltip, AreaChart, Area } from "recharts";
import { SkeletonCard } from "@/components/SkeletonLoader";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment"]);

export default function CashFlowPage() {
  const { transactions, cycleStartDay, accounts, dataReady } = useData();

  if (!dataReady) {
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4"><SkeletonCard lines={2} /><SkeletonCard lines={2} /><SkeletonCard lines={2} /></div>
        <SkeletonCard lines={8} />
      </div>
    );
  }

  const recentCycles = useMemo(() => getRecentFinancialMonths(6, new Date(), cycleStartDay), [cycleStartDay]);

  // Per-cycle income vs expense
  const cycleData = useMemo(() => {
    return recentCycles.map((cycle) => {
      const txns = transactions.filter(
        (t) => t.date >= cycle.startDate && t.date <= cycle.endDate && !SKIP_CATS.has(t.category) && t.payment_type !== "Self Transfer"
      );
      let income = 0, expense = 0;
      txns.forEach((t) => {
        if (t.category === "Income" || t.amount > 0) income += Math.abs(t.amount);
        else expense += Math.abs(t.amount);
      });
      return { label: cycle.label.split(" ")[0], income, expense, net: income - expense };
    }).reverse();
  }, [recentCycles, transactions]);

  // Current cycle daily cumulative spend
  const currentCycle = recentCycles[0];
  const dailySpend = useMemo(() => {
    if (!currentCycle) return [];
    const txns = transactions.filter(
      (t) => t.date >= currentCycle.startDate && t.date <= currentCycle.endDate && t.amount < 0 && !SKIP_CATS.has(t.category) && t.payment_type !== "Self Transfer"
    );
    const dayMap: Record<string, number> = {};
    txns.forEach((t) => { dayMap[t.date] = (dayMap[t.date] || 0) + Math.abs(t.amount); });
    const sorted = Object.entries(dayMap).sort(([a], [b]) => a.localeCompare(b));
    let cumulative = 0;
    return sorted.map(([date, amt]) => {
      cumulative += amt;
      return { date: new Date(date + "T00:00:00").toLocaleDateString("en-IN", { day: "2-digit", month: "short" }), daily: amt, cumulative };
    });
  }, [currentCycle, transactions]);

  // Summary metrics
  const summary = useMemo(() => {
    const current = cycleData[cycleData.length - 1] || { income: 0, expense: 0, net: 0 };
    const totalExpense = current.expense;
    const daysInCycle = dailySpend.length || 1;
    const dailyAvg = totalExpense / daysInCycle;
    const liquidCash = accounts.filter((a) => a.type !== "credit").reduce((s, a) => s + (a.balance || 0), 0);
    const daysOfCash = dailyAvg > 0 ? Math.round(liquidCash / dailyAvg) : 999;
    const projectedBalance = liquidCash - (dailyAvg * 30 - totalExpense);
    return { dailyAvg, daysOfCash, projectedBalance, ...current };
  }, [cycleData, dailySpend, accounts]);

  return (
    <div className="space-y-4">
      {/* Hero Metrics */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card className="border-success/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <ArrowUpRight className="w-3.5 h-3.5 text-success" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Income</span>
            </div>
            <p className="text-lg font-bold text-success">{fmt(summary.income)}</p>
          </CardContent>
        </Card>
        <Card className="border-danger/20">
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <ArrowDownRight className="w-3.5 h-3.5 text-danger" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Expenses</span>
            </div>
            <p className="text-lg font-bold text-danger">{fmt(summary.expense)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <Calendar className="w-3.5 h-3.5 text-info" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Daily Avg</span>
            </div>
            <p className="text-lg font-bold text-foreground">{fmt(summary.dailyAvg)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <TrendingUp className="w-3.5 h-3.5 text-warning" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Days of Cash</span>
            </div>
            <p className={cn("text-lg font-bold", summary.daysOfCash > 60 ? "text-success" : summary.daysOfCash > 30 ? "text-warning" : "text-danger")}>
              {summary.daysOfCash > 365 ? "365+" : summary.daysOfCash} days
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Net Flow Hero */}
      <Card>
        <CardContent className="p-6 text-center">
          <span className="text-[11px] font-semibold text-muted-foreground uppercase">Net Flow This Cycle</span>
          <p className={cn("text-3xl font-bold mt-1", summary.net >= 0 ? "text-success" : "text-danger")}>
            {summary.net >= 0 ? "+" : ""}{fmt(summary.net)}
          </p>
          <p className="text-xs text-muted-foreground mt-1">
            Savings rate: {summary.income > 0 ? Math.round((summary.net / summary.income) * 100) : 0}%
          </p>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Income vs Expenses Bar Chart */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">Income vs Expenses (Last 6 Cycles)</CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <div className="h-[220px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={cycleData} barGap={4}>
                  <XAxis dataKey="label" tick={{ fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fontSize: 10 }} axisLine={false} tickLine={false} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
                  <Tooltip formatter={(v) => fmt(Number(v))} />
                  <Bar dataKey="income" fill="var(--color-success)" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="expense" fill="var(--color-danger)" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
            <div className="flex justify-center gap-4 mt-2">
              <span className="flex items-center gap-1.5 text-xs text-muted-foreground"><span className="w-2.5 h-2.5 rounded-sm bg-success" />Income</span>
              <span className="flex items-center gap-1.5 text-xs text-muted-foreground"><span className="w-2.5 h-2.5 rounded-sm bg-danger" />Expenses</span>
            </div>
          </CardContent>
        </Card>

        {/* Daily Cumulative Spend */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">Cumulative Spend ΓÇö {currentCycle?.label}</CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <div className="h-[220px]">
              {dailySpend.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={dailySpend}>
                    <XAxis dataKey="date" tick={{ fontSize: 10 }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fontSize: 10 }} axisLine={false} tickLine={false} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
                    <Tooltip formatter={(v) => fmt(Number(v))} />
                    <Area type="monotone" dataKey="cumulative" stroke="var(--color-danger)" fill="var(--color-danger)" fillOpacity={0.1} strokeWidth={2} />
                  </AreaChart>
                </ResponsiveContainer>
              ) : (
                <div className="flex items-center justify-center h-full text-sm text-muted-foreground">No spend data yet</div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { motion } from "framer-motion";
import { useData } from "@/providers/DataProvider";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Input, Badge, Progress } from "@/components/ui";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RTooltip, Cell,
} from "recharts";
import {
  TrendingDown,
  Zap,
  Snowflake,
  Calculator,
  CreditCard,
  Calendar,
  ArrowRight,
} from "lucide-react";

interface Debt {
  id: string;
  name: string;
  balance: number;
  rate: number; // annual interest rate %
  minPayment: number;
  type: "credit_card" | "loan" | "emi";
}

type Strategy = "avalanche" | "snowball";

function calculatePayoff(debts: Debt[], extraMonthly: number, strategy: Strategy) {
  if (debts.length === 0) return { months: 0, totalInterest: 0, timeline: [], order: [] };

  // Sort by strategy
  const sorted = [...debts].sort((a, b) =>
    strategy === "avalanche" ? b.rate - a.rate : a.balance - b.balance
  );

  // Simulate month by month
  const balances = new Map(sorted.map((d) => [d.id, d.balance]));
  const timeline: Array<{ month: number; remaining: number }> = [];
  const order: string[] = [];
  let totalInterest = 0;
  let month = 0;
  const MAX_MONTHS = 600; // 50 years safety

  while (month < MAX_MONTHS) {
    const totalRemaining = Array.from(balances.values()).reduce((s, b) => s + b, 0);
    if (totalRemaining <= 0) break;
    timeline.push({ month, remaining: Math.round(totalRemaining) });

    month++;
    let extraBudget = extraMonthly;

    // Apply interest + minimum payments
    for (const debt of sorted) {
      let bal = balances.get(debt.id) || 0;
      if (bal <= 0) continue;

      // Monthly interest
      const interest = bal * (debt.rate / 100 / 12);
      bal += interest;
      totalInterest += interest;

      // Minimum payment
      const minPay = Math.min(debt.minPayment, bal);
      bal -= minPay;
      balances.set(debt.id, Math.max(0, bal));
    }

    // Apply extra payment to highest-priority debt
    for (const debt of sorted) {
      let bal = balances.get(debt.id) || 0;
      if (bal <= 0) continue;

      const payment = Math.min(extraBudget, bal);
      bal -= payment;
      extraBudget -= payment;
      balances.set(debt.id, Math.max(0, bal));

      if (bal <= 0 && !order.includes(debt.id)) {
        order.push(debt.id);
      }
      if (extraBudget <= 0) break;
    }
  }

  timeline.push({ month, remaining: 0 });
  return { months: month, totalInterest: Math.round(totalInterest), timeline, order };
}

export default function DebtStrategyPage() {
  const { accounts, creditCards } = useData();
  const [extraPayment, setExtraPayment] = useState("5000");
  const [debts, setDebts] = useState<Debt[]>(() => {
    // Auto-populate from credit cards with outstanding
    return creditCards
      .filter((cc) => (cc.liability || 0) > 0)
      .map((cc) => ({
        id: cc.id,
        name: cc.account_name,
        balance: cc.liability || 0,
        rate: 36, // Default CC rate in India
        minPayment: Math.max(500, Math.round((cc.liability || 0) * 0.05)),
        type: "credit_card" as const,
      }));
  });
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", balance: "", rate: "12", minPayment: "1000", type: "loan" });

  const addDebt = () => {
    if (!form.name || !form.balance) return;
    setDebts([...debts, {
      id: Date.now().toString(36),
      name: form.name,
      balance: parseFloat(form.balance) || 0,
      rate: parseFloat(form.rate) || 12,
      minPayment: parseFloat(form.minPayment) || 1000,
      type: form.type as Debt["type"],
    }]);
    setForm({ name: "", balance: "", rate: "12", minPayment: "1000", type: "loan" });
    setShowAdd(false);
  };

  const removeDebt = (id: string) => setDebts(debts.filter((d) => d.id !== id));

  const extra = parseFloat(extraPayment) || 0;
  const avalanche = useMemo(() => calculatePayoff(debts, extra, "avalanche"), [debts, extra]);
  const snowball = useMemo(() => calculatePayoff(debts, extra, "snowball"), [debts, extra]);

  const totalDebt = debts.reduce((s, d) => s + d.balance, 0);
  const totalMinPayments = debts.reduce((s, d) => s + d.minPayment, 0);
  const interestSaved = snowball.totalInterest - avalanche.totalInterest;
  const monthsSaved = snowball.months - avalanche.months;

  // Chart data
  const chartData = useMemo(() => {
    const maxMonths = Math.max(avalanche.months, snowball.months, 1);
    const step = Math.max(1, Math.floor(maxMonths / 12));
    const data: Array<{ month: number; avalanche: number; snowball: number }> = [];
    for (let m = 0; m <= maxMonths; m += step) {
      const avEntry = avalanche.timeline.find((t) => t.month >= m) || { remaining: 0 };
      const snEntry = snowball.timeline.find((t) => t.month >= m) || { remaining: 0 };
      data.push({ month: m, avalanche: avEntry.remaining, snowball: snEntry.remaining });
    }
    return data;
  }, [avalanche, snowball]);

  return (
    <div className="space-y-6 max-w-5xl">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Debt Payoff Strategy</h1>
          <p className="text-sm text-muted-foreground">Compare Avalanche vs Snowball methods</p>
        </div>
        <button
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-brand text-white text-sm font-medium hover:bg-brand/90 transition-colors"
        >
          + Add Debt
        </button>
      </div>

      {/* Debt List */}
      {debts.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>Your Debts</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {debts.map((d) => (
                <div key={d.id} className="flex items-center justify-between p-3 rounded-lg bg-muted/50 border border-border/50">
                  <div className="flex items-center gap-3">
                    <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center", d.type === "credit_card" ? "bg-danger/10" : "bg-warning/10")}>
                      {d.type === "credit_card" ? <CreditCard className="w-4 h-4 text-danger" /> : <Calendar className="w-4 h-4 text-warning" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-foreground">{d.name}</p>
                      <p className="text-[11px] text-muted-foreground">{d.rate}% APR ┬╖ Min: {fmt(d.minPayment)}/mo</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="text-sm font-bold text-foreground">{fmt(d.balance)}</span>
                    <button onClick={() => removeDebt(d.id)} className="text-muted-foreground hover:text-danger text-xs">├ù</button>
                  </div>
                </div>
              ))}
            </div>
            <div className="mt-4 pt-4 border-t border-border flex items-center gap-4">
              <span className="text-sm text-muted-foreground">Extra monthly payment:</span>
              <Input
                type="number"
                value={extraPayment}
                onChange={(e) => setExtraPayment(e.target.value)}
                className="w-32"
                placeholder="5000"
              />
            </div>
          </CardContent>
        </Card>
      )}

      {debts.length > 0 && (
        <>
          {/* Summary KPIs */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            <Card>
              <CardContent className="p-4">
                <p className="text-[11px] font-medium text-muted-foreground uppercase mb-1">Total Debt</p>
                <p className="text-xl font-bold text-danger">{fmt(totalDebt)}</p>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <p className="text-[11px] font-medium text-muted-foreground uppercase mb-1">Monthly Minimum</p>
                <p className="text-xl font-bold text-foreground">{fmt(totalMinPayments)}</p>
              </CardContent>
            </Card>
            <Card className="border-success/20">
              <CardContent className="p-4">
                <p className="text-[11px] font-medium text-muted-foreground uppercase mb-1">Interest Saved (Avalanche)</p>
                <p className="text-xl font-bold text-success">{fmt(interestSaved)}</p>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <p className="text-[11px] font-medium text-muted-foreground uppercase mb-1">Months Saved</p>
                <p className="text-xl font-bold text-brand">{monthsSaved > 0 ? monthsSaved : 0}</p>
              </CardContent>
            </Card>
          </div>

          {/* Strategy Comparison */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Avalanche */}
            <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }}>
              <Card className="border-brand/20 h-full">
                <CardHeader>
                  <div className="flex items-center justify-between">
                    <CardTitle className="flex items-center gap-2">
                      <Zap className="w-5 h-5 text-brand" /> Avalanche
                    </CardTitle>
                    <Badge variant="success">Recommended</Badge>
                  </div>
                  <p className="text-xs text-muted-foreground">Pay highest interest rate first (saves most money)</p>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Payoff time</span>
                      <span className="font-bold text-foreground">{avalanche.months} months ({(avalanche.months / 12).toFixed(1)} yrs)</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Total interest</span>
                      <span className="font-bold text-danger">{fmt(avalanche.totalInterest)}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Total paid</span>
                      <span className="font-bold text-foreground">{fmt(totalDebt + avalanche.totalInterest)}</span>
                    </div>
                    {avalanche.order.length > 0 && (
                      <div className="pt-3 border-t border-border">
                        <p className="text-[11px] font-medium text-muted-foreground mb-2">Payoff Order:</p>
                        <div className="flex flex-wrap gap-1">
                          {avalanche.order.map((id, i) => {
                            const d = debts.find((x) => x.id === id);
                            return d ? (
                              <span key={id} className="inline-flex items-center gap-1 text-[11px] px-2 py-0.5 rounded-full bg-muted">
                                <span className="text-muted-foreground">{i + 1}.</span>
                                <span className="font-medium text-foreground">{d.name}</span>
                              </span>
                            ) : null;
                          })}
                        </div>
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>
            </motion.div>

            {/* Snowball */}
            <motion.div initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }}>
              <Card className="h-full">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <Snowflake className="w-5 h-5 text-info" /> Snowball
                  </CardTitle>
                  <p className="text-xs text-muted-foreground">Pay smallest balance first (psychological wins)</p>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Payoff time</span>
                      <span className="font-bold text-foreground">{snowball.months} months ({(snowball.months / 12).toFixed(1)} yrs)</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Total interest</span>
                      <span className="font-bold text-danger">{fmt(snowball.totalInterest)}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Total paid</span>
                      <span className="font-bold text-foreground">{fmt(totalDebt + snowball.totalInterest)}</span>
                    </div>
                    {snowball.order.length > 0 && (
                      <div className="pt-3 border-t border-border">
                        <p className="text-[11px] font-medium text-muted-foreground mb-2">Payoff Order:</p>
                        <div className="flex flex-wrap gap-1">
                          {snowball.order.map((id, i) => {
                            const d = debts.find((x) => x.id === id);
                            return d ? (
                              <span key={id} className="inline-flex items-center gap-1 text-[11px] px-2 py-0.5 rounded-full bg-muted">
                                <span className="text-muted-foreground">{i + 1}.</span>
                                <span className="font-medium text-foreground">{d.name}</span>
                              </span>
                            ) : null;
                          })}
                        </div>
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          </div>

          {/* Payoff Timeline Chart */}
          <Card>
            <CardHeader>
              <CardTitle>Debt Payoff Timeline</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="w-full" style={{ height: 250 }}>
                <ResponsiveContainer width="100%" height={250}>
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                    <XAxis dataKey="month" tick={{ fontSize: 11 }} className="fill-muted-foreground" label={{ value: "Months", position: "bottom", fontSize: 11 }} />
                    <YAxis tick={{ fontSize: 11 }} className="fill-muted-foreground" tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
                    <RTooltip formatter={(value) => fmt(value as number)} />
                    <Bar dataKey="avalanche" name="Avalanche" fill="#0080ff" radius={[2, 2, 0, 0]} />
                    <Bar dataKey="snowball" name="Snowball" fill="#64748b" radius={[2, 2, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
              <div className="flex items-center justify-center gap-6 mt-3 text-xs text-muted-foreground">
                <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-brand" /> Avalanche</span>
                <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-[#64748b]" /> Snowball</span>
              </div>
            </CardContent>
          </Card>

          {/* Monthly Allocation */}
          <Card>
            <CardHeader>
              <CardTitle>Monthly Payment Allocation (Avalanche)</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {[...debts].sort((a, b) => b.rate - a.rate).map((d, i) => {
                  const isTarget = i === 0;
                  const payment = isTarget ? d.minPayment + extra : d.minPayment;
                  const totalMonthly = totalMinPayments + extra;
                  const pct = (payment / totalMonthly) * 100;
                  return (
                    <div key={d.id}>
                      <div className="flex justify-between items-center mb-1">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-medium text-foreground">{d.name}</span>
                          {isTarget && <Badge variant="success" className="text-[9px]">Priority</Badge>}
                        </div>
                        <span className="text-xs text-muted-foreground">{fmt(payment)}/mo ({d.rate}% APR)</span>
                      </div>
                      <Progress value={pct} />
                    </div>
                  );
                })}
              </div>
              <div className="mt-4 pt-3 border-t border-border flex justify-between text-sm">
                <span className="text-muted-foreground">Total monthly</span>
                <span className="font-bold text-foreground">{fmt(totalMinPayments + extra)}</span>
              </div>
            </CardContent>
          </Card>
        </>
      )}

      {debts.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <TrendingDown className="w-12 h-12 mx-auto mb-3 text-muted-foreground/40" />
            <p className="text-sm text-muted-foreground mb-1">No debts added yet</p>
            <p className="text-xs text-muted-foreground">Add your credit card balances, loans, or EMIs to compare payoff strategies.</p>
          </CardContent>
        </Card>
      )}

      {/* Add Debt Modal */}
      {showAdd && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={() => setShowAdd(false)}>
          <div onClick={(e) => e.stopPropagation()} className="w-full max-w-md mx-4 rounded-2xl bg-card border border-border shadow-2xl p-6">
            <h3 className="text-lg font-bold text-foreground mb-4">Add Debt</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-medium text-muted-foreground mb-1">Name</label>
                <Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="e.g. HDFC Credit Card" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-medium text-muted-foreground mb-1">Outstanding Balance</label>
                  <Input type="number" value={form.balance} onChange={(e) => setForm({ ...form, balance: e.target.value })} placeholder="50000" />
                </div>
                <div>
                  <label className="block text-xs font-medium text-muted-foreground mb-1">Interest Rate (%/yr)</label>
                  <Input type="number" value={form.rate} onChange={(e) => setForm({ ...form, rate: e.target.value })} placeholder="36" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-medium text-muted-foreground mb-1">Min Payment/month</label>
                  <Input type="number" value={form.minPayment} onChange={(e) => setForm({ ...form, minPayment: e.target.value })} placeholder="1000" />
                </div>
                <div>
                  <label className="block text-xs font-medium text-muted-foreground mb-1">Type</label>
                  <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value })} className="w-full h-9 px-3 rounded-lg border border-input bg-card text-sm text-foreground">
                    <option value="credit_card">Credit Card</option>
                    <option value="loan">Loan</option>
                    <option value="emi">EMI</option>
                  </select>
                </div>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowAdd(false)} className="flex-1 py-2 rounded-lg border border-border text-sm font-medium text-muted-foreground hover:bg-muted">Cancel</button>
                <button onClick={addDebt} className="flex-1 py-2 rounded-lg bg-brand text-white text-sm font-medium hover:bg-brand/90">Add</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useAuth } from "@/providers/AuthProvider";
import { db } from "@/lib/firebase";
import { collection, onSnapshot, query, orderBy } from "firebase/firestore";
import { lendingAPI } from "@/services/api";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Badge, Input } from "@/components/ui";
import ConfirmDialog from "@/components/ConfirmDialog";
import { Plus, ArrowUpRight, ArrowDownRight, Search, Trash2, X, Users } from "lucide-react";
import toast from "react-hot-toast";

interface LendingRecord {
  id: string;
  person_name: string;
  amount: number;
  paid_amount?: number;
  type: string;
  status: string;
  date: string;
}

export default function LendingPage() {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [records, setRecords] = useState<LendingRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ person_name: "", amount: "", type: "lent", date: new Date().toISOString().split("T")[0] });
  const [repayId, setRepayId] = useState<string | null>(null);
  const [repayAmount, setRepayAmount] = useState("");
  const [confirmState, setConfirmState] = useState<{ open: boolean; id?: string; name?: string }>({ open: false });
  const [tab, setTab] = useState<"active" | "settled">("active");
  const [searchText, setSearchText] = useState("");
  const [sortBy, setSortBy] = useState<"date" | "amount" | "name">("date");

  useEffect(() => {
    if (!user) return;
    const q = query(collection(db, `users/${user.uid}/lending`), orderBy("date", "desc"));
    const unsub = onSnapshot(q, (snap) => {
      setRecords(snap.docs.map((d) => ({ id: d.id, ...d.data() } as LendingRecord)));
      setLoading(false);
    });
    return () => unsub();
  }, [user]);

  const addMutation = useMutation({
    mutationFn: (data: Record<string, unknown>) => lendingAPI.create(data as Parameters<typeof lendingAPI.create>[0]),
    onSuccess: () => { toast.success("Record added!"); setShowAdd(false); setForm({ person_name: "", amount: "", type: "lent", date: new Date().toISOString().split("T")[0] }); },
    onError: () => toast.error("Failed"),
  });

  const repayMutation = useMutation({
    mutationFn: ({ id, amount }: { id: string; amount: number }) => lendingAPI.repay(id, amount),
    onSuccess: () => { toast.success("Repayment recorded!"); setRepayId(null); setRepayAmount(""); },
    onError: () => toast.error("Failed"),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => lendingAPI.delete(id),
    onSuccess: () => toast.success("Deleted!"),
    onError: () => toast.error("Failed"),
  });

  const totalLent = records.filter((r) => r.type === "lent" && r.status !== "settled").reduce((s, r) => s + ((r.amount || 0) - (r.paid_amount || 0)), 0);
  const totalBorrowed = records.filter((r) => r.type === "borrowed" && r.status !== "settled").reduce((s, r) => s + ((r.amount || 0) - (r.paid_amount || 0)), 0);

  const filteredRecords = useMemo(() => {
    let result = records.filter((r) => {
      const outstanding = (r.amount || 0) - (r.paid_amount || 0);
      const isSettled = r.status === "settled" || outstanding <= 0;
      return tab === "active" ? !isSettled : isSettled;
    });

    if (searchText.trim()) {
      const s = searchText.toLowerCase();
      result = result.filter((r) => r.person_name.toLowerCase().includes(s));
    }

    result = [...result].sort((a, b) => {
      if (sortBy === "date") return b.date.localeCompare(a.date);
      if (sortBy === "amount") return (b.amount || 0) - (a.amount || 0);
      return a.person_name.localeCompare(b.person_name);
    });

    return result;
  }, [records, tab, searchText, sortBy]);

  // Per-person summary
  const personSummary = useMemo(() => {
    const map: Record<string, { name: string; lent: number; borrowed: number; net: number }> = {};
    records.filter((r) => r.status !== "settled").forEach((r) => {
      const outstanding = (r.amount || 0) - (r.paid_amount || 0);
      if (outstanding <= 0) return;
      if (!map[r.person_name]) map[r.person_name] = { name: r.person_name, lent: 0, borrowed: 0, net: 0 };
      if (r.type === "lent") map[r.person_name].lent += outstanding;
      else map[r.person_name].borrowed += outstanding;
      map[r.person_name].net = map[r.person_name].lent - map[r.person_name].borrowed;
    });
    return Object.values(map).sort((a, b) => Math.abs(b.net) - Math.abs(a.net));
  }, [records]);

  if (loading) return (
    <div className="flex items-center justify-center h-[60vh]">
      <div className="w-10 h-10 border-4 border-brand/20 border-t-brand rounded-full animate-spin" />
    </div>
  );

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <div>
          <p className="text-sm text-muted-foreground mt-0.5">{records.length} records ┬╖ {personSummary.length} people</p>
        </div>
        <Button onClick={() => setShowAdd(!showAdd)} className="gap-1.5">
          <Plus className="w-4 h-4" /> Add Record
        </Button>
      </div>

      {/* Summary */}
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <ArrowUpRight className="w-4 h-4 text-success" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">People Owe You</span>
            </div>
            <p className="text-xl font-bold text-success">{fmt(totalLent)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-1">
              <ArrowDownRight className="w-4 h-4 text-danger" />
              <span className="text-[11px] font-medium text-muted-foreground uppercase">You Owe</span>
            </div>
            <p className="text-xl font-bold text-danger">{fmt(totalBorrowed)}</p>
          </CardContent>
        </Card>
        <Card className="hidden sm:block">
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Net Position</span>
            <p className={cn("text-xl font-bold mt-1", totalLent - totalBorrowed >= 0 ? "text-success" : "text-danger")}>
              {fmt(totalLent - totalBorrowed)}
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Per-Person Summary */}
      {personSummary.length > 0 && (
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2"><Users className="w-4 h-4" /> Per-Person Summary</CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <div className="flex flex-wrap gap-2">
              {personSummary.slice(0, 8).map((p) => (
                <button
                  key={p.name}
                  onClick={() => setSearchText(p.name)}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-medium transition-all hover:bg-muted/50",
                    p.net > 0 ? "border-success/30" : "border-danger/30"
                  )}
                >
                  <span className="text-foreground">{p.name}</span>
                  <span className={p.net > 0 ? "text-success" : "text-danger"}>{p.net > 0 ? "+" : ""}{fmt(p.net)}</span>
                </button>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Tabs + Search + Sort */}
      <div className="flex flex-wrap items-center gap-2">
        <div className="flex rounded-lg border border-border overflow-hidden">
          <button onClick={() => setTab("active")} className={cn("px-3 py-1.5 text-xs font-medium transition-colors", tab === "active" ? "bg-brand text-white" : "text-muted-foreground hover:bg-muted")}>Active</button>
          <button onClick={() => setTab("settled")} className={cn("px-3 py-1.5 text-xs font-medium transition-colors", tab === "settled" ? "bg-brand text-white" : "text-muted-foreground hover:bg-muted")}>Settled</button>
        </div>
        <div className="relative flex-1 min-w-[160px]">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input value={searchText} onChange={(e) => setSearchText(e.target.value)} placeholder="Search by name..." className="pl-9 h-8 text-sm" />
        </div>
        <div className="flex items-center gap-1">
          <span className="text-[10px] text-muted-foreground">Sort:</span>
          {(["date", "amount", "name"] as const).map((col) => (
            <button key={col} onClick={() => setSortBy(col)} className={cn("px-2 py-1 rounded text-[11px] font-medium capitalize transition-colors", sortBy === col ? "bg-brand/10 text-brand" : "text-muted-foreground hover:text-foreground")}>
              {col}
            </button>
          ))}
        </div>
      </div>

      {/* Add Form */}
      {showAdd && (
        <Card className="border-brand/20">
          <CardContent className="p-5">
            <form onSubmit={(e) => { e.preventDefault(); addMutation.mutate({ person_name: form.person_name, amount: parseFloat(form.amount), type: form.type, status: "pending", date: form.date }); }} className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <Input value={form.person_name} onChange={(e) => setForm({ ...form, person_name: e.target.value })} placeholder="Person Name" required />
                <Input type="number" value={form.amount} onChange={(e) => setForm({ ...form, amount: e.target.value })} placeholder="Amount (Γé╣)" required />
                <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value })} className="h-9 px-3 rounded-lg border border-input bg-card text-sm text-foreground">
                  <option value="lent">Lent (they owe me)</option>
                  <option value="borrowed">Borrowed (I owe them)</option>
                </select>
                <Input type="date" value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} />
              </div>
              <div className="flex gap-2">
                <Button type="submit" size="sm">Add</Button>
                <Button type="button" variant="ghost" size="sm" onClick={() => setShowAdd(false)}>Cancel</Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      {/* Records */}
      {filteredRecords.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-16">
            <p className="text-lg font-semibold text-foreground">{tab === "active" ? "No active records" : "No settled records"}</p>
            <p className="text-sm text-muted-foreground mt-1">
              {searchText ? "Try a different search" : tab === "active" ? "Add your first lending record" : "Settle records to see them here"}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-2">
          {filteredRecords.map((r) => {
            const outstanding = (r.amount || 0) - (r.paid_amount || 0);
            const isSettled = r.status === "settled" || outstanding <= 0;
            return (
              <Card key={r.id} className={cn(isSettled && "opacity-60")}>
                <CardContent className="p-4 flex flex-wrap items-center gap-4">
                  <div className={cn("w-9 h-9 rounded-lg flex items-center justify-center", r.type === "lent" ? "bg-success/10" : "bg-danger/10")}>
                    {r.type === "lent" ? <ArrowUpRight className="w-4 h-4 text-success" /> : <ArrowDownRight className="w-4 h-4 text-danger" />}
                  </div>
                  <div className="flex-1 min-w-[140px]">
                    <p className="text-sm font-semibold text-foreground">{r.person_name}</p>
                    <p className="text-[11px] text-muted-foreground">{r.type === "lent" ? "You lent" : "You borrowed"} ┬╖ {new Date(r.date).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })}</p>
                  </div>
                  <div className="text-right">
                    <p className={cn("text-base font-bold", r.type === "lent" ? "text-success" : "text-danger")}>{fmt(r.amount)}</p>
                    {!isSettled && <p className="text-[11px] text-muted-foreground">Remaining: {fmt(outstanding)}</p>}
                    {isSettled && <Badge variant="success" className="text-[10px]">Settled</Badge>}
                  </div>
                  {!isSettled && (
                    <div className="flex gap-2 items-center">
                      {repayId === r.id ? (
                        <form onSubmit={(e) => { e.preventDefault(); repayMutation.mutate({ id: r.id, amount: parseFloat(repayAmount) }); }} className="flex gap-1.5 items-center">
                          <Input type="number" value={repayAmount} onChange={(e) => setRepayAmount(e.target.value)} placeholder="Γé╣" className="w-20 h-7 text-xs" required />
                          <Button type="submit" size="sm" className="h-7 px-2 text-[11px]">Record</Button>
                          <button type="button" onClick={() => setRepayId(null)} className="p-1 text-muted-foreground hover:text-foreground"><X className="w-3.5 h-3.5" /></button>
                        </form>
                      ) : (
                        <Button variant="outline" size="sm" className="h-7 text-[11px]" onClick={() => setRepayId(r.id)}>Repay</Button>
                      )}
                      <button onClick={() => setConfirmState({ open: true, id: r.id, name: r.person_name })} className="p-1.5 text-danger/70 hover:text-danger hover:bg-danger/10 rounded-lg transition-colors">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      <ConfirmDialog open={confirmState.open} title={`Delete record for "${confirmState.name}"?`} message="This will permanently remove this record." confirmColor="danger" onConfirm={() => { if (confirmState.id) deleteMutation.mutate(confirmState.id); setConfirmState({ open: false }); }} onCancel={() => setConfirmState({ open: false })} />
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { recurringAPI } from "@/services/api";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Button,
  Input,
  Badge,
} from "@/components/ui";
import EmptyState from "@/components/EmptyState";
import {
  Plus,
  Pause,
  Play,
  Square,
  Trash2,
  CalendarClock,
  Repeat,
  TrendingDown,
  Edit2,
  X,
  Check,
} from "lucide-react";
import toast from "react-hot-toast";

type RecurringStatus = "active" | "paused" | "stopped";
type Frequency = "weekly" | "monthly" | "yearly";

interface FormData {
  description: string;
  category: string;
  amount: string;
  frequency: Frequency;
  next_date: string;
  account_id: string;
  payment_type: string;
  type: string;
}

const INITIAL_FORM: FormData = {
  description: "",
  category: "",
  amount: "",
  frequency: "monthly",
  next_date: new Date().toISOString().split("T")[0],
  account_id: "",
  payment_type: "",
  type: "expense",
};

const FREQ_LABEL: Record<Frequency, string> = {
  weekly: "Weekly",
  monthly: "Monthly",
  yearly: "Yearly",
};

const STATUS_STYLES: Record<RecurringStatus, string> = {
  active: "bg-success/10 text-success border-success/20",
  paused: "bg-warning/10 text-warning border-warning/20",
  stopped: "bg-danger/10 text-danger border-danger/20",
};

function getNextDate(current: string, frequency: Frequency): string {
  const d = new Date(current);
  if (frequency === "weekly") d.setDate(d.getDate() + 7);
  else if (frequency === "monthly") d.setMonth(d.getMonth() + 1);
  else d.setFullYear(d.getFullYear() + 1);
  return d.toISOString().split("T")[0];
}

function getDaysUntil(dateStr: string): number {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const target = new Date(dateStr);
  target.setHours(0, 0, 0, 0);
  return Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
}

export default function RecurringPage() {
  const { recurring, categories, accounts, transactions } = useData();
  const queryClient = useQueryClient();
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<FormData>(INITIAL_FORM);
  const [filterStatus, setFilterStatus] = useState<RecurringStatus | "all">("all");
  const [filterFreq, setFilterFreq] = useState<Frequency | "all">("all");
  const migrationDone = useRef(false);

  // Auto-migrate transactions marked is_recurring into the recurring collection
  useEffect(() => {
    if (migrationDone.current) return;
    if (recurring.length > 0) { migrationDone.current = true; return; }

    const recurringTxns = transactions.filter(
      (t) => (t as unknown as Record<string, unknown>).is_recurring === true
    );
    if (recurringTxns.length === 0) return;
    migrationDone.current = true;

    // Group by description/category to avoid duplicates
    const seen = new Set<string>();
    const toCreate: Record<string, unknown>[] = [];

    for (const t of recurringTxns) {
      const raw = t as unknown as Record<string, unknown>;
      const key = `${(t.description || t.category).toLowerCase()}|${t.category}`;
      if (seen.has(key)) continue;
      seen.add(key);

      const freq = (raw.recurrence_interval || raw.recurring_frequency || "monthly") as string;
      const nextDate = (raw.next_date as string) || t.date;

      toCreate.push({
        description: t.description || t.notes || t.category,
        category: t.category,
        amount: Math.abs(t.amount),
        frequency: freq === "weekly" ? "weekly" : freq === "yearly" ? "yearly" : "monthly",
        next_date: nextDate,
        account_id: t.account_id || "",
        type: t.amount < 0 ? "expense" : "income",
        status: "active",
      });
    }

    if (toCreate.length === 0) return;
    Promise.all(toCreate.map((d) => recurringAPI.create(d))).then(() => {
      toast.success(`Migrated ${toCreate.length} recurring item(s)`);
    }).catch(() => {});
  }, [recurring, transactions]);

  // Mutations
  const createMutation = useMutation({
    mutationFn: (data: Record<string, unknown>) => recurringAPI.create(data),
    onSuccess: () => {
      toast.success("Recurring item created");
      setShowForm(false);
      setForm(INITIAL_FORM);
      queryClient.invalidateQueries({ queryKey: ["recurring"] });
    },
    onError: (err: Error) => toast.error(err.message),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Record<string, unknown> }) =>
      recurringAPI.update(id, data),
    onSuccess: () => {
      toast.success("Updated");
      setEditingId(null);
      setForm(INITIAL_FORM);
      queryClient.invalidateQueries({ queryKey: ["recurring"] });
    },
    onError: (err: Error) => toast.error(err.message),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => recurringAPI.delete(id),
    onSuccess: () => {
      toast.success("Deleted");
      queryClient.invalidateQueries({ queryKey: ["recurring"] });
    },
    onError: (err: Error) => toast.error(err.message),
  });

  // Filtered list
  const filtered = useMemo(() => {
    return recurring.filter((item) => {
      if (filterStatus !== "all" && item.status !== filterStatus) return false;
      if (filterFreq !== "all" && item.frequency !== filterFreq) return false;
      return true;
    });
  }, [recurring, filterStatus, filterFreq]);

  // Summary stats
  const stats = useMemo(() => {
    const active = recurring.filter((r) => r.status === "active");
    const monthlyTotal = active.reduce((sum, r) => {
      if (r.frequency === "monthly") return sum + r.amount;
      if (r.frequency === "weekly") return sum + r.amount * 4.33;
      if (r.frequency === "yearly") return sum + r.amount / 12;
      return sum;
    }, 0);
    const yearlyTotal = monthlyTotal * 12;
    const dueNext7 = active.filter((r) => {
      const days = getDaysUntil(r.next_date);
      return days >= 0 && days <= 7;
    }).length;
    return { total: recurring.length, active: active.length, monthlyTotal, yearlyTotal, dueNext7 };
  }, [recurring]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      description: form.description.trim(),
      category: form.category,
      amount: parseFloat(form.amount),
      frequency: form.frequency,
      next_date: form.next_date,
      account_id: form.account_id || null,
      payment_type: form.payment_type || null,
      type: form.type,
    };

    if (editingId) {
      updateMutation.mutate({ id: editingId, data: payload });
    } else {
      createMutation.mutate(payload);
    }
  };

  const handleEdit = (item: typeof recurring[0]) => {
    setEditingId(item.id);
    setForm({
      description: item.description,
      category: item.category,
      amount: String(item.amount),
      frequency: item.frequency,
      next_date: item.next_date,
      account_id: item.account_id || "",
      payment_type: item.payment_type || "",
      type: item.type || "expense",
    });
    setShowForm(true);
  };

  const handleStatusChange = (id: string, status: RecurringStatus) => {
    updateMutation.mutate({ id, data: { status } });
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Recurring Transactions</h1>
          <p className="text-sm text-muted-foreground mt-1">
            Manage your scheduled bills, subscriptions, and recurring payments
          </p>
        </div>
        <Button onClick={() => { setShowForm(!showForm); setEditingId(null); setForm(INITIAL_FORM); }}>
          <Plus className="w-4 h-4 mr-1.5" />
          Add Recurring
        </Button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Card>
          <CardContent className="p-4">
            <p className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Active</p>
            <p className="text-2xl font-bold text-foreground mt-1">{stats.active}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <p className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Monthly Cost</p>
            <p className="text-2xl font-bold text-foreground mt-1">{fmt(stats.monthlyTotal)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <p className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Yearly Cost</p>
            <p className="text-2xl font-bold text-foreground mt-1">{fmt(stats.yearlyTotal)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <p className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">Due (7 days)</p>
            <p className="text-2xl font-bold text-brand mt-1">{stats.dueNext7}</p>
          </CardContent>
        </Card>
      </div>

      {/* Add/Edit Form */}
      <AnimatePresence>
        {showForm && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            className="overflow-hidden"
          >
            <Card>
              <CardHeader>
                <CardTitle>{editingId ? "Edit Recurring" : "New Recurring Transaction"}</CardTitle>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleSubmit} className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Description *</label>
                    <Input
                      value={form.description}
                      onChange={(e) => setForm({ ...form, description: e.target.value })}
                      placeholder="Netflix, Rent, Gym..."
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Category *</label>
                    <select
                      value={form.category}
                      onChange={(e) => setForm({ ...form, category: e.target.value })}
                      className="w-full h-9 px-3 rounded-lg border border-border bg-background text-sm text-foreground"
                      required
                    >
                      <option value="">Select category</option>
                      {categories.map((c) => (
                        <option key={c.id} value={c.name}>{c.name}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Amount *</label>
                    <Input
                      type="number"
                      min="0"
                      step="0.01"
                      value={form.amount}
                      onChange={(e) => setForm({ ...form, amount: e.target.value })}
                      placeholder="500"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Frequency *</label>
                    <select
                      value={form.frequency}
                      onChange={(e) => setForm({ ...form, frequency: e.target.value as Frequency })}
                      className="w-full h-9 px-3 rounded-lg border border-border bg-background text-sm text-foreground"
                    >
                      <option value="weekly">Weekly</option>
                      <option value="monthly">Monthly</option>
                      <option value="yearly">Yearly</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Next Due Date *</label>
                    <Input
                      type="date"
                      value={form.next_date}
                      onChange={(e) => setForm({ ...form, next_date: e.target.value })}
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Type</label>
                    <select
                      value={form.type}
                      onChange={(e) => setForm({ ...form, type: e.target.value })}
                      className="w-full h-9 px-3 rounded-lg border border-border bg-background text-sm text-foreground"
                    >
                      <option value="expense">Expense</option>
                      <option value="income">Income</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Account</label>
                    <select
                      value={form.account_id}
                      onChange={(e) => setForm({ ...form, account_id: e.target.value })}
                      className="w-full h-9 px-3 rounded-lg border border-border bg-background text-sm text-foreground"
                    >
                      <option value="">No account</option>
                      {accounts.map((a) => (
                        <option key={a.id} value={a.id}>{a.account_name}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-muted-foreground mb-1.5">Payment Method</label>
                    <select
                      value={form.payment_type}
                      onChange={(e) => setForm({ ...form, payment_type: e.target.value })}
                      className="w-full h-9 px-3 rounded-lg border border-border bg-background text-sm text-foreground"
                    >
                      <option value="">Any</option>
                      <option value="UPI">UPI</option>
                      <option value="Debit Card">Debit Card</option>
                      <option value="Credit Card">Credit Card</option>
                      <option value="Cash">Cash</option>
                    </select>
                  </div>
                  <div className="flex items-end gap-2 sm:col-span-2 lg:col-span-1">
                    <Button type="submit" disabled={createMutation.isPending || updateMutation.isPending} className="flex-1">
                      <Check className="w-4 h-4 mr-1.5" />
                      {editingId ? "Update" : "Create"}
                    </Button>
                    <Button
                      type="button"
                      variant="ghost"
                      onClick={() => { setShowForm(false); setEditingId(null); setForm(INITIAL_FORM); }}
                    >
                      <X className="w-4 h-4" />
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Filters */}
      <div className="flex flex-wrap gap-2">
        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
          <span className="font-medium">Status:</span>
          {(["all", "active", "paused", "stopped"] as const).map((s) => (
            <button
              key={s}
              onClick={() => setFilterStatus(s)}
              className={cn(
                "px-2.5 py-1 rounded-md font-medium transition-colors capitalize",
                filterStatus === s
                  ? "bg-brand/10 text-brand"
                  : "hover:bg-muted text-muted-foreground"
              )}
            >
              {s}
            </button>
          ))}
        </div>
        <div className="flex items-center gap-1.5 text-xs text-muted-foreground ml-4">
          <span className="font-medium">Freq:</span>
          {(["all", "weekly", "monthly", "yearly"] as const).map((f) => (
            <button
              key={f}
              onClick={() => setFilterFreq(f)}
              className={cn(
                "px-2.5 py-1 rounded-md font-medium transition-colors capitalize",
                filterFreq === f
                  ? "bg-brand/10 text-brand"
                  : "hover:bg-muted text-muted-foreground"
              )}
            >
              {f}
            </button>
          ))}
        </div>
      </div>

      {/* Recurring List */}
      {filtered.length === 0 ? (
        <EmptyState
          icon={Repeat}
          title="No recurring transactions"
          description="Add your bills, subscriptions, and regular payments to track them automatically."
          actionLabel="Add Recurring"
          onAction={() => setShowForm(true)}
        />
      ) : (
        <div className="space-y-2">
          {filtered.map((item) => {
            const daysUntil = getDaysUntil(item.next_date);
            const isOverdue = daysUntil < 0 && item.status === "active";
            const isDueSoon = daysUntil >= 0 && daysUntil <= 3 && item.status === "active";

            return (
              <motion.div
                key={item.id}
                layout
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                className={cn(
                  "flex items-center gap-4 p-4 rounded-xl border transition-all",
                  isOverdue
                    ? "border-danger/30 bg-danger/5"
                    : isDueSoon
                    ? "border-warning/30 bg-warning/5"
                    : "border-border bg-card hover:border-border/80"
                )}
              >
                {/* Icon */}
                <div
                  className={cn(
                    "w-10 h-10 rounded-xl flex items-center justify-center shrink-0",
                    item.status === "active" ? "bg-brand/10" : "bg-muted"
                  )}
                >
                  {item.status === "paused" ? (
                    <Pause className="w-4 h-4 text-warning" />
                  ) : item.status === "stopped" ? (
                    <Square className="w-4 h-4 text-danger" />
                  ) : (
                    <Repeat className="w-4 h-4 text-brand" />
                  )}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-sm text-foreground truncate">
                      {item.description}
                    </span>
                    <Badge
                      variant="outline"
                      className={cn("text-[10px] px-1.5 py-0", STATUS_STYLES[item.status])}
                    >
                      {item.status}
                    </Badge>
                    {isOverdue && (
                      <Badge className="text-[10px] px-1.5 py-0 bg-danger/10 text-danger border-danger/20">
                        Overdue
                      </Badge>
                    )}
                  </div>
                  <div className="flex items-center gap-3 mt-1 text-xs text-muted-foreground">
                    <span>{item.category}</span>
                    <span>ΓÇó</span>
                    <span>{FREQ_LABEL[item.frequency]}</span>
                    {item.status === "active" && (
                      <>
                        <span>ΓÇó</span>
                        <span className={cn(isOverdue && "text-danger", isDueSoon && "text-warning")}>
                          {isOverdue
                            ? `${Math.abs(daysUntil)}d overdue`
                            : daysUntil === 0
                            ? "Due today"
                            : `in ${daysUntil}d`}
                        </span>
                      </>
                    )}
                  </div>
                </div>

                {/* Amount */}
                <div className="text-right shrink-0">
                  <p className={cn("font-bold text-sm", item.type === "income" ? "text-success" : "text-foreground")}>
                    {item.type === "income" ? "+" : "-"}{fmt(item.amount)}
                  </p>
                  {item.next_date && item.status === "active" && (
                    <p className="text-[11px] text-muted-foreground mt-0.5">
                      Next: {new Date(item.next_date).toLocaleDateString("en-IN", { day: "numeric", month: "short" })}
                    </p>
                  )}
                </div>

                {/* Actions */}
                <div className="flex items-center gap-1 shrink-0">
                  {item.status === "active" && (
                    <button
                      onClick={() => handleStatusChange(item.id, "paused")}
                      className="p-1.5 rounded-md text-muted-foreground hover:text-warning hover:bg-warning/10 transition-colors"
                      title="Pause"
                    >
                      <Pause className="w-3.5 h-3.5" />
                    </button>
                  )}
                  {item.status === "paused" && (
                    <button
                      onClick={() => handleStatusChange(item.id, "active")}
                      className="p-1.5 rounded-md text-muted-foreground hover:text-success hover:bg-success/10 transition-colors"
                      title="Resume"
                    >
                      <Play className="w-3.5 h-3.5" />
                    </button>
                  )}
                  {item.status !== "stopped" && (
                    <button
                      onClick={() => handleStatusChange(item.id, "stopped")}
                      className="p-1.5 rounded-md text-muted-foreground hover:text-danger hover:bg-danger/10 transition-colors"
                      title="Stop"
                    >
                      <Square className="w-3.5 h-3.5" />
                    </button>
                  )}
                  {item.status === "stopped" && (
                    <button
                      onClick={() => handleStatusChange(item.id, "active")}
                      className="p-1.5 rounded-md text-muted-foreground hover:text-success hover:bg-success/10 transition-colors"
                      title="Reactivate"
                    >
                      <Play className="w-3.5 h-3.5" />
                    </button>
                  )}
                  <button
                    onClick={() => handleEdit(item)}
                    className="p-1.5 rounded-md text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
                    title="Edit"
                  >
                    <Edit2 className="w-3.5 h-3.5" />
                  </button>
                  <button
                    onClick={() => {
                      if (confirm("Delete this recurring item?")) {
                        deleteMutation.mutate(item.id);
                      }
                    }}
                    className="p-1.5 rounded-md text-muted-foreground hover:text-danger hover:bg-danger/10 transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo, useCallback } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { transactionsAPI } from "@/services/api";
import { useUndoDelete } from "@/hooks/useUndoDelete";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import TransactionTable from "@/components/TransactionTable";
import QuickAddTransaction from "@/components/QuickAddTransaction";
import ConfirmDialog from "@/components/ConfirmDialog";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, Button, Badge, Input } from "@/components/ui";
import {
  Plus, Search, X, ArrowUpRight, ArrowDownRight,
  Download, Trash2, CheckSquare,
} from "lucide-react";
import toast from "react-hot-toast";
import { saveAs } from "file-saver";
import * as XLSX from "xlsx";
import { SkeletonTable } from "@/components/SkeletonLoader";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment"]);
const PAYMENT_METHODS = ["Cash", "Debit Card", "UPI", "Self Transfer"];

export default function TransactionsPage() {
  const queryClient = useQueryClient();
  const { accounts, creditCards, categories, cycleStartDay, transactions, dataReady } = useData();

  const [selectedCycle, setSelectedCycle] = useState(0);
  const [showAdd, setShowAdd] = useState(false);

  // Listen for keyboard shortcut "N" via custom event from CommandPalette
  useEffect(() => {
    const handler = () => setShowAdd(true);
    document.addEventListener("quick-add-open", handler);
    return () => document.removeEventListener("quick-add-open", handler);
  }, []);

  if (!dataReady) {
    return <SkeletonTable rows={8} cols={5} />;
  }
  const [editTxn, setEditTxn] = useState<Record<string, unknown> | null>(null);
  const [searchText, setSearchText] = useState("");
  const [filterCategory, setFilterCategory] = useState("");
  const [filterPayment, setFilterPayment] = useState("");
  const [filterType, setFilterType] = useState<"all" | "income" | "expense" | "transfer">("all");
  const [filterAccount, setFilterAccount] = useState("");
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);
  const [sortBy, setSortBy] = useState<"date" | "amount" | "category">("date");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [selectionMode, setSelectionMode] = useState(false);

  const recentCycles = useMemo(() => getRecentFinancialMonths(8, new Date(), cycleStartDay), [cycleStartDay]);
  const currentCycle = recentCycles[selectedCycle];

  const cycleTxns = useMemo(() => {
    if (!currentCycle) return transactions.filter((t) => t.payment_type !== "Credit Card" && !creditCards.some((c) => c.id === t.account_id));
    return transactions.filter((t) => t.date >= currentCycle.startDate && t.date <= currentCycle.endDate && t.payment_type !== "Credit Card" && !creditCards.some((c) => c.id === t.account_id));
  }, [transactions, currentCycle, creditCards]);

  const filteredTxns = useMemo(() => {
    let result = cycleTxns;

    if (searchText.trim()) {
      const s = searchText.toLowerCase();
      result = result.filter((t) =>
        t.notes?.toLowerCase().includes(s) ||
        t.category?.toLowerCase().includes(s) ||
        t.description?.toLowerCase().includes(s) ||
        String(Math.abs(t.amount)).includes(s)
      );
    }

    if (filterCategory) result = result.filter((t) => t.category === filterCategory);
    if (filterPayment) result = result.filter((t) => t.payment_type === filterPayment);
    if (filterAccount) result = result.filter((t) => t.account_id === filterAccount);

    if (filterType === "income") result = result.filter((t) => t.amount > 0 || t.category === "Income");
    else if (filterType === "expense") result = result.filter((t) => t.amount < 0 && t.category !== "Transfer" && t.category !== "Credit Card Payment");
    else if (filterType === "transfer") result = result.filter((t) => t.category === "Transfer" || t.payment_type === "Self Transfer");

    // Sort
    result = [...result].sort((a, b) => {
      let cmp = 0;
      if (sortBy === "date") cmp = a.date.localeCompare(b.date);
      else if (sortBy === "amount") cmp = Math.abs(a.amount) - Math.abs(b.amount);
      else if (sortBy === "category") cmp = (a.category || "").localeCompare(b.category || "");
      return sortOrder === "desc" ? -cmp : cmp;
    });

    return result;
  }, [cycleTxns, searchText, filterCategory, filterPayment, filterAccount, filterType, sortBy, sortOrder]);

  const stats = useMemo(() => {
    let income = 0, expense = 0;
    cycleTxns.forEach((t) => {
      if (t.payment_type === "Credit Card" || t.payment_type === "Self Transfer" || SKIP_CATS.has(t.category)) return;
      if (t.category === "Income") income += Math.abs(t.amount);
      else if (t.amount < 0) expense += Math.abs(t.amount);
    });
    const topCategory = Object.entries(
      cycleTxns.filter((t) => t.amount < 0 && !SKIP_CATS.has(t.category) && t.category !== "Income")
        .reduce((acc, t) => { acc[t.category] = (acc[t.category] || 0) + Math.abs(t.amount); return acc; }, {} as Record<string, number>)
    ).sort((a, b) => b[1] - a[1])[0];
    return { income, expense, net: income - expense, topCategory: topCategory?.[0] || "-", count: cycleTxns.length };
  }, [cycleTxns]);

  const activeFilters = [filterCategory, filterPayment, filterAccount, filterType !== "all" ? filterType : ""].filter(Boolean);

  const clearAllFilters = () => {
    setFilterCategory("");
    setFilterPayment("");
    setFilterAccount("");
    setFilterType("all");
    setSearchText("");
  };

  const addTxnMutation = useMutation({
    mutationFn: (data: unknown) => transactionsAPI.create(data as Parameters<typeof transactionsAPI.create>[0]),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["transactions"] }); toast.success("Transaction added!"); },
    onError: () => toast.error("Failed to add transaction"),
  });

  const updateTxnMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Record<string, unknown> }) => transactionsAPI.update(id, data as Parameters<typeof transactionsAPI.update>[1]),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["transactions"] }); toast.success("Updated!"); },
    onError: () => toast.error("Failed to update"),
  });

  const deleteTxnMutation = useMutation({
    mutationFn: (id: string) => transactionsAPI.delete(id),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["transactions"] }); },
    onError: () => toast.error("Failed to delete"),
  });

  const { softDelete: undoDelete } = useUndoDelete({
    deleteFn: (id) => deleteTxnMutation.mutateAsync(id),
    entityName: "Transaction",
  });

  const handleSubmit = (data: unknown) => {
    const d = data as Record<string, unknown>;
    if (editTxn?.id) {
      updateTxnMutation.mutate({ id: editTxn.id as string, data: d });
    } else {
      addTxnMutation.mutate(d);
    }
    setEditTxn(null);
  };

  const toggleSort = (col: typeof sortBy) => {
    if (sortBy === col) setSortOrder(sortOrder === "asc" ? "desc" : "asc");
    else { setSortBy(col); setSortOrder("desc"); }
  };

  const handleToggleSelect = useCallback((id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  }, []);

  const handleToggleSelectAll = useCallback((txns: { id: string }[]) => {
    setSelectedIds((prev) => {
      const allSelected = txns.every((t) => prev.has(t.id));
      if (allSelected) return new Set();
      return new Set(txns.map((t) => t.id));
    });
  }, []);

  const handleBulkDelete = () => {
    const count = selectedIds.size;
    if (count === 0) return;
    setConfirmDelete("__bulk__");
  };

  const executeBulkDelete = async () => {
    const ids = Array.from(selectedIds);
    let success = 0;
    for (const id of ids) {
      try { await transactionsAPI.delete(id); success++; } catch { /* skip */ }
    }
    toast.success(`Deleted ${success} transactions`);
    setSelectedIds(new Set());
    setSelectionMode(false);
    queryClient.invalidateQueries({ queryKey: ["transactions"] });
  };

  const handleExport = () => {
    const data = filteredTxns.map((t) => ({
      Date: t.date,
      Category: t.category,
      Amount: t.amount,
      "Payment Method": t.payment_type || "",
      Account: [...accounts, ...creditCards].find((a) => a.id === t.account_id)?.account_name || "",
      Notes: t.notes || "",
    }));
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Transactions");
    const buf = XLSX.write(wb, { bookType: "xlsx", type: "array" });
    saveAs(new Blob([buf], { type: "application/octet-stream" }), `transactions-${currentCycle?.cycleKey || "all"}.xlsx`);
    toast.success(`Exported ${data.length} transactions`);
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <p className="text-sm text-muted-foreground">
            {currentCycle?.label} ┬╖ {stats.count} transactions
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm" onClick={handleExport} className="gap-1.5 text-xs">
            <Download className="w-3.5 h-3.5" /> Export
          </Button>
          <Button
            variant={selectionMode ? "default" : "outline"}
            size="sm"
            onClick={() => { setSelectionMode(!selectionMode); setSelectedIds(new Set()); }}
            className="gap-1.5 text-xs"
          >
            <CheckSquare className="w-3.5 h-3.5" /> {selectionMode ? "Cancel" : "Select"}
          </Button>
          <Button onClick={() => { setEditTxn(null); setShowAdd(true); }} className="gap-2">
            <Plus className="w-4 h-4" /> Add Transaction
          </Button>
        </div>
      </div>

      {/* Bulk Actions Bar */}
      {selectionMode && selectedIds.size > 0 && (
        <div className="flex items-center gap-3 px-4 py-2.5 rounded-lg bg-brand/5 border border-brand/20">
          <span className="text-sm font-medium text-brand">{selectedIds.size} selected</span>
          <div className="flex-1" />
          <Button variant="outline" size="sm" onClick={handleExport} className="gap-1.5 text-xs">
            <Download className="w-3.5 h-3.5" /> Export Selected
