/* ΓöÇΓöÇΓöÇ KPI Widget ΓöÇΓöÇΓöÇ */
function KpiStrip({ items }: { items: Array<{ label: string; value: number; icon: React.ReactNode; trend?: number; isPercent?: boolean; color: string }> }) {
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
      {items.map((item) => (
        <Card key={item.label} className="group hover:border-brand/30 transition-all duration-300">
          <CardContent className="p-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">
                {item.label}
              </span>
              <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center transition-colors", `bg-[${item.color}]/10`)} style={{ backgroundColor: `${item.color}15` }}>
                {item.icon}
              </div>
            </div>
            <p className="text-xl font-bold tracking-tight text-foreground">
              {item.isPercent ? (
                <CountUp end={item.value} decimals={1} suffix="%" duration={1} />
              ) : (
                <CountUp end={item.value} decimals={0} duration={1} formattingFn={(n) => "Γé╣" + new Intl.NumberFormat("en-IN").format(n)} />
              )}
            </p>
            {item.trend !== undefined && item.trend !== 0 && (
              <div className="flex items-center gap-1 mt-1.5">
                {item.trend > 0 ? (
                  <ArrowUpRight className="w-3 h-3 text-success" />
                ) : (
                  <ArrowDownRight className="w-3 h-3 text-danger" />
                )}
                <span className="text-[11px] font-medium text-muted-foreground">
                  {Math.abs(item.trend).toFixed(1)}% vs last
                </span>
              </div>
            )}
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Health Gauge ΓöÇΓöÇΓöÇ */
function HealthGauge({ score }: { score: number }) {
  const getLabel = (s: number) => s >= 80 ? "Excellent" : s >= 60 ? "Good" : s >= 40 ? "Average" : "Poor";
  const getColor = (s: number) => s >= 80 ? "var(--color-success)" : s >= 60 ? "hsl(var(--brand))" : s >= 40 ? "var(--color-warning)" : "var(--color-danger)";
  const color = getColor(score);
  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative w-[130px] h-[75px] overflow-hidden">
        <svg width="130" height="75" viewBox="0 0 130 75" className="absolute top-0 left-0">
          <path d="M 10 65 A 55 55 0 0 1 120 65" className="stroke-muted" strokeWidth="10" fill="none" strokeLinecap="round" />
          <path d="M 10 65 A 55 55 0 0 1 120 65" stroke={color} strokeWidth="10" fill="none" strokeLinecap="round" strokeDasharray={`${(score / 100) * 173} 173`} className="transition-all duration-1000" />
        </svg>
        <div className="absolute bottom-2 left-0 right-0 text-center text-2xl font-bold text-foreground">{score}</div>
      </div>
      <Badge variant={score >= 60 ? "success" : score >= 40 ? "warning" : "danger"}>
        {getLabel(score)}
      </Badge>
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Cycle Progress Ring ΓöÇΓöÇΓöÇ */
function CycleProgressRing({ daysElapsed, totalDays, dailyBudgetLeft }: { daysElapsed: number; totalDays: number; dailyBudgetLeft: number }) {
  const progress = (daysElapsed / totalDays) * 100;
  const circumference = 2 * Math.PI * 40;
  const offset = circumference - (progress / 100) * circumference;
  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative w-24 h-24">
        <svg className="w-24 h-24 -rotate-90" viewBox="0 0 100 100">
          <circle cx="50" cy="50" r="40" className="stroke-muted" strokeWidth="8" fill="none" />
          <circle cx="50" cy="50" r="40" className="stroke-brand transition-all duration-1000" strokeWidth="8" fill="none" strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset} />
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-lg font-bold text-foreground">{daysElapsed}</span>
          <span className="text-[10px] text-muted-foreground">/ {totalDays}</span>
        </div>
      </div>
      <div className="text-center">
        <p className="text-xs text-muted-foreground">{totalDays - daysElapsed} days left</p>
        <p className="text-sm font-semibold text-foreground mt-0.5">
          {fmt(dailyBudgetLeft)}<span className="text-muted-foreground font-normal">/day</span>
        </p>
      </div>
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Spending Heatmap ΓöÇΓöÇΓöÇ */
function SpendingHeatmap({ transactions }: { transactions: Array<{ amount: number; date: string; category: string; payment_type?: string }> }) {
  const today = new Date();
  const days: string[] = [];
  for (let i = 29; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    days.push(d.toISOString().split("T")[0]);
  }
  const daysSet = new Set(days);
  const spendByDay: Record<string, number> = {};
  transactions.forEach((t) => {
    if (t.amount < 0 && daysSet.has(t.date) && t.category !== "Transfer" && !t.payment_type?.includes("Transfer") && t.category !== "Credit Card Payment") {
      spendByDay[t.date] = (spendByDay[t.date] || 0) + Math.abs(t.amount);
    }
  });
  const maxSpend = Math.max(...Object.values(spendByDay), 1);
  return (
    <div>
      <div className="grid grid-cols-10 gap-1">
        {days.map((day) => {
          const amt = spendByDay[day] || 0;
          const intensity = amt / maxSpend;
          const bg = amt === 0
            ? "bg-muted"
            : intensity > 0.7 ? "bg-danger" : intensity > 0.4 ? "bg-warning" : "bg-success";
          return (
            <div
              key={day}
              title={`${day}: ${fmt(amt)}`}
              className={cn("aspect-square rounded-[3px] transition-transform hover:scale-125", bg)}
              style={amt > 0 ? { opacity: 0.4 + intensity * 0.6 } : undefined}
            />
          );
        })}
      </div>
      <div className="flex gap-2 mt-2 items-center">
        <span className="text-[10px] text-muted-foreground">Less</span>
        <div className="w-2.5 h-2.5 rounded-sm bg-success opacity-50" />
        <div className="w-2.5 h-2.5 rounded-sm bg-warning opacity-70" />
        <div className="w-2.5 h-2.5 rounded-sm bg-danger" />
        <span className="text-[10px] text-muted-foreground">More</span>
      </div>
    </div>
  );
}

export default function DashboardPage() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { user } = useAuth();
  const { transactions, accounts, creditCards, categories, cycleStartDay, currentAggregate, recurring } = useData();
  const [showQuickAdd, setShowQuickAdd] = useState(false);
  const [goals, setGoals] = useState<Array<{ id: string; target_amount?: number; current_amount?: number }>>([]);
  const [mutualFunds, setMutualFunds] = useState<Array<{ id: string; current_nav?: string; units: string; invested_amount?: string }>>([]);
  const [lending, setLending] = useState<Array<{ id: string; type: string; amount: number; paid_amount?: number }>>([]);
  const [prevAggregate, setPrevAggregate] = useState<Record<string, number> | null>(null);
  const [pastAggregates, setPastAggregates] = useState<Array<{ cycleKey: string; label: string; totalSpent: number; totalIncome: number }>>([]);

  // Listen for keyboard shortcut "N" via custom event from CommandPalette
  useEffect(() => {
    const handler = () => setShowQuickAdd(true);
    document.addEventListener("quick-add-open", handler);
    return () => document.removeEventListener("quick-add-open", handler);
  }, []);

  useEffect(() => {
    if (!user) return;
    const uid = user.uid;
    const unsubs = [
      onSnapshot(collection(db, `users/${uid}/goals`), (snap) => setGoals(snap.docs.map((d) => ({ id: d.id, ...d.data() } as typeof goals[0])))),
      onSnapshot(collection(db, `users/${uid}/mutualFunds`), (snap) => setMutualFunds(snap.docs.map((d) => ({ id: d.id, ...d.data() } as typeof mutualFunds[0])))),
      onSnapshot(collection(db, `users/${uid}/lending`), (snap) => setLending(snap.docs.map((d) => ({ id: d.id, ...d.data() } as typeof lending[0])))),
    ];
    return () => unsubs.forEach((fn) => fn());
  }, [user]);

  // Load past 6 cycle aggregates for trend chart
  useEffect(() => {
    if (!user) return;
    const cycles = getRecentFinancialMonths(6, new Date(), cycleStartDay);
    const unsubs = cycles.map((c) =>
      onSnapshot(doc(db, `users/${user.uid}/aggregates/${c.cycleKey}`), (snap) => {
        setPastAggregates((prev) => {
          const filtered = prev.filter((p) => p.cycleKey !== c.cycleKey);
          if (snap.exists()) {
            const data = snap.data();
            filtered.push({ cycleKey: c.cycleKey, label: c.label.split(" ")[0].slice(0, 3), totalSpent: data.totalSpent || 0, totalIncome: data.totalIncome || 0 });
          }
          return filtered.sort((a, b) => a.cycleKey.localeCompare(b.cycleKey));
        });
      })
    );
    return () => unsubs.forEach((fn) => fn());
  }, [user, cycleStartDay]);

  const currentCycle = useMemo(() => getFinancialCycle(new Date(), cycleStartDay), [cycleStartDay]);
  const cycleInfo = useMemo(() => getCycleDayInfo(new Date(), cycleStartDay), [cycleStartDay]);

  const prevCycleKey = useMemo(() => {
    const cycles = getRecentFinancialMonths(2, new Date(), cycleStartDay);
    return cycles.length > 1 ? cycles[1].cycleKey : null;
  }, [cycleStartDay]);

  useEffect(() => {
    if (!user || !prevCycleKey) return;
    const unsub = onSnapshot(doc(db, `users/${user.uid}/aggregates/${prevCycleKey}`), (snap) => {
      if (snap.exists()) setPrevAggregate(snap.data() as Record<string, number>);
      else setPrevAggregate(null);
    });
    return () => unsub();
  }, [user, prevCycleKey]);

  const bankAccounts = useMemo(() => accounts.filter((a) => a.type !== "credit"), [accounts]);
  const accountsBalance = bankAccounts.reduce((s, a) => s + (a.balance || 0), 0);
  const totalSavings = mutualFunds.reduce((s, mf) => {
    const val = mf.current_nav ? parseFloat(mf.current_nav) * parseFloat(mf.units) : parseFloat(mf.invested_amount || "0");
    return s + val;
  }, 0);
  const totalLiabilities = creditCards.reduce((s, cc) => s + parseFloat(String(cc.liability || cc.balance || 0)), 0)
    + lending.filter((l) => l.type === "borrowed").reduce((s, l) => s + ((l.amount || 0) - (l.paid_amount || 0)), 0);
  const netWorth = accountsBalance + totalSavings - totalLiabilities;

  const cycleTxns = useMemo(() => transactions.filter((t) => t.date >= currentCycle.startDate && t.date <= currentCycle.endDate), [transactions, currentCycle]);

  const cashFlow = useMemo(() => {
    let tIncome = 0, tExpense = 0;
    const skipCats = new Set(["Transfer", "Credit Card Payment"]);
    cycleTxns.forEach((t) => {
      if (t.payment_type === "Credit Card" || t.payment_type === "Self Transfer" || t.payment_type === "Transfer" || skipCats.has(t.category)) return;
      if (t.category === "Income") tIncome += Math.abs(t.amount);
      else if (t.amount < 0) tExpense += Math.abs(t.amount);
    });
    return { totalIncome: tIncome, totalExpenses: tExpense, netSavings: tIncome - tExpense, dailyAvgSpend: cycleInfo.daysElapsed > 0 ? tExpense / cycleInfo.daysElapsed : 0 };
  }, [cycleTxns, cycleInfo]);

  const savingsRate = cashFlow.totalIncome > 0 ? ((cashFlow.totalIncome - cashFlow.totalExpenses) / cashFlow.totalIncome) * 100 : 0;

  const categoryData = useMemo(() => {
    const map: Record<string, { name: string; value: number; color: string }> = {};
    cycleTxns.forEach((t) => {
      if (t.category === "Income" || t.amount >= 0 || t.category === "Transfer" || t.payment_type === "Credit Card" || t.payment_type?.includes("Transfer") || t.category === "Credit Card Payment") return;
      const col = categories.find((c) => c.name === t.category)?.color || "#94a3b8";
      if (!map[t.category]) map[t.category] = { name: t.category, value: 0, color: col };
      map[t.category].value += Math.abs(t.amount);
    });
    return Object.values(map).sort((a, b) => b.value - a.value);
  }, [cycleTxns, categories]);

  const healthScore = useMemo(() => {
    let score = 0;
    score += Math.min(30, (savingsRate / 20) * 30);
    const totalCCLimit = creditCards.reduce((s, c) => s + parseFloat(String(c.credit_limit || 0)), 0);
    const totalCCOutstanding = creditCards.reduce((s, c) => s + parseFloat(String(c.liability || c.balance || 0)), 0);
    const ccUtil = totalCCLimit > 0 ? totalCCOutstanding / totalCCLimit : 0;
    score += Math.max(0, 25 - ccUtil * 83);
    score += 25;
    score += 10;
    return Math.max(0, Math.min(100, Math.round(score)));
  }, [savingsRate, creditCards]);

  const riskAlerts = useMemo(() => {
    const alerts: Array<{ type: "danger" | "warning"; message: string }> = [];
    bankAccounts.forEach((a) => { if ((a.balance || 0) < 1000) alerts.push({ type: "danger", message: `Low balance: ${a.account_name} ΓÇö ${fmt(a.balance || 0)}` }); });
    creditCards.forEach((cc) => {
      const health = calculateCreditCardHealth(cc, creditCards);
      if (health.utilization > 80) alerts.push({ type: "danger", message: `${cc.account_name} at ${health.utilization}% utilization` });
      else if (health.utilization > 50) alerts.push({ type: "warning", message: `${cc.account_name} at ${health.utilization}% utilization` });
    });
    return alerts.slice(0, 4);
  }, [bankAccounts, creditCards]);

  // Budget usage for top categories
  const budgetStatus = useMemo(() => {
    if (!currentAggregate?.categoryBreakdown) return [];
    const breakdown = currentAggregate.categoryBreakdown as Record<string, number>;
    return Object.entries(breakdown)
      .filter(([cat]) => cat !== "Income" && cat !== "Transfer" && cat !== "Credit Card Payment")
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([cat, spent]) => ({ category: cat, spent, color: categories.find((c) => c.name === cat)?.color || "#94a3b8" }));
  }, [currentAggregate, categories]);

  // CC overview
  const ccOverview = useMemo(() => {
    const totalLimit = creditCards.reduce((s, c) => s + parseFloat(String(c.credit_limit || 0)), 0);
    const totalOutstanding = creditCards.reduce((s, c) => s + parseFloat(String(c.liability || c.balance || 0)), 0);
    const utilization = totalLimit > 0 ? (totalOutstanding / totalLimit) * 100 : 0;
    return { totalLimit, totalOutstanding, available: totalLimit - totalOutstanding, utilization };
  }, [creditCards]);

  // Daily budget remaining
  const dailyBudgetLeft = useMemo(() => {
    const remaining = cashFlow.totalIncome - cashFlow.totalExpenses;
    const daysLeft = cycleInfo.totalDays - cycleInfo.daysElapsed;
    return daysLeft > 0 ? remaining / daysLeft : 0;
  }, [cashFlow, cycleInfo]);

  // Smart insights (enhanced)
  const insights = useMemo(() => {
    const pastBreakdowns = pastAggregates
      .filter((p) => p.cycleKey !== currentCycle.cycleKey)
      .map((p) => {
        // We only have totalSpent/totalIncome in pastAggregates, not full breakdowns
        // Use current aggregate breakdown as proxy for anomaly detection seed
        return {};
      });

    const smartInsights = generateSmartInsights({
      aggregate: currentAggregate,
      budgets: [],
      accounts,
      transactions: cycleTxns,
      recurring,
      income: cashFlow.totalIncome,
      daysElapsed: cycleInfo.daysElapsed,
      totalDays: cycleInfo.totalDays,
      savingsRate,
    });

    return smartInsights.slice(0, 5);
  }, [currentAggregate, accounts, cycleTxns, recurring, cashFlow, cycleInfo, savingsRate, pastAggregates, currentCycle]);

  // Recent transactions
  const recentTxns = useMemo(() => cycleTxns.slice(0, 8), [cycleTxns]);

  const addTxnMutation = useMutation({
    mutationFn: (data: unknown) => transactionsAPI.create(data as Parameters<typeof transactionsAPI.create>[0]),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["transactions"] }),
  });

  // Trends for KPI
  const getTrend = (current: number, prevKey: string) => {
    if (!prevAggregate || !(prevKey in prevAggregate) || prevAggregate[prevKey] === 0) return undefined;
    return ((current - prevAggregate[prevKey]) / prevAggregate[prevKey]) * 100;
  };

  // Dashboard DnD
  const { layout, reorder, isVisible, toggleVisibility } = useDashboardLayout();
  const [showWidgetPicker, setShowWidgetPicker] = useState(false);
  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor)
  );

  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      reorder(active.id as WidgetId, over.id as WidgetId);
    }
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <p className="text-sm text-muted-foreground">{currentCycle.label} ┬╖ Day {cycleInfo.daysElapsed} of {cycleInfo.totalDays}</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => setShowWidgetPicker(true)} className="gap-1.5">
            <Settings2 className="w-3.5 h-3.5" /> Customize
          </Button>
          <Button onClick={() => setShowQuickAdd(true)} className="gap-2">
            <Plus className="w-4 h-4" /> Add Transaction
          </Button>
        </div>
      </div>

      {/* Widget Picker Modal */}
      {showWidgetPicker && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4" onClick={() => setShowWidgetPicker(false)}>
          <Card className="w-full max-w-sm" onClick={(e) => e.stopPropagation()}>
            <CardContent className="p-5 space-y-3">
              <h3 className="text-base font-bold text-foreground">Dashboard Widgets</h3>
              <p className="text-xs text-muted-foreground">Toggle widgets on/off. Drag to reorder on the dashboard.</p>
              {WIDGET_IDS.map((id) => (
                <label key={id} className="flex items-center justify-between py-2 cursor-pointer">
                  <span className="text-sm text-foreground">{WIDGET_LABELS[id]}</span>
                  <input
                    type="checkbox"
                    checked={isVisible(id)}
                    onChange={() => toggleVisibility(id)}
                    className="h-4 w-4 rounded border-border accent-brand"
                  />
                </label>
              ))}
              <Button variant="outline" className="w-full mt-2" onClick={() => setShowWidgetPicker(false)}>Done</Button>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Sortable Widgets */}
      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <SortableContext items={layout.order} strategy={verticalListSortingStrategy}>
          {layout.order.map((widgetId) => {
            if (!isVisible(widgetId)) return null;
            return (
              <SortableWidget key={widgetId} id={widgetId}>
                {widgetId === "kpi-strip" && (
      <KpiStrip items={[
        { label: "Net Worth", value: netWorth, icon: <Wallet className="w-4 h-4" style={{ color: "#0080ff" }} />, color: "#0080ff" },
        { label: "Balance", value: accountsBalance, icon: <Landmark className="w-4 h-4" style={{ color: "#10b981" }} />, color: "#10b981" },
        { label: "Income", value: cashFlow.totalIncome, icon: <TrendingUp className="w-4 h-4" style={{ color: "#22c55e" }} />, color: "#22c55e", trend: getTrend(cashFlow.totalIncome, "totalIncome") },
        { label: "Expenses", value: cashFlow.totalExpenses, icon: <TrendingDown className="w-4 h-4" style={{ color: "#ef4444" }} />, color: "#ef4444", trend: getTrend(cashFlow.totalExpenses, "totalSpent") },
        { label: "Savings Rate", value: savingsRate, icon: <PiggyBank className="w-4 h-4" style={{ color: "#f59e0b" }} />, color: "#f59e0b", isPercent: true },
      ]} />
                )}
                {widgetId === "cash-flow-row" && (
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        {/* Cash Flow Chart (2 cols) */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle>Cash Flow</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-4 gap-2 mb-4">
              {[
                { label: "Income", value: cashFlow.totalIncome, color: "text-success" },
                { label: "Expenses", value: cashFlow.totalExpenses, color: "text-danger" },
                { label: "Net", value: cashFlow.netSavings, color: cashFlow.netSavings >= 0 ? "text-success" : "text-danger" },
                { label: "Daily Avg", value: cashFlow.dailyAvgSpend, color: "text-warning" },
              ].map(({ label, value, color }) => (
                <div key={label} className="rounded-lg bg-muted/50 p-2.5">
                  <p className="text-[10px] font-medium text-muted-foreground uppercase">{label}</p>
                  <p className={cn("text-sm font-bold mt-0.5", color)}>{fmt(Math.abs(value))}</p>
                </div>
              ))}
            </div>
            <div>
              <div className="flex justify-between text-[11px] text-muted-foreground mb-1">
                <span>Cycle progress</span>
                <span>{cycleInfo.daysRemaining} days left</span>
              </div>
              <Progress value={(cycleInfo.daysElapsed / cycleInfo.totalDays) * 100} />
            </div>
          </CardContent>
        </Card>

        {/* Financial Health (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>Health Score</CardTitle>
          </CardHeader>
          <CardContent className="flex justify-center">
            <HealthGauge score={healthScore} />
          </CardContent>
        </Card>

        {/* Cycle Progress Ring (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>Cycle Progress</CardTitle>
          </CardHeader>
          <CardContent className="flex justify-center">
            <CycleProgressRing
              daysElapsed={cycleInfo.daysElapsed}
              totalDays={cycleInfo.totalDays}
              dailyBudgetLeft={dailyBudgetLeft}
            />
          </CardContent>
        </Card>
      </div>
                )}
                {widgetId === "category-row" && (
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        {/* Spending by Category (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>By Category</CardTitle>
          </CardHeader>
          <CardContent>
            {categoryData.length > 0 ? (
              <>
                <div className="w-full" style={{ height: 160 }}>
                  <ResponsiveContainer width="100%" height={160}>
                    <PieChart>
                      <Pie data={categoryData.slice(0, 6)} cx="50%" cy="50%" innerRadius={35} outerRadius={60} paddingAngle={3} dataKey="value" stroke="none">
                        {categoryData.slice(0, 6).map((item, i) => <Cell key={i} fill={item.color} />)}
                      </Pie>
                      <RTooltip formatter={(value) => fmt(Number(value))} />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                <div className="flex flex-wrap gap-1 mt-2">
                  {categoryData.slice(0, 4).map((item) => (
                    <Badge key={item.name} variant="secondary" className="text-[10px] gap-1">
                      <span className="w-1.5 h-1.5 rounded-full" style={{ background: item.color }} />
                      {item.name}
                    </Badge>
                  ))}
                </div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
                <CircleDot className="w-8 h-8 mb-2 opacity-50" />
                <p className="text-xs">No data yet</p>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Budget Status (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>Top Spending</CardTitle>
          </CardHeader>
          <CardContent>
            {budgetStatus.length > 0 ? (
              <div className="space-y-3">
                {budgetStatus.map((b) => (
                  <div key={b.category}>
                    <div className="flex justify-between items-center mb-1">
                      <span className="text-xs font-medium text-foreground">{b.category}</span>
                      <span className="text-xs text-muted-foreground">{fmt(b.spent)}</span>
                    </div>
                    <div className="h-1.5 rounded-full bg-muted overflow-hidden">
                      <div className="h-full rounded-full transition-all" style={{ width: `${Math.min(100, (b.spent / (cashFlow.totalExpenses || 1)) * 100)}%`, backgroundColor: b.color }} />
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
                <Target className="w-8 h-8 mb-2 opacity-50" />
                <p className="text-xs">No spending yet</p>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Spending Trend (2 cols) */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle>Spending Trend</CardTitle>
          </CardHeader>
          <CardContent>
            {pastAggregates.length > 1 ? (
              <div className="w-full" style={{ height: 180 }}>
                <ResponsiveContainer width="100%" height={180}>
                  <AreaChart data={pastAggregates}>
                    <defs>
                      <linearGradient id="spendGradient" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="hsl(var(--brand))" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="hsl(var(--brand))" stopOpacity={0} />
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                    <XAxis dataKey="label" tick={{ fontSize: 11 }} className="fill-muted-foreground" />
                    <YAxis tick={{ fontSize: 11 }} className="fill-muted-foreground" tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
                    <RTooltip formatter={(value) => fmt(Number(value))} />
                    <Area type="monotone" dataKey="totalSpent" stroke="hsl(var(--brand))" fill="url(#spendGradient)" strokeWidth={2} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
                <BarChart3 className="w-8 h-8 mb-2 opacity-50" />
                <p className="text-xs">Need more cycles for trends</p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
                )}
                {widgetId === "activity-row" && (
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
        {/* Recent Transactions (2 cols) */}
        <Card className="lg:col-span-2">
          <CardHeader className="flex-row items-center justify-between">
            <CardTitle>Recent Transactions</CardTitle>
            <Button variant="ghost" size="sm" onClick={() => router.push("/money/transactions")} className="text-xs text-brand">
              View all
            </Button>
          </CardHeader>
          <CardContent>
            {recentTxns.length > 0 ? (
              <div className="space-y-1">
                {recentTxns.map((t) => (
                  <div key={t.id} className="flex items-center justify-between py-2 border-b border-border last:border-0">
                    <div className="flex items-center gap-3">
                      <div className={cn("w-8 h-8 rounded-lg flex items-center justify-center", t.amount > 0 ? "bg-success/10" : "bg-danger/10")}>
                        {t.amount > 0 ? <ArrowUpRight className="w-4 h-4 text-success" /> : <ArrowDownRight className="w-4 h-4 text-danger" />}
                      </div>
                      <div>
                        <p className="text-sm font-medium text-foreground">{t.category}</p>
                        <p className="text-[11px] text-muted-foreground">{t.date}</p>
                      </div>
                    </div>
                    <span className={cn("text-sm font-semibold", t.amount > 0 ? "text-success" : "text-foreground")}>
                      {t.amount > 0 ? "+" : ""}{fmt(t.amount)}
                    </span>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
                <ArrowLeftRight className="w-8 h-8 mb-2 opacity-50" />
                <p className="text-xs">No transactions yet</p>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Smart Insights (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>Insights</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {insights.map((insight) => (
                <div
                  key={insight.id}
                  className={cn(
                    "flex items-start gap-2 p-2.5 rounded-lg border cursor-pointer transition-colors",
                    insight.type === "success" ? "bg-success/5 border-success/20 hover:bg-success/10" :
                    insight.type === "warning" ? "bg-warning/5 border-warning/20 hover:bg-warning/10" :
                    insight.type === "danger" ? "bg-danger/5 border-danger/20 hover:bg-danger/10" :
                    "bg-info/5 border-info/20 hover:bg-info/10"
                  )}
                  onClick={() => insight.actionPath && router.push(insight.actionPath)}
                >
                  {insight.type === "success" ? <CheckCircle2 className="w-3.5 h-3.5 mt-0.5 text-success flex-shrink-0" /> :
                   insight.type === "warning" ? <AlertTriangle className="w-3.5 h-3.5 mt-0.5 text-warning flex-shrink-0" /> :
                   insight.type === "danger" ? <AlertTriangle className="w-3.5 h-3.5 mt-0.5 text-danger flex-shrink-0" /> :
                   <Zap className="w-3.5 h-3.5 mt-0.5 text-info flex-shrink-0" />}
                  <div className="flex-1 min-w-0">
                    <p className="text-[11px] font-semibold text-foreground">{insight.title}</p>
                    <p className="text-xs leading-relaxed text-muted-foreground">{insight.message}</p>
                  </div>
                </div>
              ))}
              {insights.length === 0 && (
                <div className="flex items-start gap-2 p-2.5 rounded-lg border bg-info/5 border-info/20">
                  <Zap className="w-3.5 h-3.5 mt-0.5 text-info flex-shrink-0" />
                  <p className="text-xs leading-relaxed text-foreground">Your finances are on track this cycle.</p>
                </div>
              )}
            </div>

            {/* Spending Heatmap (compact) */}
            <div className="mt-4 pt-4 border-t border-border">
              <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider mb-2">30-Day Heatmap</p>
              <SpendingHeatmap transactions={transactions} />
            </div>
          </CardContent>
        </Card>

        {/* Quick Actions + CC Overview (1 col) */}
        <Card>
          <CardHeader>
            <CardTitle>Quick Actions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 gap-2 mb-4">
              {[
                { label: "Transaction", icon: Plus, action: () => setShowQuickAdd(true) },
                { label: "Pay CC", icon: CreditCard, action: () => router.push("/credit/statements") },
                { label: "Budgets", icon: Target, action: () => router.push("/spending/budgets") },
                { label: "Export", icon: BarChart3, action: () => router.push("/settings") },
              ].map((item) => (
                <button
                  key={item.label}
                  onClick={item.action}
                  className="flex flex-col items-center gap-1.5 p-3 rounded-lg bg-muted/50 hover:bg-muted transition-colors text-foreground"
                >
                  <item.icon className="w-4 h-4 text-brand" />
                  <span className="text-[10px] font-medium">{item.label}</span>
                </button>
              ))}
            </div>

            {/* CC Overview mini */}
            {creditCards.length > 0 && (
              <div className="pt-3 border-t border-border">
                <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider mb-2">Credit Cards</p>
                <div className="space-y-1.5">
                  <div className="flex justify-between text-xs">
                    <span className="text-muted-foreground">Utilization</span>
                    <span className="font-semibold text-foreground">{ccOverview.utilization.toFixed(0)}%</span>
                  </div>
                  <Progress
                    value={ccOverview.utilization}
                    indicatorClassName={ccOverview.utilization > 50 ? "bg-danger" : ccOverview.utilization > 30 ? "bg-warning" : "bg-success"}
                  />
                  <div className="flex justify-between text-[11px] text-muted-foreground mt-1">
                    <span>Used: {fmt(ccOverview.totalOutstanding)}</span>
                    <span>Limit: {fmt(ccOverview.totalLimit)}</span>
                  </div>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
                )}
              </SortableWidget>
            );
          })}
        </SortableContext>
      </DndContext>

      {showQuickAdd && (
        <QuickAddTransaction isOpen={showQuickAdd} onClose={() => setShowQuickAdd(false)} onSubmit={(data) => addTxnMutation.mutate(data)} accounts={accounts} creditCards={creditCards} categories={categories} />
      )}
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { useInvestments } from "@/hooks/useInvestments";
import {
  calculateNetWorth,
  calculatePortfolioAllocation,
  calculateSavingsRateFromAggregates,
  calculateCCUtilization,
} from "@/utils/calculations";
import { useTheme } from "@/providers/ThemeProvider";
import { Heart, ShieldCheck, PiggyBank, CreditCard, Landmark, PieChart as PieIcon, type LucideIcon } from "lucide-react";
import { motion } from "framer-motion";
import ExportBar from "@/components/ExportBar";

interface Pillar {
  name: string;
  icon: LucideIcon;
  score: number;
  maxScore: number;
  status: string;
  color: string;
  advice: string;
}

export default function FinancialHealthPage() {
  const { accounts, currentAggregate } = useData();
  const { investments } = useInvestments();
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const savingsData = useMemo(
    () => calculateSavingsRateFromAggregates(currentAggregate || {}),
    [currentAggregate]
  );

  const netWorthData = useMemo(
    () => calculateNetWorth(accounts, investments, []),
    [accounts, investments]
  );

  const allocation = useMemo(
    () => calculatePortfolioAllocation(accounts, investments),
    [accounts, investments]
  );

  const ccMetrics = useMemo(
    () => calculateCCUtilization(accounts),
    [accounts]
  );

  // Calculate individual pillar scores
  const pillars: Pillar[] = useMemo(() => {
    // 1. Savings Rate (0-30 pts)
    const savingsRate = savingsData.savings_rate || 0;
    const savingsScore = Math.min(30, Math.round((savingsRate / 20) * 30));
    const savingsStatus = savingsRate >= 20 ? "Excellent" : savingsRate >= 10 ? "Fair" : "Needs Work";
    const savingsColor = savingsRate >= 20 ? "#10b981" : savingsRate >= 10 ? "#f59e0b" : "#ef4444";
    const savingsAdvice = savingsRate >= 20
      ? `Saving ${savingsRate.toFixed(0)}% ΓÇö well above the 20% target.`
      : savingsRate >= 10
      ? `Saving ${savingsRate.toFixed(0)}%. Aim for 20%+ by cutting discretionary spending.`
      : `Only saving ${savingsRate.toFixed(0)}%. Review subscriptions and dining out expenses.`;

    // 2. Debt Health (0-30 pts)
    const totalDebt = netWorthData.total_cc_outstanding || 0;
    const totalAssets = (netWorthData.total_accounts || 0) + (netWorthData.total_investments || 0);
    const debtRatio = totalAssets > 0 ? totalDebt / totalAssets : totalDebt > 0 ? 1 : 0;
    const debtScore = Math.max(0, Math.round(30 - debtRatio * 60));
    const avgUtil = ccMetrics.length > 0 ? ccMetrics.reduce((s, c) => s + c.utilization_percentage, 0) / ccMetrics.length : 0;
    const debtStatus = debtScore >= 25 ? "Excellent" : debtScore >= 15 ? "Fair" : "Needs Work";
    const debtColor = debtScore >= 25 ? "#10b981" : debtScore >= 15 ? "#f59e0b" : "#ef4444";
    const highUtilCards = ccMetrics.filter((c) => c.utilization_percentage > 30);
    const debtAdvice = highUtilCards.length > 0
      ? `${highUtilCards.length} card(s) above 30% utilization. Pay down Γé╣${Math.round(highUtilCards.reduce((s, c) => s + Math.max(0, c.outstanding - c.credit_limit * 0.3), 0)).toLocaleString("en-IN")} to fix.`
      : totalDebt > 0
      ? `CC outstanding: Γé╣${totalDebt.toLocaleString("en-IN")}. Keep utilization below 30%.`
      : "No credit card debt. Excellent!";

    // 3. Emergency Fund (0-20 pts)
    const monthlyExpenses = savingsData.expenses || 0;
    const targetEmergency = monthlyExpenses > 0 ? monthlyExpenses * 3 : 50000;
    const currentCash = allocation.totals?.Cash || 0;
    const emergencyScore = Math.min(20, Math.round((currentCash / targetEmergency) * 20));
    const emergencyMonths = monthlyExpenses > 0 ? currentCash / monthlyExpenses : 0;
    const emergencyStatus = emergencyMonths >= 3 ? "Excellent" : emergencyMonths >= 1 ? "Fair" : "Needs Work";
    const emergencyColor = emergencyMonths >= 3 ? "#10b981" : emergencyMonths >= 1 ? "#f59e0b" : "#ef4444";
    const emergencyAdvice = emergencyMonths >= 6
      ? `${emergencyMonths.toFixed(1)} months of expenses covered. Well cushioned.`
      : emergencyMonths >= 3
      ? `${emergencyMonths.toFixed(1)} months covered. Consider building to 6 months.`
      : `Only ${emergencyMonths.toFixed(1)} months of runway. Target Γé╣${targetEmergency.toLocaleString("en-IN")} (3 months).`;

    // 4. Diversification (0-20 pts)
    const percentages = allocation.percentages || {};
    const maxAlloc = Math.max(percentages.Equity || 0, percentages.Debt || 0, percentages.Gold || 0, percentages.Crypto || 0);
    const diversScore = totalAssets > 0 ? (maxAlloc < 80 ? 20 : Math.max(0, Math.round(100 - maxAlloc))) : 0;
    const assetClasses = Object.values(percentages).filter((v) => v > 5).length;
    const diversStatus = diversScore >= 15 ? "Excellent" : diversScore >= 8 ? "Fair" : "Needs Work";
    const diversColor = diversScore >= 15 ? "#10b981" : diversScore >= 8 ? "#f59e0b" : "#ef4444";
    const diversAdvice = assetClasses >= 3
      ? `Spread across ${assetClasses} asset classes. Well diversified.`
      : totalAssets > 0
      ? `Concentrated in ${assetClasses} class(es). Consider adding Gold or Debt for balance.`
      : "No investments yet. Start with a diversified portfolio.";

    return [
      { name: "Savings Rate", icon: PiggyBank, score: savingsScore, maxScore: 30, status: savingsStatus, color: savingsColor, advice: savingsAdvice },
      { name: "Debt Health", icon: CreditCard, score: debtScore, maxScore: 30, status: debtStatus, color: debtColor, advice: debtAdvice },
      { name: "Emergency Fund", icon: Landmark, score: emergencyScore, maxScore: 20, status: emergencyStatus, color: emergencyColor, advice: emergencyAdvice },
      { name: "Diversification", icon: PieIcon, score: diversScore, maxScore: 20, status: diversStatus, color: diversColor, advice: diversAdvice },
    ];
  }, [savingsData, netWorthData, allocation, ccMetrics]);

  const totalScore = pillars.reduce((s, p) => s + p.score, 0);
  const overallColor = totalScore >= 70 ? "#10b981" : totalScore >= 40 ? "#f59e0b" : "#ef4444";
  const overallLabel = totalScore >= 70 ? "Excellent" : totalScore >= 40 ? "Good" : "Needs Attention";

  return (
    <div className="space-y-6">
      {/* Header with export */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold">Financial Health</h1>
        <ExportBar elementId="health-report" filename="financial-health" title="Financial Health Score" />
      </div>

      <div id="health-report" className="space-y-6">
      {/* Overall Score */}
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="rounded-2xl border border-border p-6 sm:p-8 flex flex-col items-center"
        style={{ background: isDark ? "#111827" : "#ffffff" }}
      >
        <Heart className="w-6 h-6 mb-3" style={{ color: overallColor }} />
        <p className="text-sm text-muted-foreground mb-4">Financial Health Score</p>

        {/* Score Ring */}
        <div className="relative w-36 h-36 mb-4">
          <svg className="w-full h-full -rotate-90" viewBox="0 0 120 120">
            <circle cx="60" cy="60" r="50" fill="none" stroke={isDark ? "#1f2937" : "#e5e7eb"} strokeWidth="10" />
            <circle
              cx="60" cy="60" r="50" fill="none"
              stroke={overallColor}
              strokeWidth="10" strokeLinecap="round"
              strokeDasharray={`${(totalScore / 100) * 314} 314`}
            />
          </svg>
          <div className="absolute inset-0 flex flex-col items-center justify-center">
            <span className="text-3xl font-extrabold text-foreground">{totalScore}</span>
            <span className="text-xs text-muted-foreground">/100</span>
          </div>
        </div>

        <p className="text-lg font-bold" style={{ color: overallColor }}>{overallLabel}</p>
        <p className="text-xs text-muted-foreground mt-1 text-center max-w-sm">
          Based on savings discipline, debt management, emergency preparedness, and investment diversification.
        </p>
      </motion.div>

      {/* Pillar Breakdown */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {pillars.map((pillar, idx) => {
          const Icon = pillar.icon;
          const pct = (pillar.score / pillar.maxScore) * 100;

          return (
            <motion.div
              key={pillar.name}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.1 }}
              className="rounded-2xl border border-border p-5 space-y-3"
              style={{ background: isDark ? "#111827" : "#ffffff" }}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg flex items-center justify-center" style={{ background: `${pillar.color}20` }}>
                    <Icon className="w-4 h-4" style={{ color: pillar.color }} />
                  </div>
                  <div>
                    <h4 className="text-sm font-bold text-foreground">{pillar.name}</h4>
                    <p className="text-[11px]" style={{ color: pillar.color }}>{pillar.status}</p>
                  </div>
                </div>
                <span className="text-lg font-bold text-foreground">
                  {pillar.score}<span className="text-xs text-muted-foreground">/{pillar.maxScore}</span>
                </span>
              </div>

              {/* Progress Bar */}
              <div className="w-full h-2 rounded-full bg-muted overflow-hidden">
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${pct}%` }}
                  transition={{ duration: 0.8, delay: idx * 0.1 }}
                  className="h-full rounded-full"
                  style={{ background: pillar.color }}
                />
              </div>

              {/* Advice */}
              <p className="text-xs text-muted-foreground">{pillar.advice}</p>
            </motion.div>
          );
        })}
      </div>

      {/* Tips */}
      <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
        <div className="flex items-center gap-2">
          <ShieldCheck className="w-4 h-4 text-brand" />
          <h3 className="text-sm font-bold text-foreground">How to Improve</h3>
        </div>
        <div className="space-y-2 text-sm">
          {pillars
            .filter((p) => p.score < p.maxScore * 0.7)
            .sort((a, b) => (a.score / a.maxScore) - (b.score / b.maxScore))
            .slice(0, 3)
            .map((p) => (
              <div key={p.name} className="flex items-start gap-2 py-1">
                <span className="w-1.5 h-1.5 rounded-full mt-1.5 shrink-0" style={{ background: p.color }} />
                <div>
                  <span className="font-medium text-foreground">{p.name}: </span>
                  <span className="text-muted-foreground">{p.advice}</span>
                </div>
              </div>
            ))}
          {pillars.every((p) => p.score >= p.maxScore * 0.7) && (
            <p className="text-muted-foreground">All pillars are in good shape. Keep up the great work!</p>
          )}
        </div>
      </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { generateInsightsFromAggregates, generateCycleComparisonInsights } from "@/utils/insights";
import { fmt } from "@/utils/format";
import { useTheme } from "@/providers/ThemeProvider";
import ChartCard from "@/components/ChartCard";
import StatCard from "@/components/StatCard";
import { CalendarDays, TrendingUp, TrendingDown, Wallet, PiggyBank, Lightbulb } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Tooltip, Cell } from "recharts";
import { motion } from "framer-motion";
import ExportBar from "@/components/ExportBar";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment"]);

export default function MonthlyReviewPage() {
  const { transactions, cycleStartDay, accounts } = useData();
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const recentCycles = useMemo(
    () => getRecentFinancialMonths(8, new Date(), cycleStartDay),
    [cycleStartDay]
  );

  const [selectedIdx, setSelectedIdx] = useState(0);
  const selectedCycle = recentCycles[selectedIdx];
  const previousCycle = recentCycles[selectedIdx + 1];

  // Compute aggregate for a cycle
  const computeAggregate = (cycleIdx: number) => {
    const cycle = recentCycles[cycleIdx];
    if (!cycle) return { totalSpent: 0, totalIncome: 0, categoryBreakdown: {} as Record<string, number>, txnCount: 0 };
    const txns = transactions.filter(
      (t) => t.date >= cycle.startDate && t.date <= cycle.endDate && !SKIP_CATS.has(t.category) && t.payment_type !== "Self Transfer"
    );
    let totalSpent = 0, totalIncome = 0;
    const categoryBreakdown: Record<string, number> = {};
    txns.forEach((t) => {
      if (t.category === "Income" || t.amount > 0) {
        totalIncome += Math.abs(t.amount);
      } else {
        totalSpent += Math.abs(t.amount);
        categoryBreakdown[t.category] = (categoryBreakdown[t.category] || 0) + Math.abs(t.amount);
      }
    });
    return { totalSpent, totalIncome, categoryBreakdown, txnCount: txns.length };
  };

  const currentAgg = useMemo(() => computeAggregate(selectedIdx), [selectedIdx, transactions, recentCycles]);
  const previousAgg = useMemo(() => computeAggregate(selectedIdx + 1), [selectedIdx, transactions, recentCycles]);

  const savingsRate = currentAgg.totalIncome > 0
    ? ((currentAgg.totalIncome - currentAgg.totalSpent) / currentAgg.totalIncome) * 100
    : 0;

  // Category breakdown sorted
  const categoryData = useMemo(
    () =>
      Object.entries(currentAgg.categoryBreakdown)
        .map(([name, value]) => ({ name, value: Math.round(value) }))
        .sort((a, b) => b.value - a.value),
    [currentAgg]
  );

  // Top 5 largest expenses
  const topExpenses = useMemo(() => {
    return transactions
      .filter(
        (t) =>
          t.date >= selectedCycle.startDate &&
          t.date <= selectedCycle.endDate &&
          t.amount < 0 &&
          !SKIP_CATS.has(t.category) &&
          t.payment_type !== "Self Transfer"
      )
      .sort((a, b) => a.amount - b.amount)
      .slice(0, 5);
  }, [transactions, selectedCycle]);

  // Insights
  const insights = useMemo(() => {
    const agg = { totalSpent: currentAgg.totalSpent, totalIncome: currentAgg.totalIncome, categoryBreakdown: currentAgg.categoryBreakdown };
    const prevAgg = previousAgg.totalIncome > 0 ? { totalSpent: previousAgg.totalSpent, totalIncome: previousAgg.totalIncome, categoryBreakdown: previousAgg.categoryBreakdown } : null;
    return [
      ...generateInsightsFromAggregates(agg, [], accounts, savingsRate),
      ...generateCycleComparisonInsights(agg, prevAgg),
    ];
  }, [currentAgg, previousAgg, accounts, savingsRate]);

  return (
    <div className="space-y-6">
      {/* Header with export */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold">Monthly Review</h1>
        <ExportBar elementId="monthly-report" filename={`monthly-${selectedCycle.cycleKey}`} title="Monthly Report" />
      </div>

      <div id="monthly-report" className="space-y-6">
      {/* Cycle Selector */}
      <div className="flex gap-2 flex-wrap">
        {recentCycles.map((c, idx) => (
          <button
            key={c.cycleKey}
            onClick={() => setSelectedIdx(idx)}
            className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors ${
              idx === selectedIdx ? "bg-brand text-white" : "bg-muted text-muted-foreground hover:bg-muted/80"
            }`}
          >
            {c.label.split(" ")[0].slice(0, 3)} {c.label.split(" ")[1]?.slice(2)}
          </button>
        ))}
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <StatCard title="Income" value={currentAgg.totalIncome} icon={TrendingUp} color="primary" delay={0} />
        <StatCard title="Expenses" value={currentAgg.totalSpent} icon={TrendingDown} color="danger" delay={0.1} />
        <StatCard title="Saved" value={Math.max(0, currentAgg.totalIncome - currentAgg.totalSpent)} icon={PiggyBank} color="accent" delay={0.15} />
        <StatCard title="Transactions" value={currentAgg.txnCount} prefix="" icon={Wallet} delay={0.2} />
      </div>

      {/* Savings Rate Ring */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-2xl border border-border p-5 flex items-center gap-6"
        style={{ background: isDark ? "#111827" : "#ffffff" }}
      >
        <div className="relative w-20 h-20 shrink-0">
          <svg className="w-full h-full -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="32" fill="none" stroke={isDark ? "#1f2937" : "#e5e7eb"} strokeWidth="8" />
            <circle
              cx="40" cy="40" r="32" fill="none"
              stroke={savingsRate >= 20 ? "#10b981" : savingsRate >= 10 ? "#f59e0b" : "#ef4444"}
              strokeWidth="8" strokeLinecap="round"
              strokeDasharray={`${(Math.min(100, Math.max(0, savingsRate)) / 100) * 201} 201`}
            />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-lg font-bold text-foreground">{savingsRate.toFixed(0)}%</span>
          </div>
        </div>
        <div>
          <h3 className="text-sm font-bold text-foreground">Savings Rate</h3>
          <p className="text-xs text-muted-foreground mt-1">
            {savingsRate >= 20 ? "Great! You're saving well above the recommended 20%." :
             savingsRate >= 10 ? "Decent, but try to push above 20% for better financial health." :
             "Your savings rate is low. Look for areas to cut back."}
          </p>
        </div>
      </motion.div>

      {/* Category Breakdown */}
      {categoryData.length > 0 && (
        <ChartCard title="Spending by Category" subtitle={selectedCycle.label}>
          <ResponsiveContainer width="100%" height={Math.max(180, categoryData.length * 28)}>
            <BarChart data={categoryData.slice(0, 10)} layout="vertical" margin={{ left: 80 }}>
              <XAxis type="number" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
              <YAxis type="category" dataKey="name" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} width={75} />
              <Tooltip contentStyle={{ background: isDark ? "#1f2937" : "#fff", border: "none", borderRadius: 12 }} formatter={(v) => [fmt(Number(v)), ""]} />
              <Bar dataKey="value" radius={[0, 4, 4, 0]}>
                {categoryData.slice(0, 10).map((_, idx) => (
                  <Cell key={idx} fill={idx === 0 ? "#ef4444" : idx < 3 ? "#f59e0b" : "#1abf94"} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      )}

      {/* Top 5 Expenses */}
      {topExpenses.length > 0 && (
        <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
          <h3 className="text-sm font-bold text-foreground">Top 5 Expenses</h3>
          <div className="space-y-2">
            {topExpenses.map((t, idx) => (
              <div key={idx} className="flex items-center justify-between py-1.5 border-b border-border last:border-0">
                <div className="flex items-center gap-3">
                  <span className="text-xs font-bold text-muted-foreground w-5">{idx + 1}</span>
                  <div>
                    <p className="text-sm text-foreground">{t.notes || t.category}</p>
                    <p className="text-[11px] text-muted-foreground">
                      {new Date(t.date + "T00:00:00").toLocaleDateString("en-IN", { day: "numeric", month: "short" })} ┬╖ {t.category}
                    </p>
                  </div>
                </div>
                <span className="text-sm font-semibold text-foreground">{fmt(Math.abs(t.amount))}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Insights */}
      {insights.length > 0 && (
        <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
          <div className="flex items-center gap-2 mb-2">
            <Lightbulb className="w-4 h-4 text-brand" />
            <h3 className="text-sm font-bold text-foreground">Cycle Insights</h3>
          </div>
          <div className="space-y-2">
            {insights.map((insight, idx) => (
              <motion.div
                key={idx}
                initial={{ opacity: 0, x: -8 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: idx * 0.08 }}
                className={`rounded-xl p-3 text-sm ${
                  insight.type === "success" ? "bg-emerald-500/10 text-emerald-700 dark:text-emerald-400" :
                  insight.type === "danger" ? "bg-red-500/10 text-red-700 dark:text-red-400" :
                  insight.type === "warning" ? "bg-amber-500/10 text-amber-700 dark:text-amber-400" :
                  "bg-blue-500/10 text-blue-700 dark:text-blue-400"
                }`}
              >
                <p className="font-medium">{insight.title}</p>
                <p className="text-xs mt-0.5 opacity-80">{insight.message}</p>
              </motion.div>
            ))}
          </div>
        </div>
      )}
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo, useRef, useCallback } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useTheme } from "@/providers/ThemeProvider";
import { useAuth } from "@/providers/AuthProvider";
import { useData } from "@/providers/DataProvider";
import { accountsAPI, profileAPI, categoriesAPI, importAPI } from "@/services/api";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Button, Input, Separator } from "@/components/ui";
import ConfirmDialog from "@/components/ConfirmDialog";
import {
  Sun, Moon, Monitor, Calendar, Plus, Pencil, Trash2, Download, LogOut,
  User, Settings2, Palette, Upload, AlertTriangle, IndianRupee, DollarSign, Euro,
} from "lucide-react";
import toast from "react-hot-toast";
import { motion } from "framer-motion";

const TABS = [
  { key: "profile", label: "Profile", icon: User },
  { key: "financial", label: "Financial", icon: Settings2 },
  { key: "categories", label: "Categories", icon: Palette },
  { key: "data", label: "Data", icon: Download },
  { key: "danger", label: "Danger Zone", icon: AlertTriangle },
] as const;

type Tab = (typeof TABS)[number]["key"];

const CURRENCIES = [
  { code: "INR", symbol: "Γé╣", label: "Indian Rupee", icon: IndianRupee },
  { code: "USD", symbol: "$", label: "US Dollar", icon: DollarSign },
  { code: "EUR", symbol: "Γé¼", label: "Euro", icon: Euro },
];

export default function SettingsPage() {
  const [tab, setTab] = useState<Tab>("profile");

  return (
    <div className="max-w-4xl space-y-5">
      <h1 className="text-2xl font-bold text-foreground">Settings</h1>

      {/* Tab bar */}
      <div className="flex gap-1 p-1 rounded-xl bg-muted/50 overflow-x-auto">
        {TABS.map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            className={cn(
              "flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all",
              tab === key
                ? "bg-background text-foreground shadow-sm"
                : "text-muted-foreground hover:text-foreground"
            )}
          >
            <Icon className="w-3.5 h-3.5" />
            {label}
          </button>
        ))}
      </div>

      {/* Tab content */}
      <motion.div
        key={tab}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.15 }}
      >
        {tab === "profile" && <ProfileTab />}
        {tab === "financial" && <FinancialTab />}
        {tab === "categories" && <CategoriesTab />}
        {tab === "data" && <DataTab />}
        {tab === "danger" && <DangerTab />}
      </motion.div>
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Profile Tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function ProfileTab() {
  const { theme, setTheme } = useTheme();
  const { user } = useAuth();
  const [name, setName] = useState(user?.displayName || "");
  const [saving, setSaving] = useState(false);

  const displayName = user?.displayName || user?.email?.split("@")[0] || "User";
  const initials = displayName.split(" ").map((n: string) => n[0]).join("").toUpperCase().slice(0, 2);

  const handleSaveName = async () => {
    if (!name.trim()) return;
    setSaving(true);
    try {
      await profileAPI.update({ displayName: name.trim() });
      toast.success("Name updated");
    } catch { toast.error("Failed to update name"); }
    finally { setSaving(false); }
  };

  return (
    <div className="space-y-5">
      <Card>
        <CardContent className="p-5 space-y-4">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-full bg-gradient-to-br from-brand to-accent flex items-center justify-center text-white font-bold text-lg">{initials}</div>
            <div className="flex-1">
              <p className="text-sm text-muted-foreground mb-1">Display Name</p>
              <div className="flex gap-2">
                <Input value={name} onChange={(e) => setName(e.target.value)} className="max-w-xs" placeholder="Your name" />
                <Button size="sm" onClick={handleSaveName} disabled={saving || name.trim() === displayName}>
                  {saving ? "Saving..." : "Save"}
                </Button>
              </div>
            </div>
          </div>
          <Separator />
          <div>
            <p className="text-sm text-muted-foreground">Email</p>
            <p className="text-sm font-medium text-foreground">{user?.email}</p>
          </div>
        </CardContent>
      </Card>

      {/* Theme */}
      <Card>
        <CardHeader><CardTitle>Appearance</CardTitle></CardHeader>
        <CardContent className="flex gap-2 flex-wrap">
          {([
            { key: "light", icon: Sun, label: "Light" },
            { key: "dark", icon: Moon, label: "Dark" },
            { key: "system", icon: Monitor, label: "System" },
          ] as const).map(({ key, icon: Icon, label }) => (
            <button
              key={key}
              onClick={() => setTheme(key)}
              className={cn(
                "flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium border transition-all",
                theme === key
                  ? "border-brand bg-brand/5 text-brand ring-2 ring-brand/20"
                  : "border-border text-foreground hover:bg-muted/50"
              )}
            >
              <Icon className="w-4 h-4" /> {label}
            </button>
          ))}
        </CardContent>
      </Card>

      {/* Sign Out */}
      <SignOutButton />
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Financial Tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function FinancialTab() {
  const { cycleStartDay, monthlySalary, currency } = useData();
  const [cycleDay, setCycleDay] = useState(cycleStartDay || 25);
  const [salary, setSalary] = useState(String(monthlySalary || ""));
  const [selectedCurrency, setSelectedCurrency] = useState(currency || "INR");
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    const day = parseInt(String(cycleDay), 10);
    if (isNaN(day) || day < 1 || day > 28) { toast.error("Cycle day must be 1-28"); return; }
    setSaving(true);
    try {
      await profileAPI.update({
        cycleStartDay: day,
        monthlySalary: Number(salary) || 0,
        currency: selectedCurrency,
      });
      toast.success("Financial settings saved");
    } catch { toast.error("Failed to save"); }
    finally { setSaving(false); }
  };

  return (
    <div className="space-y-5">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2"><Calendar className="w-4 h-4 text-brand" /> Financial Cycle</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <p className="text-sm font-medium text-foreground mb-1">Cycle Start Day</p>
            <p className="text-xs text-muted-foreground mb-2">Your monthly financial cycle starts on this day (1ΓÇô28)</p>
            <Input type="number" min={1} max={28} value={cycleDay} onChange={(e) => setCycleDay(parseInt(e.target.value))} className="w-24" />
          </div>
          <Separator />
          <div>
            <p className="text-sm font-medium text-foreground mb-1">Monthly Salary</p>
            <p className="text-xs text-muted-foreground mb-2">Used to calculate savings rate and budget recommendations</p>
            <div className="relative w-48">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">Γé╣</span>
              <Input type="number" value={salary} onChange={(e) => setSalary(e.target.value)} className="pl-7" placeholder="50000" />
            </div>
          </div>
          <Separator />
          <div>
            <p className="text-sm font-medium text-foreground mb-1">Currency</p>
            <p className="text-xs text-muted-foreground mb-2">Display currency for amounts throughout the app</p>
            <div className="flex gap-2 flex-wrap">
              {CURRENCIES.map(({ code, symbol, label, icon: Icon }) => (
                <button
                  key={code}
                  onClick={() => setSelectedCurrency(code)}
                  className={cn(
                    "flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium border transition-all",
                    selectedCurrency === code
                      ? "border-brand bg-brand/5 text-brand ring-2 ring-brand/20"
                      : "border-border text-foreground hover:bg-muted/50"
                  )}
                >
                  <Icon className="w-4 h-4" /> {symbol} {label}
                </button>
              ))}
            </div>
          </div>
          <Button onClick={handleSave} disabled={saving} className="mt-2">
            {saving ? "Saving..." : "Save Financial Settings"}
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Categories Tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function CategoriesTab() {
  const { categories } = useData();
  const queryClient = useQueryClient();
  const [newName, setNewName] = useState("");
  const [newColor, setNewColor] = useState("#6366f1");
  const [confirmState, setConfirmState] = useState<{ open: boolean; id?: string; name?: string }>({ open: false });

  const addMutation = useMutation({
    mutationFn: (data: { name: string; color: string }) => categoriesAPI.create(data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["categories"] }); toast.success("Category added"); setNewName(""); },
    onError: () => toast.error("Failed to add category"),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => categoriesAPI.delete(id),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["categories"] }); toast.success("Category deleted"); },
    onError: () => toast.error("Failed to delete"),
  });

  const PRESET_COLORS = ["#ef4444", "#f59e0b", "#10b981", "#3b82f6", "#6366f1", "#8b5cf6", "#ec4899", "#14b8a6", "#f97316", "#64748b"];

  return (
    <div className="space-y-5">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2"><Palette className="w-4 h-4 text-brand" /> Categories</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Add new */}
          <div className="flex items-end gap-3 pb-4 border-b border-border">
            <div className="flex-1">
              <p className="text-xs text-muted-foreground mb-1">Name</p>
              <Input value={newName} onChange={(e) => setNewName(e.target.value)} placeholder="New category" className="h-9" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground mb-1">Color</p>
              <div className="flex gap-1">
                {PRESET_COLORS.map((c) => (
                  <button
                    key={c}
                    onClick={() => setNewColor(c)}
                    className={cn("w-6 h-6 rounded-full border-2 transition-transform", newColor === c ? "border-foreground scale-125" : "border-transparent")}
                    style={{ background: c }}
                  />
                ))}
              </div>
            </div>
            <Button
              size="sm"
              onClick={() => { if (newName.trim()) addMutation.mutate({ name: newName.trim(), color: newColor }); }}
              disabled={!newName.trim()}
              className="gap-1"
            >
              <Plus className="w-3.5 h-3.5" /> Add
            </Button>
          </div>

          {/* List */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 max-h-[400px] overflow-y-auto">
            {categories.map((cat) => (
              <div key={cat.id} className="flex items-center justify-between p-2.5 rounded-xl bg-muted/50">
                <div className="flex items-center gap-2.5">
                  <span className="w-3.5 h-3.5 rounded-full shrink-0" style={{ background: cat.color }} />
                  <span className="text-sm font-medium text-foreground">{cat.name}</span>
                </div>
                <button
                  onClick={() => setConfirmState({ open: true, id: cat.id, name: cat.name })}
                  className="p-1.5 rounded-lg hover:bg-danger/10 text-muted-foreground hover:text-danger transition-colors"
                >
                  <Trash2 className="w-3.5 h-3.5" />
                </button>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      <ConfirmDialog
        open={confirmState.open}
        title={`Delete "${confirmState.name}"?`}
        message="Transactions using this category will keep their label but won't be grouped."
        confirmColor="danger"
        onConfirm={() => { if (confirmState.id) deleteMutation.mutate(confirmState.id); setConfirmState({ open: false }); }}
        onCancel={() => setConfirmState({ open: false })}
      />
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Data Tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
type ImportStep = "upload" | "map" | "preview" | "done";
const REQUIRED_FIELDS = ["date", "amount", "category"] as const;
const OPTIONAL_FIELDS = ["notes", "payment_type", "type", "account"] as const;
const ALL_FIELDS = [...REQUIRED_FIELDS, ...OPTIONAL_FIELDS, "skip"] as const;
type MappableField = (typeof ALL_FIELDS)[number];

function DataTab() {
  const { transactions, accounts, categories } = useData();
  const fileRef = useRef<HTMLInputElement>(null);
  const [uploading, setUploading] = useState(false);
  const [dragOver, setDragOver] = useState(false);

  // CSV Import state
  const [step, setStep] = useState<ImportStep>("upload");
  const [parsedHeaders, setParsedHeaders] = useState<string[]>([]);
  const [parsedRows, setParsedRows] = useState<string[][]>([]);
  const [columnMap, setColumnMap] = useState<Record<number, MappableField>>({});
  const [importResult, setImportResult] = useState<{ success: number; duplicates: number; errors: number } | null>(null);

  const handleExportCSV = () => {
    if (!transactions.length) { toast.error("No transactions to export"); return; }
    const headers = ["Date", "Amount", "Type", "Category", "Notes", "Payment Type"];
    const rows = transactions.map((t) => [t.date, t.amount, t.type, `"${(t.category || "").replace(/"/g, '""')}"`, `"${(t.notes || t.description || "").replace(/"/g, '""')}"`, t.payment_type || ""].join(","));
    const csv = [headers.join(","), ...rows].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `wealthflow_export_${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("Exported!");
  };

  const parseCSV = (text: string): { headers: string[]; rows: string[][] } => {
    const lines = text.split(/\r?\n/).filter((l) => l.trim());
    if (lines.length < 2) return { headers: [], rows: [] };
    const parse = (line: string) => {
      const result: string[] = [];
      let current = "";
      let inQuotes = false;
      for (const char of line) {
        if (char === '"') { inQuotes = !inQuotes; continue; }
        if (char === "," && !inQuotes) { result.push(current.trim()); current = ""; continue; }
        current += char;
      }
      result.push(current.trim());
      return result;
    };
    return { headers: parse(lines[0]), rows: lines.slice(1).map(parse) };
  };

  const handleFileSelect = useCallback(async (file: File) => {
    const validTypes = ["text/csv", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", "application/vnd.ms-excel"];
    if (!validTypes.includes(file.type) && !file.name.match(/\.(xlsx|xls|csv)$/i)) {
      toast.error("Please upload an Excel or CSV file");
      return;
    }

    // For CSV, parse client-side for mapping
    if (file.name.endsWith(".csv") || file.type === "text/csv") {
      const text = await file.text();
      const { headers, rows } = parseCSV(text);
      if (headers.length === 0) { toast.error("Empty or invalid CSV"); return; }
      setParsedHeaders(headers);
      setParsedRows(rows);

      // Auto-detect column mapping
      const autoMap: Record<number, MappableField> = {};
      headers.forEach((h, i) => {
        const lower = h.toLowerCase().replace(/[^a-z]/g, "");
        if (lower.includes("date") || lower === "time") autoMap[i] = "date";
        else if (lower.includes("amount") || lower.includes("value") || lower.includes("debit") || lower.includes("credit")) autoMap[i] = "amount";
        else if (lower.includes("category") || lower.includes("cat")) autoMap[i] = "category";
        else if (lower.includes("note") || lower.includes("description") || lower.includes("narration") || lower.includes("remarks") || lower.includes("particular")) autoMap[i] = "notes";
        else if (lower.includes("payment") || lower.includes("mode") || lower.includes("method")) autoMap[i] = "payment_type";
        else if (lower.includes("type")) autoMap[i] = "type";
        else if (lower.includes("account")) autoMap[i] = "account";
        else autoMap[i] = "skip";
      });
      setColumnMap(autoMap);
      setStep("map");
    } else {
      // Excel: direct upload (server handles parsing)
      setUploading(true);
      try {
        const formData = new FormData();
        formData.append("file", file);
        const res = await importAPI.uploadExcel(formData);
        toast.success(`Imported ${res.count || 0} transactions`);
      } catch (err) {
        toast.error(err instanceof Error ? err.message : "Import failed");
      } finally {
        setUploading(false);
      }
    }
  }, []);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) handleFileSelect(file);
  };

  const canProceedToPreview = useMemo(() => {
    const mapped = Object.values(columnMap);
    return mapped.includes("date") && mapped.includes("amount");
  }, [columnMap]);

  const previewRows = useMemo(() => {
    if (step !== "preview") return [];
    return parsedRows.slice(0, 10).map((row) => {
      const record: Record<string, string> = {};
      Object.entries(columnMap).forEach(([idx, field]) => {
        if (field !== "skip") record[field] = row[parseInt(idx)] || "";
      });
      return record;
    });
  }, [step, parsedRows, columnMap]);

  const handleImport = async () => {
    setUploading(true);
    const existingDates = new Set(transactions.map((t) => `${t.date}_${t.amount}_${t.category}`));
    let success = 0, duplicates = 0, errors = 0;

    const batch: Record<string, unknown>[] = [];
    for (const row of parsedRows) {
      const record: Record<string, string> = {};
      Object.entries(columnMap).forEach(([idx, field]) => {
        if (field !== "skip") record[field] = row[parseInt(idx)] || "";
      });

      // Validate & transform
      const date = record.date;
      const amount = parseFloat(record.amount?.replace(/[^0-9.\-]/g, "") || "0");
      if (!date || isNaN(amount) || amount === 0) { errors++; continue; }

      // Normalize date to YYYY-MM-DD
      let normalizedDate = date;
      const dateFormats = [
        /^(\d{4})-(\d{2})-(\d{2})/, // YYYY-MM-DD
        /^(\d{2})\/(\d{2})\/(\d{4})/, // DD/MM/YYYY
        /^(\d{2})-(\d{2})-(\d{4})/, // DD-MM-YYYY
      ];
      if (dateFormats[1].test(date)) {
        const [, d, m, y] = date.match(dateFormats[1])!;
        normalizedDate = `${y}-${m}-${d}`;
      } else if (dateFormats[2].test(date)) {
        const [, d, m, y] = date.match(dateFormats[2])!;
        normalizedDate = `${y}-${m}-${d}`;
      }

      const category = record.category || "Other";
      const key = `${normalizedDate}_${amount}_${category}`;
      if (existingDates.has(key)) { duplicates++; continue; }
      existingDates.add(key);

      batch.push({
        date: normalizedDate,
        amount,
        category,
        notes: record.notes || "",
        payment_type: record.payment_type || "UPI",
        type: amount > 0 ? "income" : "expense",
        account_id: accounts[0]?.id || null,
      });
      success++;
    }

    try {
      // Upload in batches of 50
      for (let i = 0; i < batch.length; i += 50) {
        const chunk = batch.slice(i, i + 50);
        await importAPI.uploadBatch(chunk);
      }
      setImportResult({ success, duplicates, errors });
      setStep("done");
      toast.success(`Imported ${success} transactions`);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Import failed");
    } finally {
      setUploading(false);
    }
  };

  const resetImport = () => {
    setStep("upload");
    setParsedHeaders([]);
    setParsedRows([]);
    setColumnMap({});
    setImportResult(null);
  };

  return (
    <div className="space-y-5">
      {/* Import */}
      <Card>
        <CardHeader><CardTitle className="flex items-center gap-2"><Upload className="w-4 h-4 text-brand" /> Import Data</CardTitle></CardHeader>
        <CardContent>
          {step === "upload" && (
            <>
              <div
                onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                onDragLeave={() => setDragOver(false)}
                onDrop={handleDrop}
                onClick={() => fileRef.current?.click()}
                className={cn(
                  "border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors",
                  dragOver ? "border-brand bg-brand/5" : "border-border hover:border-brand/50"
                )}
              >
                <Upload className="w-8 h-8 mx-auto mb-3 text-muted-foreground" />
                <p className="text-sm font-medium text-foreground">
                  {uploading ? "Uploading..." : "Drop CSV/Excel file here or click to browse"}
                </p>
                <p className="text-xs text-muted-foreground mt-1">CSV files get column mapping. Excel files are imported directly.</p>
              </div>
              <input
                ref={fileRef}
                type="file"
                accept=".xlsx,.xls,.csv"
                className="hidden"
                onChange={(e) => { const f = e.target.files?.[0]; if (f) handleFileSelect(f); e.target.value = ""; }}
              />
            </>
          )}

          {step === "map" && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-foreground">Map Columns</p>
                  <p className="text-xs text-muted-foreground">{parsedRows.length} rows detected. Map columns to fields (date & amount required).</p>
                </div>
                <button onClick={resetImport} className="text-xs text-muted-foreground hover:text-foreground">Cancel</button>
              </div>
              <div className="space-y-2">
                {parsedHeaders.map((header, idx) => (
                  <div key={idx} className="flex items-center gap-3 p-2 rounded-lg bg-muted/50">
                    <span className="text-xs font-medium text-foreground w-32 truncate" title={header}>{header}</span>
                    <span className="text-xs text-muted-foreground truncate w-24" title={parsedRows[0]?.[idx]}>e.g. {parsedRows[0]?.[idx]?.slice(0, 20)}</span>
                    <select
                      value={columnMap[idx] || "skip"}
                      onChange={(e) => setColumnMap({ ...columnMap, [idx]: e.target.value as MappableField })}
                      className="ml-auto h-8 px-2 rounded-md border border-input bg-card text-xs text-foreground"
                    >
                      <option value="skip">Skip</option>
                      <option value="date">Date *</option>
                      <option value="amount">Amount *</option>
                      <option value="category">Category</option>
                      <option value="notes">Notes / Description</option>
                      <option value="payment_type">Payment Method</option>
                      <option value="type">Type (income/expense)</option>
                      <option value="account">Account</option>
                    </select>
                  </div>
                ))}
              </div>
              <div className="flex gap-3">
                <Button variant="secondary" onClick={resetImport}>Back</Button>
                <Button onClick={() => setStep("preview")} disabled={!canProceedToPreview}>Preview Import</Button>
              </div>
            </div>
          )}

          {step === "preview" && (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-foreground">Preview (first 10 rows)</p>
                  <p className="text-xs text-muted-foreground">{parsedRows.length} total rows will be imported</p>
                </div>
              </div>
              <div className="overflow-x-auto rounded-lg border border-border">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="bg-muted/50 border-b border-border">
                      {Object.keys(previewRows[0] || {}).map((key) => (
                        <th key={key} className="px-3 py-2 text-left font-medium text-muted-foreground">{key}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {previewRows.map((row, i) => (
                      <tr key={i} className="border-b border-border/50">
                        {Object.values(row).map((val, j) => (
                          <td key={j} className="px-3 py-1.5 text-foreground">{val?.slice(0, 30)}</td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <div className="flex gap-3">
                <Button variant="secondary" onClick={() => setStep("map")}>Back</Button>
                <Button onClick={handleImport} disabled={uploading}>
                  {uploading ? "Importing..." : `Import ${parsedRows.length} Rows`}
                </Button>
              </div>
            </div>
          )}

          {step === "done" && importResult && (
            <div className="space-y-3 text-center py-4">
              <div className="w-12 h-12 rounded-full bg-success/10 mx-auto flex items-center justify-center">
                <Download className="w-6 h-6 text-success" />
              </div>
              <p className="text-sm font-semibold text-foreground">Import Complete</p>
              <div className="flex justify-center gap-6 text-xs">
                <span className="text-success font-medium">{importResult.success} imported</span>
                <span className="text-warning font-medium">{importResult.duplicates} duplicates skipped</span>
                {importResult.errors > 0 && <span className="text-danger font-medium">{importResult.errors} errors</span>}
              </div>
              <Button variant="secondary" onClick={resetImport} className="mt-2">Import Another File</Button>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Export */}
      <Card>
        <CardHeader><CardTitle className="flex items-center gap-2"><Download className="w-4 h-4 text-brand" /> Export Data</CardTitle></CardHeader>
        <CardContent>
          <Button variant="outline" onClick={handleExportCSV} className="gap-2">
            <Download className="w-4 h-4" /> Export All Transactions (CSV)
          </Button>
          <p className="text-xs text-muted-foreground mt-2">{transactions.length} transactions will be exported</p>
        </CardContent>
      </Card>
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Danger Zone Tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function DangerTab() {
  const { signOut } = useAuth();
  const [deleteConfirm, setDeleteConfirm] = useState("");
  const [deleting, setDeleting] = useState(false);
  const [showDelete, setShowDelete] = useState(false);

  const handleDeleteAccount = async () => {
    if (deleteConfirm !== "DELETE") { toast.error("Type DELETE to confirm"); return; }
    setDeleting(true);
    try {
      await profileAPI.delete();
      toast.success("Account deleted");
      await signOut();
    } catch {
      toast.error("Failed to delete account");
    } finally {
      setDeleting(false);
    }
  };

  return (
    <div className="space-y-5">
      <Card className="border-danger/30">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-danger">
            <AlertTriangle className="w-4 h-4" /> Danger Zone
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <p className="text-sm text-muted-foreground">
            These actions are irreversible. Proceed with extreme caution.
          </p>

          <Separator />

          <div className="space-y-3">
            <div>
              <p className="text-sm font-medium text-foreground">Delete Account</p>
              <p className="text-xs text-muted-foreground">
                Permanently deletes your account, all transactions, accounts, categories, investments, goals, and all other data.
              </p>
            </div>

            {!showDelete ? (
              <Button variant="outline" onClick={() => setShowDelete(true)} className="text-danger border-danger/30 hover:bg-danger/5">
                Delete My Account
              </Button>
            ) : (
              <div className="space-y-3 p-4 rounded-xl border border-danger/30 bg-danger/5">
                <p className="text-sm font-medium text-danger">Type DELETE to confirm:</p>
                <Input
                  value={deleteConfirm}
                  onChange={(e) => setDeleteConfirm(e.target.value)}
                  placeholder="DELETE"
                  className="max-w-xs border-danger/30"
                />
                <div className="flex gap-2">
                  <Button
                    onClick={handleDeleteAccount}
                    disabled={deleteConfirm !== "DELETE" || deleting}
                    className="bg-danger text-white hover:bg-danger/90"
                  >
                    {deleting ? "Deleting..." : "Permanently Delete Account"}
                  </Button>
                  <Button variant="ghost" onClick={() => { setShowDelete(false); setDeleteConfirm(""); }}>
                    Cancel
                  </Button>
                </div>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Sign Out */}
      <SignOutButton />
    </div>
  );
}

/* ΓöÇΓöÇΓöÇ Shared Sign Out ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function SignOutButton() {
  const { signOut } = useAuth();
  return (
    <Button variant="outline" onClick={signOut} className="w-full gap-2 text-danger border-danger/20 hover:bg-danger/5 hover:text-danger">
      <LogOut className="w-4 h-4" /> Sign Out
    </Button>
  );
}

