"use client";

import { useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { detectRecurringTransactions } from "@/utils/calculations";
import { generateInsightsFromAggregates } from "@/utils/insights";
import { fmt } from "@/utils/format";
import { useTheme } from "@/providers/ThemeProvider";
import ChartCard from "@/components/ChartCard";
import StatCard from "@/components/StatCard";
import { BarChart3, Zap, CreditCard, Lightbulb, TrendingDown } from "lucide-react";
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip,
} from "recharts";
import { motion } from "framer-motion";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment", "Income"]);
const DAY_NAMES = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
const PIE_COLORS = ["#1abf94", "#3b82f6", "#f59e0b", "#8b5cf6", "#ef4444", "#6b7280", "#ec4899"];

export default function AnalyticsPage() {
  const { transactions, cycleStartDay, accounts } = useData();
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const currentCycle = useMemo(
    () => getRecentFinancialMonths(1, new Date(), cycleStartDay)[0],
    [cycleStartDay]
  );

  const prevCycle = useMemo(
    () => getRecentFinancialMonths(2, new Date(), cycleStartDay)[1],
    [cycleStartDay]
  );

  const cycleTxns = useMemo(
    () =>
      transactions.filter(
        (t) =>
          t.date >= currentCycle.startDate &&
          t.date <= currentCycle.endDate &&
          t.amount < 0 &&
          !SKIP_CATS.has(t.category) &&
          t.payment_type !== "Self Transfer"
      ),
    [transactions, currentCycle]
  );

  const prevCycleTxns = useMemo(
    () =>
      transactions.filter(
        (t) =>
          t.date >= prevCycle.startDate &&
          t.date <= prevCycle.endDate &&
          t.amount < 0 &&
          !SKIP_CATS.has(t.category) &&
          t.payment_type !== "Self Transfer"
      ),
    [transactions, prevCycle]
  );

  // Cycle-over-cycle comparison by category
  const cycleComparison = useMemo(() => {
    const currentCats: Record<string, number> = {};
    const prevCats: Record<string, number> = {};
    cycleTxns.forEach((t) => { currentCats[t.category] = (currentCats[t.category] || 0) + Math.abs(t.amount); });
    prevCycleTxns.forEach((t) => { prevCats[t.category] = (prevCats[t.category] || 0) + Math.abs(t.amount); });
    const allCats = [...new Set([...Object.keys(currentCats), ...Object.keys(prevCats)])];
    return allCats
      .map((cat) => ({
        category: cat,
        current: Math.round(currentCats[cat] || 0),
        previous: Math.round(prevCats[cat] || 0),
        change: currentCats[cat] && prevCats[cat]
          ? Math.round(((currentCats[cat] - prevCats[cat]) / prevCats[cat]) * 100)
          : null,
      }))
      .sort((a, b) => b.current - a.current)
      .slice(0, 8);
  }, [cycleTxns, prevCycleTxns]);

  // Spending velocity (daily cumulative)
  const velocityData = useMemo(() => {
    const dayMap: Record<string, number> = {};
    cycleTxns.forEach((t) => {
      dayMap[t.date] = (dayMap[t.date] || 0) + Math.abs(t.amount);
    });
    const sorted = Object.entries(dayMap).sort(([a], [b]) => a.localeCompare(b));
    let cumulative = 0;
    return sorted.map(([date, amt]) => {
      cumulative += amt;
      return {
        date: new Date(date + "T00:00:00").toLocaleDateString("en-IN", { day: "2-digit", month: "short" }),
        daily: Math.round(amt),
        cumulative: Math.round(cumulative),
      };
    });
  }, [cycleTxns]);

  // Payment method breakdown
  const paymentBreakdown = useMemo(() => {
    const map: Record<string, number> = {};
    cycleTxns.forEach((t) => {
      const method = t.payment_type || "Other";
      map[method] = (map[method] || 0) + Math.abs(t.amount);
    });
    return Object.entries(map)
      .map(([name, value]) => ({ name, value: Math.round(value) }))
      .sort((a, b) => b.value - a.value);
  }, [cycleTxns]);

  // Day-of-week pattern
  const dayOfWeekData = useMemo(() => {
    const totals = [0, 0, 0, 0, 0, 0, 0];
    const counts = [0, 0, 0, 0, 0, 0, 0];
    cycleTxns.forEach((t) => {
      const day = new Date(t.date + "T00:00:00").getDay();
      totals[day] += Math.abs(t.amount);
      counts[day]++;
    });
    return DAY_NAMES.map((name, idx) => ({
      day: name,
      total: Math.round(totals[idx]),
      avg: counts[idx] > 0 ? Math.round(totals[idx] / counts[idx]) : 0,
      count: counts[idx],
    }));
  }, [cycleTxns]);

  // Top merchants/notes
  const topMerchants = useMemo(() => {
    const map: Record<string, { total: number; count: number }> = {};
    cycleTxns.forEach((t) => {
      const key = (t.notes || t.category || "Unknown").trim();
      if (!map[key]) map[key] = { total: 0, count: 0 };
      map[key].total += Math.abs(t.amount);
      map[key].count++;
    });
    return Object.entries(map)
      .map(([name, data]) => ({ name, ...data }))
      .sort((a, b) => b.total - a.total)
      .slice(0, 8);
  }, [cycleTxns]);

  // Recurring transactions
  const recurring = useMemo(
    () => detectRecurringTransactions(transactions as Parameters<typeof detectRecurringTransactions>[0]),
    [transactions]
  );

  // Summary stats
  const stats = useMemo(() => {
    const totalSpend = cycleTxns.reduce((s, t) => s + Math.abs(t.amount), 0);
    const txnCount = cycleTxns.length;
    const daysActive = new Set(cycleTxns.map((t) => t.date)).size;
    const dailyAvg = daysActive > 0 ? totalSpend / daysActive : 0;
    const avgTxnSize = txnCount > 0 ? totalSpend / txnCount : 0;
    return { totalSpend, txnCount, dailyAvg, avgTxnSize, daysActive };
  }, [cycleTxns]);

  // Insights
  const insights = useMemo(() => {
    const catBreakdown: Record<string, number> = {};
    cycleTxns.forEach((t) => {
      catBreakdown[t.category] = (catBreakdown[t.category] || 0) + Math.abs(t.amount);
    });
    const aggregate = { totalSpent: stats.totalSpend, totalIncome: 0, categoryBreakdown: catBreakdown };
    return generateInsightsFromAggregates(aggregate, [], accounts);
  }, [cycleTxns, stats, accounts]);

  return (
    <div className="space-y-6">
      {/* Summary Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <StatCard title="Total Spend" value={stats.totalSpend} icon={TrendingDown} color="danger" delay={0} />
        <StatCard title="Transactions" value={stats.txnCount} prefix="" icon={BarChart3} delay={0.1} />
        <StatCard title="Daily Average" value={stats.dailyAvg} icon={Zap} color="warning" delay={0.15} />
        <StatCard title="Avg Txn Size" value={stats.avgTxnSize} icon={CreditCard} color="accent" delay={0.2} />
      </div>

      {/* Spending Velocity */}
      {velocityData.length > 0 && (
        <ChartCard title="Spending Velocity" subtitle="Daily cumulative spend this cycle">
          <ResponsiveContainer width="100%" height={200}>
            <AreaChart data={velocityData}>
              <CartesianGrid strokeDasharray="3 3" stroke={isDark ? "#1f2937" : "#e5e7eb"} />
              <XAxis dataKey="date" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} />
              <YAxis tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
              <Tooltip contentStyle={{ background: isDark ? "#1f2937" : "#fff", border: "none", borderRadius: 12 }} formatter={(v) => [fmt(Number(v)), ""]} />
              <Area type="monotone" dataKey="cumulative" stroke="#1abf94" fill="#1abf94" fillOpacity={0.2} />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Payment Method Breakdown */}
        {paymentBreakdown.length > 0 && (
          <ChartCard title="Payment Methods" subtitle="How you pay">
            <ResponsiveContainer width="100%" height={180}>
              <PieChart>
                <Pie data={paymentBreakdown} cx="50%" cy="50%" innerRadius={40} outerRadius={70} dataKey="value" label={({ name }) => name}>
                  {paymentBreakdown.map((_, idx) => (
                    <Cell key={idx} fill={PIE_COLORS[idx % PIE_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(v) => fmt(Number(v))} />
              </PieChart>
            </ResponsiveContainer>
          </ChartCard>
        )}

        {/* Day of Week Pattern */}
        <ChartCard title="Day-of-Week Pattern" subtitle="Which days you spend most">
          <ResponsiveContainer width="100%" height={180}>
            <BarChart data={dayOfWeekData}>
              <XAxis dataKey="day" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} />
              <YAxis tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
              <Tooltip contentStyle={{ background: isDark ? "#1f2937" : "#fff", border: "none", borderRadius: 12 }} formatter={(v) => [fmt(Number(v)), ""]} />
              <Bar dataKey="total" fill="#3b82f6" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Top Merchants */}
      {topMerchants.length > 0 && (
        <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
          <h3 className="text-sm font-bold text-foreground">Top Spending Destinations</h3>
          <div className="space-y-2">
            {topMerchants.map((m, idx) => (
              <div key={m.name} className="flex items-center justify-between py-1.5">
                <div className="flex items-center gap-2">
                  <span className="text-xs font-bold text-muted-foreground w-5">{idx + 1}</span>
                  <span className="text-sm text-foreground truncate max-w-[200px]">{m.name}</span>
                  <span className="text-[11px] text-muted-foreground">({m.count}x)</span>
                </div>
                <span className="text-sm font-semibold text-foreground">{fmt(m.total)}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Recurring Patterns */}
      {recurring.length > 0 && (
        <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
          <h3 className="text-sm font-bold text-foreground">Detected Recurring Expenses</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {recurring.slice(0, 6).map((r) => (
              <div key={r.key} className="rounded-xl bg-muted p-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium text-foreground truncate max-w-[150px]">{r.description}</span>
                  <span className="text-xs px-2 py-0.5 rounded-full bg-brand/10 text-brand font-medium">{r.frequency}</span>
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  ~{fmt(r.avgAmount)} ┬╖ {r.occurrences} times ┬╖ Next: {new Date(r.nextExpectedDate + "T00:00:00").toLocaleDateString("en-IN", { day: "numeric", month: "short" })}
                </p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Cycle-over-Cycle Comparison */}
      {cycleComparison.length > 0 && (
        <ChartCard title="Cycle-over-Cycle" subtitle={`Current vs Previous (${prevCycle.label})`}>
          <ResponsiveContainer width="100%" height={220}>
            <BarChart data={cycleComparison} layout="vertical" margin={{ left: 60 }}>
              <CartesianGrid strokeDasharray="3 3" stroke={isDark ? "#1f2937" : "#e5e7eb"} />
              <XAxis type="number" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} tickFormatter={(v) => `Γé╣${(v / 1000).toFixed(0)}k`} />
              <YAxis type="category" dataKey="category" tick={{ fontSize: 11, fill: isDark ? "#9ca3af" : "#6b7280" }} width={60} />
              <Tooltip contentStyle={{ background: isDark ? "#1f2937" : "#fff", border: "none", borderRadius: 12 }} formatter={(v) => fmt(Number(v))} />
              <Bar dataKey="current" fill="#0080ff" radius={[0, 4, 4, 0]} name="Current" />
              <Bar dataKey="previous" fill="#6b7280" radius={[0, 4, 4, 0]} name="Previous" opacity={0.5} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      )}

      {/* Insights */}
      {insights.length > 0 && (
        <div className="rounded-2xl border border-border p-5 space-y-3" style={{ background: isDark ? "#111827" : "#ffffff" }}>
          <div className="flex items-center gap-2 mb-2">
            <Lightbulb className="w-4 h-4 text-brand" />
            <h3 className="text-sm font-bold text-foreground">Insights</h3>
          </div>
          <div className="space-y-2">
            {insights.map((insight, idx) => (
              <motion.div
                key={idx}
                initial={{ opacity: 0, x: -8 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: idx * 0.1 }}
                className={`rounded-xl p-3 text-sm ${
                  insight.type === "success" ? "bg-emerald-500/10 text-emerald-700 dark:text-emerald-400" :
                  insight.type === "danger" ? "bg-red-500/10 text-red-700 dark:text-red-400" :
                  insight.type === "warning" ? "bg-amber-500/10 text-amber-700 dark:text-amber-400" :
                  "bg-blue-500/10 text-blue-700 dark:text-blue-400"
                }`}
              >
                <p className="font-medium">{insight.title}</p>
                <p className="text-xs mt-0.5 opacity-80">{insight.message}</p>
              </motion.div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { motion } from "framer-motion";
import { useData } from "@/providers/DataProvider";
import { useAuth } from "@/providers/AuthProvider";
import { db } from "@/lib/firebase";
import { collection, onSnapshot } from "firebase/firestore";
import { budgetSnapshotsAPI, profileAPI } from "@/services/api";
import { getFinancialCycle, getCycleDayInfo, getRecentFinancialMonths } from "@/utils/financialMonth";
import { fmt } from "@/utils/format";
import { cn } from "@/lib/utils";
import { Card, CardContent, CardHeader, CardTitle, Badge, Button, Progress, Input } from "@/components/ui";
import {
  ChevronLeft, ChevronRight, Pencil, Check, X, Plus,
  AlertTriangle, ShieldCheck, TrendingUp, Wallet, Target,
} from "lucide-react";
import toast from "react-hot-toast";
import { SkeletonCard } from "@/components/SkeletonLoader";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment", "Income"]);
const SKIP_PAYMENTS = new Set(["Credit Card", "Self Transfer", "Transfer"]);

const getBudgetStatus = (pct: number) => {
  if (pct > 100) return { label: "Over Budget", variant: "danger" as const };
  if (pct >= 80) return { label: "At Risk", variant: "warning" as const };
  return { label: "On Track", variant: "success" as const };
};

export default function BudgetsPage() {
  const { user } = useAuth();
  const { categories, transactions, cycleStartDay, dataReady } = useData();

  const [cycleIdx, setCycleIdx] = useState(0);
  const [budgetLimits, setBudgetLimits] = useState<Record<string, number>>({});
  const [editingCatId, setEditingCatId] = useState<string | null>(null);

  if (!dataReady) {
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4"><SkeletonCard lines={2} /><SkeletonCard lines={2} /><SkeletonCard lines={2} /></div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4"><SkeletonCard lines={4} /><SkeletonCard lines={4} /><SkeletonCard lines={4} /><SkeletonCard lines={4} /></div>
      </div>
    );
  }
  const [editValue, setEditValue] = useState("");
  const [salary, setSalary] = useState(0);
  const [editingSalary, setEditingSalary] = useState(false);
  const [salaryInput, setSalaryInput] = useState("");
  const [showAddBudget, setShowAddBudget] = useState(false);
  const [addCatName, setAddCatName] = useState("");
  const [addCatLimit, setAddCatLimit] = useState("");

  const recentCycles = useMemo(() => getRecentFinancialMonths(8, new Date(), cycleStartDay), [cycleStartDay]);
  const currentCycle = recentCycles[cycleIdx];
  const cycleInfo = useMemo(() => getCycleDayInfo(new Date(), cycleStartDay), [cycleStartDay]);
  const isCurrentCycle = cycleIdx === 0;

  // Load salary from profile
  useEffect(() => {
    if (!user) return;
    profileAPI.get().then((p) => { if (p?.monthlySalary) setSalary(p.monthlySalary); }).catch(() => {});
  }, [user]);

  // Load budget snapshots for the cycle
  useEffect(() => {
    if (!user || !currentCycle) return;
    budgetSnapshotsAPI.get(currentCycle.cycleKey).then((data) => {
      if (data && typeof data === "object") setBudgetLimits(data as Record<string, number>);
      else setBudgetLimits({});
    }).catch(() => setBudgetLimits({}));
  }, [user, currentCycle]);

  // Compute spending per category for the cycle
  const categorySpending = useMemo(() => {
    if (!currentCycle) return {};
    const map: Record<string, number> = {};
    transactions.forEach((t) => {
      if (t.date < currentCycle.startDate || t.date > currentCycle.endDate) return;
      if (t.amount >= 0) return;
      if (SKIP_CATS.has(t.category) || SKIP_PAYMENTS.has(t.payment_type || "")) return;
      map[t.category] = (map[t.category] || 0) + Math.abs(t.amount);
    });
    return map;
  }, [transactions, currentCycle]);

  const totalSpent = Object.values(categorySpending).reduce((s, v) => s + v, 0);
  const totalBudget = Object.values(budgetLimits).reduce((s, v) => s + v, 0);
  const overallPct = totalBudget > 0 ? (totalSpent / totalBudget) * 100 : 0;

  // Build budget card data
  const budgetCards = useMemo(() => {
    const allCats = new Set([...Object.keys(budgetLimits), ...Object.keys(categorySpending)]);
    return Array.from(allCats)
      .filter((cat) => !SKIP_CATS.has(cat))
      .map((cat) => {
        const limit = budgetLimits[cat] || 0;
        const spent = categorySpending[cat] || 0;
        const pct = limit > 0 ? (spent / limit) * 100 : (spent > 0 ? 100 : 0);
        const remaining = Math.max(0, limit - spent);
        const daysLeft = cycleInfo.totalDays - cycleInfo.daysElapsed;
        const dailyAllowance = daysLeft > 0 && limit > 0 ? remaining / daysLeft : 0;
        const projected = cycleInfo.daysElapsed > 3 && isCurrentCycle
          ? (spent / cycleInfo.daysElapsed) * cycleInfo.totalDays
          : undefined;
        const color = categories.find((c) => c.name === cat)?.color || "#94a3b8";
        return { cat, limit, spent, pct, remaining, dailyAllowance, projected, color };
      })
      .sort((a, b) => b.spent - a.spent);
  }, [budgetLimits, categorySpending, categories, cycleInfo, isCurrentCycle]);

  // Unbudgeted categories (have spending but no limit set)
  const unbudgeted = budgetCards.filter((b) => b.limit === 0 && b.spent > 0);

  // Categories available to add budget (not already budgeted, not skipped)
  const availableCategories = useMemo(() => {
    return categories
      .filter((c) => !SKIP_CATS.has(c.name) && !(budgetLimits[c.name] > 0))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [categories, budgetLimits]);

  const handleAddBudget = async () => {
    if (!addCatName) { toast.error("Please select a category"); return; }
    const val = parseFloat(addCatLimit);
    if (isNaN(val) || val <= 0) { toast.error("Enter a valid amount"); return; }
    try {
      await budgetSnapshotsAPI.set(currentCycle.cycleKey, addCatName, val);
      setBudgetLimits((prev) => ({ ...prev, [addCatName]: val }));
      toast.success(`Budget set for ${addCatName}`);
      setShowAddBudget(false);
      setAddCatName("");
      setAddCatLimit("");
    } catch { toast.error("Failed to save budget"); }
  };

  const handleSaveBudget = async (catId: string) => {
    const val = parseFloat(editValue);
    if (isNaN(val) || val < 0) { toast.error("Invalid amount"); return; }
    try {
      await budgetSnapshotsAPI.set(currentCycle.cycleKey, catId, val);
      setBudgetLimits((prev) => ({ ...prev, [catId]: val }));
      toast.success("Budget saved");
    } catch { toast.error("Failed to save"); }
    setEditingCatId(null);
  };

  const handleSaveSalary = async () => {
    const val = parseFloat(salaryInput);
    if (isNaN(val) || val <= 0) { toast.error("Invalid salary"); return; }
    try {
      await profileAPI.update({ monthlySalary: val });
      setSalary(val);
      setEditingSalary(false);
      toast.success("Salary updated");
    } catch { toast.error("Failed to update"); }
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <p className="text-sm text-muted-foreground">{currentCycle?.label}</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm" onClick={() => setShowAddBudget(true)}>
            <Plus className="w-4 h-4 mr-1.5" /> Add Budget
          </Button>
          <Button variant="outline" size="icon-sm" onClick={() => setCycleIdx(Math.min(cycleIdx + 1, recentCycles.length - 1))} disabled={cycleIdx >= recentCycles.length - 1}>
            <ChevronLeft className="w-4 h-4" />
          </Button>
          <span className="text-sm font-medium text-foreground min-w-[100px] text-center">{currentCycle?.label}</span>
          <Button variant="outline" size="icon-sm" onClick={() => setCycleIdx(Math.max(cycleIdx - 1, 0))} disabled={cycleIdx === 0}>
            <ChevronRight className="w-4 h-4" />
          </Button>
        </div>
      </div>

      {/* Overview Strip */}
      <div className="grid grid-cols-1 sm:grid-cols-4 gap-3">
        {/* Salary */}
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between mb-1">
              <span className="text-[11px] font-medium text-muted-foreground uppercase">Monthly Salary</span>
              {!editingSalary ? (
                <button onClick={() => { setEditingSalary(true); setSalaryInput(String(salary)); }} className="text-muted-foreground hover:text-foreground">
                  <Pencil className="w-3.5 h-3.5" />
                </button>
              ) : (
                <div className="flex gap-1">
                  <button onClick={handleSaveSalary} className="text-success"><Check className="w-3.5 h-3.5" /></button>
                  <button onClick={() => setEditingSalary(false)} className="text-danger"><X className="w-3.5 h-3.5" /></button>
                </div>
              )}
            </div>
            {editingSalary ? (
              <Input value={salaryInput} onChange={(e) => setSalaryInput(e.target.value)} className="h-7 text-sm" autoFocus />
            ) : (
              <p className="text-lg font-bold text-foreground">{fmt(salary)}</p>
            )}
          </CardContent>
        </Card>

        {/* Total Budget */}
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Total Budget</span>
            <p className="text-lg font-bold text-foreground mt-1">{fmt(totalBudget)}</p>
            <p className="text-[10px] text-muted-foreground">{salary > 0 ? `${((totalBudget / salary) * 100).toFixed(0)}% of salary` : ""}</p>
          </CardContent>
        </Card>

        {/* Total Spent */}
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Total Spent</span>
            <p className={cn("text-lg font-bold mt-1", overallPct > 100 ? "text-danger" : "text-foreground")}>{fmt(totalSpent)}</p>
            <Progress value={Math.min(overallPct, 100)} className="mt-2 h-1.5" indicatorClassName={overallPct > 100 ? "bg-danger" : overallPct > 80 ? "bg-warning" : "bg-success"} />
          </CardContent>
        </Card>

        {/* Overall Status */}
        <Card>
          <CardContent className="p-4">
            <span className="text-[11px] font-medium text-muted-foreground uppercase">Status</span>
            <div className="flex items-center gap-2 mt-2">
              {overallPct > 100 ? <AlertTriangle className="w-5 h-5 text-danger" /> : <ShieldCheck className="w-5 h-5 text-success" />}
              <div>
                <p className="text-sm font-bold text-foreground">{overallPct.toFixed(0)}% used</p>
                <p className="text-[10px] text-muted-foreground">{fmt(Math.max(0, totalBudget - totalSpent))} remaining</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Budget Cards Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {budgetCards.filter((b) => b.limit > 0).length === 0 && unbudgeted.length === 0 ? (
          <Card className="col-span-full">
            <CardContent className="flex flex-col items-center justify-center py-12">
              <Target className="w-10 h-10 text-muted-foreground mb-3" />
              <p className="text-sm font-semibold text-foreground mb-1">No budgets set yet</p>
              <p className="text-xs text-muted-foreground mb-4 text-center max-w-xs">
                Set monthly spending limits for your categories to stay on track.
              </p>
              <Button size="sm" onClick={() => setShowAddBudget(true)}>
                <Plus className="w-4 h-4 mr-1.5" /> Add Your First Budget
              </Button>
            </CardContent>
          </Card>
        ) : (
          budgetCards.filter((b) => b.limit > 0).map((b) => {
          const status = getBudgetStatus(b.pct);
          const isEditing = editingCatId === b.cat;
          return (
            <Card key={b.cat} className="group">
              <CardContent className="p-4">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full" style={{ backgroundColor: b.color }} />
                    <span className="text-sm font-semibold text-foreground">{b.cat}</span>
                  </div>
                  <Badge variant={status.variant}>{status.label}</Badge>
                </div>

                {/* Progress */}
                <div className="mb-3">
                  <div className="flex justify-between text-[11px] text-muted-foreground mb-1">
                    <span>{fmt(b.spent)} spent</span>
                    <span>{fmt(b.limit)} limit</span>
                  </div>
                  <Progress
                    value={Math.min(b.pct, 100)}
                    className="h-2"
                    indicatorClassName={b.pct > 100 ? "bg-danger" : b.pct > 80 ? "bg-warning" : "bg-success"}
                  />
                  <p className="text-right text-[10px] text-muted-foreground mt-0.5">{b.pct.toFixed(0)}%</p>
                </div>

                {/* Stats row */}
                <div className="grid grid-cols-2 gap-2 text-[11px]">
                  <div className="rounded-md bg-muted/50 p-2">
                    <span className="text-muted-foreground">Remaining</span>
                    <p className="font-semibold text-foreground">{fmt(b.remaining)}</p>
                  </div>
                  <div className="rounded-md bg-muted/50 p-2">
                    <span className="text-muted-foreground">Daily Left</span>
                    <p className="font-semibold text-foreground">{fmt(b.dailyAllowance)}</p>
                  </div>
                </div>

                {/* Projected (only current cycle, after day 3) */}
                {b.projected !== undefined && (
                  <div className="mt-2 flex items-center gap-1.5 text-[11px]">
                    <TrendingUp className="w-3 h-3 text-muted-foreground" />
                    <span className="text-muted-foreground">Projected: </span>
                    <span className={cn("font-semibold", b.projected > b.limit ? "text-danger" : "text-success")}>
                      {fmt(b.projected)}
                    </span>
                  </div>
                )}

                {/* Edit limit */}
                <div className="mt-3 pt-3 border-t border-border">
                  {isEditing ? (
                    <div className="flex items-center gap-1.5">
                      <Input
                        value={editValue}
                        onChange={(e) => setEditValue(e.target.value)}
                        className="h-7 text-sm flex-1"
                        placeholder="New limit"
                        autoFocus
                        onKeyDown={(e) => { if (e.key === "Enter") handleSaveBudget(b.cat); if (e.key === "Escape") setEditingCatId(null); }}
                      />
                      <button onClick={() => handleSaveBudget(b.cat)} className="text-success"><Check className="w-4 h-4" /></button>
                      <button onClick={() => setEditingCatId(null)} className="text-danger"><X className="w-4 h-4" /></button>
                    </div>
                  ) : (
                    <button
                      onClick={() => { setEditingCatId(b.cat); setEditValue(String(b.limit)); }}
                      className="text-[11px] text-brand hover:underline flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Pencil className="w-3 h-3" /> Edit limit
                    </button>
                  )}
                </div>
              </CardContent>
            </Card>
          );
        })
        )}
      </div>

      {/* Unbudgeted Spending */}
      {unbudgeted.length > 0 && (
        <Card className="border-warning/30">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-warning">
              <AlertTriangle className="w-4 h-4" /> Unbudgeted Spending
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-xs text-muted-foreground mb-3">These categories have spending but no budget set.</p>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
              {unbudgeted.map((b) => (
                <div key={b.cat} className="flex items-center justify-between p-2.5 rounded-lg bg-muted/50">
                  <div className="flex items-center gap-2">
                    <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: b.color }} />
                    <span className="text-sm font-medium text-foreground">{b.cat}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-semibold text-foreground">{fmt(b.spent)}</span>
                    <button
                      onClick={() => { setEditingCatId(b.cat); setEditValue(""); }}
                      className="text-brand hover:text-brand/80"
                    >
                      <Plus className="w-3.5 h-3.5" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Edit modal for unbudgeted items */}
      {editingCatId && !budgetCards.find((b) => b.cat === editingCatId && b.limit > 0) && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={() => setEditingCatId(null)}>
          <Card className="w-[320px]" onClick={(e) => e.stopPropagation()}>
            <CardHeader>
              <CardTitle>Set Budget for {editingCatId}</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <Input
                value={editValue}
                onChange={(e) => setEditValue(e.target.value)}
                placeholder="Monthly limit (Γé╣)"
                autoFocus
                onKeyDown={(e) => { if (e.key === "Enter") handleSaveBudget(editingCatId); }}
              />
              <div className="flex gap-2 justify-end">
                <Button variant="outline" size="sm" onClick={() => setEditingCatId(null)}>Cancel</Button>
                <Button size="sm" onClick={() => handleSaveBudget(editingCatId)}>Save</Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Add Budget Modal */}
      {showAddBudget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={() => setShowAddBudget(false)}>
          <Card className="w-[380px]" onClick={(e) => e.stopPropagation()}>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Target className="w-5 h-5 text-brand" /> Add Category Budget
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {availableCategories.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">All categories already have budgets set.</p>
              ) : (
                <>
                  <div>
                    <label className="block text-[13px] font-medium text-muted-foreground mb-1.5">Category</label>
                    <select
                      value={addCatName}
                      onChange={(e) => setAddCatName(e.target.value)}
                      className="w-full h-9 px-3 rounded-lg border border-input bg-card text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-ring/40"
                    >
                      <option value="">ΓÇö Select category ΓÇö</option>
                      {availableCategories.map((c) => (
                        <option key={c.id || c.name} value={c.name}>{c.name}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-[13px] font-medium text-muted-foreground mb-1.5">Monthly Limit (Γé╣)</label>
                    <Input
                      type="number"
                      min="1"
                      step="100"
                      value={addCatLimit}
                      onChange={(e) => setAddCatLimit(e.target.value)}
                      placeholder="e.g. 5000"
                      onKeyDown={(e) => { if (e.key === "Enter") handleAddBudget(); }}
                      autoFocus={!!addCatName}
                    />
                  </div>
                  {salary > 0 && addCatLimit && parseFloat(addCatLimit) > 0 && (
                    <p className="text-[11px] text-muted-foreground">
                      {((parseFloat(addCatLimit) / salary) * 100).toFixed(1)}% of monthly salary
                    </p>
                  )}
                </>
              )}
              <div className="flex gap-2 justify-end pt-1">
                <Button variant="outline" size="sm" onClick={() => { setShowAddBudget(false); setAddCatName(""); setAddCatLimit(""); }}>Cancel</Button>
                {availableCategories.length > 0 && (
                  <Button size="sm" onClick={handleAddBudget} disabled={!addCatName || !addCatLimit}>Set Budget</Button>
                )}
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useData } from "@/providers/DataProvider";
import { getRecentFinancialMonths } from "@/utils/financialMonth";
import { fmt } from "@/utils/format";
import { useTheme } from "@/providers/ThemeProvider";
import ChartCard from "@/components/ChartCard";
import { Tags, TrendingUp, TrendingDown, ChevronRight, ArrowUpRight, ArrowDownRight } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Tooltip } from "recharts";
import { motion, AnimatePresence } from "framer-motion";

const SKIP_CATS = new Set(["Transfer", "Credit Card Payment", "Income"]);

export default function CategoriesPage() {
  const { transactions, cycleStartDay } = useData();
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  const recentCycles = useMemo(
    () => getRecentFinancialMonths(6, new Date(), cycleStartDay),
    [cycleStartDay]
  );

  const currentCycle = recentCycles[0];
  const previousCycle = recentCycles[1];

  // Per-cycle category breakdown
  const cycleBreakdowns = useMemo(() => {
    return recentCycles.map((cycle) => {
      const txns = transactions.filter(
        (t) =>
          t.date >= cycle.startDate &&
          t.date <= cycle.endDate &&
          t.amount < 0 &&
          !SKIP_CATS.has(t.category) &&
          t.payment_type !== "Self Transfer"
      );
      const breakdown: Record<string, number> = {};
      txns.forEach((t) => {
        breakdown[t.category] = (breakdown[t.category] || 0) + Math.abs(t.amount);
      });
      return { cycle, breakdown };
    });
  }, [recentCycles, transactions]);

  // Current cycle category data sorted by amount
  const currentBreakdown = cycleBreakdowns[0]?.breakdown || {};
  const previousBreakdown = cycleBreakdowns[1]?.breakdown || {};

  const categories = useMemo(() => {
    const allCats = new Set([...Object.keys(currentBreakdown), ...Object.keys(previousBreakdown)]);
    return Array.from(allCats)
      .map((cat) => {
        const current = currentBreakdown[cat] || 0;
        const previous = previousBreakdown[cat] || 0;
        const change = previous > 0 ? ((current - previous) / previous) * 100 : current > 0 ? 100 : 0;
        return { category: cat, current, previous, change, delta: current - previous };
      })
      .sort((a, b) => b.current - a.current);
  }, [currentBreakdown, previousBreakdown]);

  const totalCurrent = categories.reduce((s, c) => s + c.current, 0);

  // Trend data for selected category
  const trendData = useMemo(() => {
    if (!selectedCategory) return [];
    return cycleBreakdowns
      .map((cb) => ({
        label: cb.cycle.label.split(" ")[0].slice(0, 3),
        amount: Math.round(cb.breakdown[selectedCategory] || 0),
      }))
      .reverse();
  }, [selectedCategory, cycleBreakdowns]);

  // Transactions for selected category in current cycle
  const categoryTxns = useMemo(() => {
    if (!selectedCategory) return [];
    return transactions
      .filter(
        (t) =>
          t.date >= currentCycle.startDate &&
          t.date <= currentCycle.endDate &&
          t.category === selectedCategory &&
          t.amount < 0 &&
          t.payment_type !== "Self Transfer"
      )
      .sort((a, b) => b.date.localeCompare(a.date))
      .slice(0, 15);
  }, [selectedCategory, transactions, currentCycle]);

  // Top growing and improving categories
  const topGrowing = useMemo(
    () => categories.filter((c) => c.change > 10 && c.delta > 200).sort((a, b) => b.delta - a.delta).slice(0, 3),
    [categories]
  );
  const topImproved = useMemo(
    () => categories.filter((c) => c.change < -10 && Math.abs(c.delta) > 200).sort((a, b) => a.delta - b.delta).slice(0, 3),
    [categories]
  );

  return (
    <div className="space-y-6">
      {/* Growth / Improvement highlights */}
      {(topGrowing.length > 0 || topImproved.length > 0) && (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {topGrowing.length > 0 && (
            <div className="rounded-2xl border border-border p-4" style={{ background: isDark ? "#111827" : "#ffffff" }}>
              <div className="flex items-center gap-2 mb-3">
                <TrendingUp className="w-4 h-4 text-red-500" />
                <h3 className="text-sm font-bold text-foreground">Spending Up</h3>
              </div>
              {topGrowing.map((c) => (
                <div key={c.category} className="flex items-center justify-between py-1.5">
                  <span className="text-sm text-foreground">{c.category}</span>
                  <span className="text-xs font-medium text-red-500">+{c.change.toFixed(0)}%</span>
                </div>
              ))}
            </div>
          )}
          {topImproved.length > 0 && (
            <div className="rounded-2xl border border-border p-4" style={{ background: isDark ? "#111827" : "#ffffff" }}>
              <div className="flex items-center gap-2 mb-3">
                <TrendingDown className="w-4 h-4 text-emerald-500" />
                <h3 className="text-sm font-bold text-foreground">Spending Down</h3>
              </div>
              {topImproved.map((c) => (
                <div key={c.category} className="flex items-center justify-between py-1.5">
                  <span className="text-sm text-foreground">{c.category}</span>
                  <span className="text-xs font-medium text-emerald-500">{c.change.toFixed(0)}%</span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Category List */}
      <div className="rounded-2xl border border-border overflow-hidden" style={{ background: isDark ? "#111827" : "#ffffff" }}>
        <div className="px-5 py-3 border-b border-border">
          <h3 className="text-sm font-bold text-foreground">Categories ΓÇö {currentCycle.label}</h3>
        </div>
        <div className="divide-y divide-border">
          {categories.map((cat) => {
            const pct = totalCurrent > 0 ? (cat.current / totalCurrent) * 100 : 0;
            const isSelected = selectedCategory === cat.category;

            return (
              <div key={cat.category}>
                <button
                  onClick={() => setSelectedCategory(isSelected ? null : cat.category)}
                  className="w-full flex items-center justify-between px-5 py-3 hover:bg-muted/50 transition-colors text-left"
                >
                  <div className="flex items-center gap-3 min-w-0">
                    <div className="w-8 h-8 rounded-lg bg-muted flex items-center justify-center shrink-0">
                      <Tags className="w-3.5 h-3.5 text-muted-foreground" />
                    </div>
                    <div className="min-w-0">
                      <p className="text-sm font-medium text-foreground truncate">{cat.category}</p>
                      <p className="text-[11px] text-muted-foreground">{pct.toFixed(1)}% of total</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <div className="text-right">
                      <p className="text-sm font-semibold text-foreground">{fmt(cat.current)}</p>
                      {cat.previous > 0 && (
                        <div className="flex items-center gap-0.5 justify-end">
                          {cat.change > 0 ? (
                            <ArrowUpRight className="w-3 h-3 text-red-500" />
                          ) : (
                            <ArrowDownRight className="w-3 h-3 text-emerald-500" />
                          )}
                          <span className={`text-[11px] font-medium ${cat.change > 0 ? "text-red-500" : "text-emerald-500"}`}>
                            {Math.abs(cat.change).toFixed(0)}%
                          </span>
                        </div>
                      )}
                    </div>
                    <ChevronRight className={`w-4 h-4 text-muted-foreground transition-transform ${isSelected ? "rotate-90" : ""}`} />
                  </div>
                </button>

                {/* Expanded: Trend + Transactions */}
                <AnimatePresence>
                  {isSelected && (
                    <motion.div
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: "auto", opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      className="overflow-hidden border-t border-border bg-muted/30"
                    >
                      <div className="p-4 space-y-4">
                        {/* 6-cycle trend */}
                        {trendData.length > 0 && (
                          <div>
                            <p className="text-xs font-medium text-muted-foreground mb-2">6-Cycle Trend</p>
                            <ResponsiveContainer width="100%" height={100}>
                              <BarChart data={trendData}>
                                <XAxis dataKey="label" tick={{ fontSize: 10, fill: isDark ? "#9ca3af" : "#6b7280" }} />
                                <Tooltip contentStyle={{ background: isDark ? "#1f2937" : "#fff", border: "none", borderRadius: 8 }} formatter={(v) => [fmt(Number(v)), ""]} />
                                <Bar dataKey="amount" fill="#1abf94" radius={[3, 3, 0, 0]} />
                              </BarChart>
                            </ResponsiveContainer>
                          </div>
                        )}
                        {/* Recent transactions */}
                        {categoryTxns.length > 0 && (
                          <div>
                            <p className="text-xs font-medium text-muted-foreground mb-2">Recent Transactions</p>
                            <div className="space-y-1.5 max-h-[200px] overflow-y-auto">
                              {categoryTxns.map((t, idx) => (
                                <div key={idx} className="flex items-center justify-between text-xs py-1">
                                  <div className="flex items-center gap-2 min-w-0">
                                    <span className="text-muted-foreground">
                                      {new Date(t.date + "T00:00:00").toLocaleDateString("en-IN", { day: "numeric", month: "short" })}
                                    </span>
                                    <span className="text-foreground truncate max-w-[150px]">{t.notes || t.category}</span>
                                  </div>
                                  <span className="font-medium text-foreground">{fmt(Math.abs(t.amount))}</span>
                                </div>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { adminAuth } from "@/lib/firebase-admin";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { token } = body;

    if (!token) {
      return NextResponse.json({ error: "Token required" }, { status: 400 });
    }

    // Verify the Firebase ID token
    const decoded = await adminAuth.verifyIdToken(token);
    if (!decoded) {
      return NextResponse.json({ error: "Invalid token" }, { status: 401 });
    }

    const response = NextResponse.json({ status: "success", uid: decoded.uid });
    response.cookies.set("__session", token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: "lax",
      maxAge: 60 * 60 * 24 * 7, // 7 days
      path: "/",
    });

    return response;
  } catch (error) {
    return NextResponse.json({ error: "Authentication failed" }, { status: 401 });
  }
}

export async function DELETE() {
  const response = NextResponse.json({ status: "success" });
  response.cookies.set("__session", "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
  return response;
}

import { NextRequest, NextResponse } from "next/server";
import { verifyAuth } from "@/lib/auth";
import { adminDb } from "@/lib/firebase-admin";
import { FieldValue } from "firebase-admin/firestore";

export async function POST(req: NextRequest) {
  const auth = await verifyAuth(req);
  if (auth instanceof NextResponse) return auth;
  const { uid } = auth;

  try {
    const body = await req.json();
    const { transactions } = body;

    if (!Array.isArray(transactions) || transactions.length === 0) {
      return NextResponse.json({ error: "No transactions provided" }, { status: 400 });
    }

    if (transactions.length > 100) {
      return NextResponse.json({ error: "Max 100 transactions per batch" }, { status: 400 });
    }

    const batch = adminDb.batch();
    const txnCollection = adminDb.collection(`users/${uid}/transactions`);
    let count = 0;

    for (const txn of transactions) {
      const { date, amount, category, notes, payment_type, type, account_id } = txn;
      if (!date || amount === undefined) continue;

      const docRef = txnCollection.doc();
      batch.set(docRef, {
        date: String(date),
        amount: Number(amount),
        category: String(category || "Other"),
        notes: String(notes || ""),
        payment_type: String(payment_type || "UPI"),
        type: Number(amount) > 0 ? "income" : "expense",
        account_id: account_id || null,
        createdAt: FieldValue.serverTimestamp(),
        source: "csv_import",
      });
      count++;
    }

    await batch.commit();
    return NextResponse.json({ success: true, count });
  } catch (error) {
    console.error("Batch import error:", error);
    return NextResponse.json({ error: "Failed to import transactions" }, { status: 500 });
  }
}

"use client";

import { useMemo } from "react";

interface BalanceSparklineProps {
  data: number[];
  width?: number;
  height?: number;
  color?: string;
  showDot?: boolean;
}

export default function BalanceSparkline({
  data,
  width = 80,
  height = 28,
  color = "var(--color-brand)",
  showDot = true,
}: BalanceSparklineProps) {
  const pathD = useMemo(() => {
    if (data.length < 2) return "";
    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const padY = 3;
    const usableH = height - padY * 2;
    const stepX = width / (data.length - 1);

    return data
      .map((v, i) => {
        const x = i * stepX;
        const y = padY + usableH - ((v - min) / range) * usableH;
        return `${i === 0 ? "M" : "L"}${x.toFixed(1)},${y.toFixed(1)}`;
      })
      .join(" ");
  }, [data, width, height]);

  if (data.length < 2) return null;

  const lastX = width;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const padY = 3;
  const usableH = height - padY * 2;
  const lastY = padY + usableH - ((data[data.length - 1] - min) / range) * usableH;
  const trend = data[data.length - 1] >= data[0];

  return (
    <svg width={width} height={height} className="flex-shrink-0">
      <path
        d={pathD}
        fill="none"
        stroke={trend ? "var(--color-success)" : "var(--color-danger)"}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      {showDot && (
        <circle
          cx={lastX - (width / (data.length - 1)) * 0 }
          cy={lastY}
          r={2.5}
          fill={trend ? "var(--color-success)" : "var(--color-danger)"}
        />
      )}
    </svg>
  );
}

