"use client";

import { useState, useRef, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useData } from "@/providers/DataProvider";
import { notificationsAPI } from "@/services/api";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";
import {
  Bell,
  Check,
  CheckCheck,
  Trash2,
  CalendarClock,
  TrendingUp,
  AlertTriangle,
  Repeat,
  X,
} from "lucide-react";

const ICON_MAP: Record<string, typeof Bell> = {
  bill_due: CalendarClock,
  budget_warning: AlertTriangle,
  budget_exceeded: AlertTriangle,
  recurring_executed: Repeat,
  insight: TrendingUp,
};

const COLOR_MAP: Record<string, string> = {
  bill_due: "text-warning",
  budget_warning: "text-warning",
  budget_exceeded: "text-danger",
  recurring_executed: "text-brand",
  insight: "text-success",
};

function timeAgo(dateStr: string): string {
  const now = Date.now();
  const then = new Date(dateStr).getTime();
  const diff = Math.floor((now - then) / 1000);

  if (diff < 60) return "Just now";
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  if (diff < 604800) return `${Math.floor(diff / 86400)}d ago`;
  return new Date(dateStr).toLocaleDateString("en-IN", { day: "numeric", month: "short" });
}

export default function NotificationCenter() {
  const { notifications } = useData();
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  const unreadCount = notifications.filter((n) => !n.read).length;

  // Close on outside click
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    if (open) document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  const markAllReadMutation = useMutation({
    mutationFn: () => notificationsAPI.markAllRead(),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["notifications"] }),
  });

  const markReadMutation = useMutation({
    mutationFn: (ids: string[]) => notificationsAPI.markRead(ids),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["notifications"] }),
  });

  const clearAllMutation = useMutation({
    mutationFn: () => notificationsAPI.clearAll(),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["notifications"] }),
  });

  return (
    <div className="relative" ref={ref}>
      {/* Bell button */}
      <button
        onClick={() => setOpen(!open)}
        className="relative p-2 rounded-lg text-muted-foreground hover:bg-muted hover:text-foreground transition-colors"
        aria-label={`Notifications${unreadCount > 0 ? ` (${unreadCount} unread)` : ""}`}
      >
        <Bell className="w-5 h-5" />
        {unreadCount > 0 && (
          <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] flex items-center justify-center rounded-full bg-danger text-white text-[10px] font-bold px-1">
            {unreadCount > 9 ? "9+" : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, y: -8, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -8, scale: 0.95 }}
            transition={{ duration: 0.15 }}
            className="absolute right-0 top-full mt-2 w-80 sm:w-96 max-h-[70vh] overflow-hidden rounded-xl border border-border bg-card shadow-xl z-50 flex flex-col"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-border">
              <h3 className="text-sm font-semibold text-foreground">Notifications</h3>
              <div className="flex items-center gap-1">
                {unreadCount > 0 && (
                  <button
                    onClick={() => markAllReadMutation.mutate()}
                    className="p-1.5 rounded-md text-xs text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
                    title="Mark all read"
                  >
                    <CheckCheck className="w-4 h-4" />
                  </button>
                )}
                {notifications.length > 0 && (
                  <button
                    onClick={() => clearAllMutation.mutate()}
                    className="p-1.5 rounded-md text-xs text-muted-foreground hover:text-danger hover:bg-danger/10 transition-colors"
                    title="Clear all"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
                <button
                  onClick={() => setOpen(false)}
                  className="p-1.5 rounded-md text-muted-foreground hover:text-foreground hover:bg-muted transition-colors md:hidden"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>

            {/* List */}
            <div className="overflow-y-auto flex-1">
              {notifications.length === 0 ? (
                <div className="py-12 text-center text-muted-foreground text-sm">
                  <Bell className="w-8 h-8 mx-auto mb-2 opacity-40" />
                  No notifications yet
                </div>
              ) : (
                <div className="divide-y divide-border">
                  {notifications.map((n) => {
                    const Icon = ICON_MAP[n.type] || Bell;
                    const color = COLOR_MAP[n.type] || "text-muted-foreground";
                    return (
                      <div
                        key={n.id}
                        className={cn(
                          "flex items-start gap-3 px-4 py-3 hover:bg-muted/50 transition-colors cursor-pointer",
                          !n.read && "bg-brand/5"
                        )}
                        onClick={() => {
                          if (!n.read) markReadMutation.mutate([n.id]);
                        }}
                      >
                        <div className={cn("mt-0.5 p-1.5 rounded-lg bg-muted", color)}>
                          <Icon className="w-4 h-4" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={cn("text-sm leading-tight", !n.read ? "font-medium text-foreground" : "text-muted-foreground")}>
                            {n.title}
                          </p>
                          <p className="text-xs text-muted-foreground mt-0.5 truncate">
                            {n.message}
                          </p>
                          <p className="text-[10px] text-muted-foreground/70 mt-1">
                            {timeAgo(n.createdAt)}
                          </p>
                        </div>
                        {!n.read && (
                          <div className="w-2 h-2 rounded-full bg-brand mt-2 shrink-0" />
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { cn } from "@/lib/utils";
import { Button, Input } from "@/components/ui";
import { X, Sparkles } from "lucide-react";
import toast from "react-hot-toast";

const getLocalISODate = () => {
  const tzOffset = new Date().getTimezoneOffset() * 60000;
  return new Date(Date.now() - tzOffset).toISOString().split("T")[0];
};

const defaultForm = {
  date: getLocalISODate(),
  amount: "",
  category: "Food",
  payment_type: "Cash",
  account_id: "",
  to_account_id: "",
  notes: "",
  is_recurring: false,
  recurrence_interval: "monthly",
};

const KEYWORD_MAP = [
  { keywords: ["swiggy", "zomato", "mcdonalds", "kfc", "pizza", "burger", "food", "restaurant", "cafe", "lunch", "dinner", "breakfast"], category: "Food" },
  { keywords: ["uber", "ola", "rapido", "auto", "cab", "taxi", "metro", "bus", "train", "flight", "petrol", "fuel", "toll"], category: "Travel" },
  { keywords: ["netflix", "prime", "hotstar", "spotify", "youtube", "subscription"], category: "Subscription" },
  { keywords: ["amazon", "flipkart", "myntra", "shop", "buy", "order", "purchase", "clothes"], category: "Shopping" },
  { keywords: ["rent", "landlord", "flat", "apartment"], category: "Rent" },
  { keywords: ["electricity", "water", "bill", "wifi", "internet", "phone", "recharge"], category: "Bills" },
  { keywords: ["movie", "cinema", "concert", "party", "entertainment"], category: "Entertainment" },
  { keywords: ["salary", "income", "bonus", "cashback", "refund", "freelance"], category: "Income" },
  { keywords: ["mutual fund", "sip", "stocks", "invest", "zerodha", "groww"], category: "Investment" },
  { keywords: ["medicine", "doctor", "hospital", "health", "medical"], category: "Utilities" },
  { keywords: ["lend", "loan", "borrow"], category: "Lending" },
  { keywords: ["gift", "present", "wedding", "birthday"], category: "Gifts" },
  { keywords: ["petrol", "fuel", "pump", "gas"], category: "Petrol" },
];

interface Category { id?: string; name: string; color?: string; }
interface Account { id: string; account_name: string; balance?: number; credit_limit?: number; }
interface TransactionData {
  date: string; amount: number; category: string; payment_type: string;
  account_id?: string; to_account_id?: string; notes?: string;
  is_recurring?: boolean; recurrence_interval?: string; next_date?: string;
}

export interface QuickAddTransactionProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: TransactionData) => void;
  accounts?: Account[];
  creditCards?: Account[];
  categories?: Category[];
  initialData?: Partial<TransactionData> & { id?: string } | null;
  allowCreditCard?: boolean;
}

function suggestCategory(notes: string, categoriesAvail: Category[]): string | null {
  if (!notes || notes.trim().length < 2) return null;
  const lower = notes.toLowerCase();
  for (const entry of KEYWORD_MAP) {
    if (entry.keywords.some((kw) => lower.includes(kw))) {
      if (categoriesAvail.some((c) => c.name === entry.category)) return entry.category;
    }
  }
  return null;
}

export default function QuickAddTransaction({ isOpen, onClose, onSubmit, accounts = [], creditCards = [], categories = [], initialData = null, allowCreditCard = false }: QuickAddTransactionProps) {
  const [form, setForm] = useState(defaultForm);
  const [suggestion, setSuggestion] = useState<string | null>(null);

  useEffect(() => {
    if (initialData) {
      setForm({
        date: initialData.date || defaultForm.date,
        amount: String(Math.abs(initialData.amount || 0)) || "",
        category: initialData.category || "Food",
        payment_type: initialData.payment_type || "Cash",
        account_id: initialData.account_id || "",
        to_account_id: initialData.to_account_id || "",
        notes: initialData.notes || "",
        is_recurring: initialData.is_recurring || false,
        recurrence_interval: initialData.recurrence_interval || "monthly",
      });
    } else {
      setForm(defaultForm);
    }
    setSuggestion(null);
  }, [initialData, isOpen]);

  const handleNotesChange = (val: string) => {
    setForm((prev) => ({ ...prev, notes: val }));
    const suggested = suggestCategory(val, categories);
    if (suggested && suggested !== form.category) setSuggestion(suggested);
    else setSuggestion(null);
  };

  const handlePaymentTypeChange = (newType: string) => {
    setForm((prev) => ({
      ...prev, payment_type: newType, account_id: "", to_account_id: "",
      category: newType === "Self Transfer" ? "Transfer" : prev.category,
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const currentToday = getLocalISODate();
    if (form.date > currentToday) { toast.error("Future dates are not allowed."); return; }
    const rawAmount = parseFloat(form.amount);
    if (isNaN(rawAmount) || rawAmount <= 0) { toast.error("Amount must be positive."); return; }

    const signedAmount = form.category === "Income" ? Math.abs(rawAmount) : -Math.abs(rawAmount);
    const submitData: TransactionData = { ...form, amount: signedAmount };

    if (submitData.is_recurring) {
      const d = new Date(submitData.date);
      if (submitData.recurrence_interval === "monthly") d.setMonth(d.getMonth() + 1);
      else if (submitData.recurrence_interval === "weekly") d.setDate(d.getDate() + 7);
      else if (submitData.recurrence_interval === "yearly") d.setFullYear(d.getFullYear() + 1);
      submitData.next_date = d.toISOString().split("T")[0];
    }

    onSubmit(submitData);
    setForm(defaultForm);
    setSuggestion(null);
    onClose();
  };

  if (!isOpen) return null;

  const isEdit = !!initialData;
  const isTransfer = form.payment_type === "Self Transfer";
  const bankAccounts = accounts.filter((a) => a.credit_limit == null && !creditCards.some((c) => c.id === a.id));
  const showCreditCardSelector = !isTransfer && form.payment_type === "Credit Card" && creditCards.length > 0;
  const showAccountSelector = !isTransfer && (form.payment_type === "Debit Card" || form.payment_type === "UPI") && bankAccounts.length > 0;

  const selectClass = "w-full h-9 px-3 rounded-lg border border-input bg-card text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-ring/40 [&>option]:bg-card [&>option]:text-foreground";

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm" onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} className="w-full max-w-md mx-4 rounded-2xl bg-card border border-border shadow-2xl p-6 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-5">
          <h3 className="text-lg font-bold text-foreground">{isEdit ? "Edit Transaction" : "Quick Add Transaction"}</h3>
          <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-muted transition-colors text-muted-foreground"><X className="w-5 h-5" /></button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">Date</label>
              <Input type="date" value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} max={getLocalISODate()} required />
            </div>
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">Amount (Γé╣)</label>
              <Input type="number" step="0.01" value={form.amount} onChange={(e) => setForm({ ...form, amount: e.target.value })} placeholder="0.00" min="0.01" required />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">Category</label>
              {isTransfer ? (
                <div className="h-9 px-3 rounded-lg bg-muted text-muted-foreground text-sm flex items-center">Transfer</div>
              ) : (
                <select value={form.category} onChange={(e) => { setForm({ ...form, category: e.target.value }); setSuggestion(null); }} className={selectClass}>
                  {categories.length > 0 ? categories.map((c) => <option key={c.id || c.name} value={c.name}>{c.name}</option>) : ["Food", "Income", "Other"].map((c) => <option key={c} value={c}>{c}</option>)}
                </select>
              )}
            </div>
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">Payment Method</label>
              <select value={form.payment_type} onChange={(e) => handlePaymentTypeChange(e.target.value)} className={selectClass}>
                <option value="Cash">≡ƒÆ╡ Cash</option>
                {allowCreditCard && <option value="Credit Card">≡ƒÆ│ Credit Card</option>}
                <option value="Debit Card">≡ƒÅª Debit Card</option>
                <option value="UPI">≡ƒô▒ UPI</option>
                <option value="Self Transfer">≡ƒöä Self Transfer</option>
              </select>
            </div>
          </div>

          {showCreditCardSelector && (
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">Credit Card</label>
              <select value={form.account_id} onChange={(e) => setForm({ ...form, account_id: e.target.value })} className={selectClass} required>
                <option value="">ΓÇö Select credit card ΓÇö</option>
                {creditCards.map((c) => <option key={c.id} value={c.id}>{c.account_name}</option>)}
              </select>
            </div>
          )}

          {showAccountSelector && (
            <div>
              <label className="block text-[13px] font-medium text-muted-foreground mb-1">{form.payment_type === "UPI" ? "UPI Linked Account" : "Bank Account"}</label>
              <select value={form.account_id} onChange={(e) => setForm({ ...form, account_id: e.target.value })} className={selectClass}>
                <option value="">ΓÇö Select account ΓÇö</option>
                {bankAccounts.map((a) => <option key={a.id} value={a.id}>{a.account_name} (Γé╣{(a.balance || 0).toLocaleString("en-IN")})</option>)}
              </select>
            </div>
          )}

          {isTransfer && (
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[13px] font-medium text-muted-foreground mb-1">From Account</label>
                <select value={form.account_id} onChange={(e) => setForm({ ...form, account_id: e.target.value })} className={selectClass} required>
                  <option value="">ΓÇö Select source ΓÇö</option>
                  {bankAccounts.map((a) => <option key={a.id} value={a.id}>{a.account_name}</option>)}
                  {creditCards.map((c) => <option key={c.id} value={c.id}>{c.account_name} (CC)</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[13px] font-medium text-muted-foreground mb-1">To Account</label>
                <select value={form.to_account_id} onChange={(e) => setForm({ ...form, to_account_id: e.target.value })} className={selectClass} required>
                  <option value="">ΓÇö Select destination ΓÇö</option>
                  {bankAccounts.map((a) => <option key={a.id} value={a.id}>{a.account_name}</option>)}
                  {creditCards.map((c) => <option key={c.id} value={c.id}>{c.account_name} (CC)</option>)}
                </select>
              </div>
            </div>
          )}

          <div>
            <label className="block text-[13px] font-medium text-muted-foreground mb-1">Notes</label>
            <Input type="text" value={form.notes} onChange={(e) => handleNotesChange(e.target.value)} placeholder="Description (e.g. Swiggy order, Uber ride...)" />
            {suggestion && (
              <div className="mt-1.5 flex items-center gap-2">
                <Sparkles className="w-3 h-3 text-accent flex-shrink-0" />
                <span className="text-[11px] text-muted-foreground">Suggested:</span>
                <button type="button" onClick={() => { setForm((p) => ({ ...p, category: suggestion })); setSuggestion(null); }} className="text-[11px] font-bold px-2.5 py-0.5 rounded-full bg-accent/10 border border-accent/30 text-accent cursor-pointer hover:bg-accent/20 transition-colors">
                  Γ£¿ {suggestion}
                </button>
              </div>
            )}
          </div>

          {!isEdit && (
            <div className="p-4 rounded-xl border border-border bg-muted/30">
              <label className="flex items-center gap-3 cursor-pointer">
                <input type="checkbox" checked={form.is_recurring} onChange={(e) => setForm({ ...form, is_recurring: e.target.checked })} className="w-4 h-4 rounded accent-brand" />
                <span className="text-sm font-medium text-foreground">Recurring transaction</span>
              </label>
              {form.is_recurring && (
                <div className="mt-3">
                  <label className="block text-xs font-medium text-muted-foreground mb-1">Frequency</label>
                  <select value={form.recurrence_interval} onChange={(e) => setForm({ ...form, recurrence_interval: e.target.value })} className={selectClass}>
                    <option value="weekly">Weekly</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                  </select>
                </div>
              )}
            </div>
          )}

          <div className="flex gap-3 pt-2">
            <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancel</Button>
            <Button type="submit" className="flex-1">{isEdit ? "Save Changes" : "Add Transaction"}</Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { useTheme } from "@/providers/ThemeProvider";

const pulse = {
  animate: { opacity: [0.4, 0.8, 0.4] },
  transition: { duration: 1.5, repeat: Infinity, ease: "easeInOut" as const },
};

function SkeletonBlock({ width = "100%", height = 16, radius = 8 }: { width?: string | number; height?: number; radius?: number }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";
  return (
    <motion.div {...pulse} style={{ width, height, borderRadius: radius, background: isDark ? "#1f2937" : "#e5e7eb" }} />
  );
}

export function SkeletonCard({ lines = 3 }: { lines?: number }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";
  return (
    <div className="rounded-2xl p-5 flex flex-col gap-3" style={{ background: isDark ? "#111827" : "#ffffff", border: `1px solid ${isDark ? "#1f2937" : "#e5e7eb"}` }}>
      <SkeletonBlock width="40%" height={12} />
      <SkeletonBlock width="60%" height={26} />
      {Array.from({ length: Math.max(0, lines - 2) }).map((_, i) => (
        <SkeletonBlock key={i} width={`${60 + Math.random() * 30}%`} height={12} />
      ))}
    </div>
  );
}

export function SkeletonTable({ rows = 5, cols = 5 }: { rows?: number; cols?: number }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";
  return (
    <div className="rounded-2xl overflow-hidden" style={{ background: isDark ? "#111827" : "#ffffff", border: `1px solid ${isDark ? "#1f2937" : "#e5e7eb"}` }}>
      <div className="p-4 flex gap-4" style={{ borderBottom: `1px solid ${isDark ? "#1f2937" : "#f3f4f6"}` }}>
        {Array.from({ length: cols }).map((_, i) => (
          <SkeletonBlock key={i} width={i === 0 ? "20%" : "15%"} height={12} />
        ))}
      </div>
      {Array.from({ length: rows }).map((_, r) => (
        <div key={r} className="p-4 flex gap-4" style={{ borderBottom: `1px solid ${isDark ? "#1f2937" : "#f9fafb"}` }}>
          {Array.from({ length: cols }).map((_, c) => (
            <SkeletonBlock key={c} width={`${40 + Math.random() * 40}%`} height={14} />
          ))}
        </div>
      ))}
    </div>
  );
}

export default SkeletonBlock;

"use client";

import { memo, useRef } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { cn } from "@/lib/utils";

const FALLBACK_COLORS: Record<string, string> = {
  Food: "#ef4444", Travel: "#3b82f6", Shopping: "#14b8a6",
  Bills: "#64748b", Entertainment: "#ec4899", Investment: "#0080ff",
  Income: "#10b981", Rent: "#f59e0b", Petrol: "#f97316",
  Utilities: "#eab308", Subscription: "#06b6d4", Lending: "#84cc16",
  Gifts: "#f43f5e", Home: "#8b5cf6", Other: "#94a3b8",
};

const paymentColors: Record<string, string> = {
  Cash: "bg-success/10 text-success",
  "Credit Card": "bg-accent/10 text-accent",
  "Debit Card": "bg-info/10 text-info",
  UPI: "bg-warning/10 text-warning",
  "Self Transfer": "bg-muted text-muted-foreground",
};

const paymentIcons: Record<string, string> = {
  Cash: "≡ƒÆ╡", "Credit Card": "≡ƒÆ│", "Debit Card": "≡ƒÅº", UPI: "≡ƒô▒", "Self Transfer": "≡ƒöä",
};

interface Category { id?: string; name: string; color?: string; }
interface Account { id: string; account_name: string; type?: string; balance?: number; }
interface Transaction {
  id: string; date: string; amount: number; category: string;
  payment_type?: string; account_id?: string; notes?: string;
  is_recurring?: boolean; recurrence_interval?: string;
}

interface TransactionTableProps {
  transactions: Transaction[];
  onEdit?: (txn: Transaction) => void;
  onDelete?: (id: string) => void;
  categories?: Category[];
  accounts?: Account[];
  creditCards?: Account[];
  selectable?: boolean;
  selectedIds?: Set<string>;
  onToggleSelect?: (id: string) => void;
  onToggleSelectAll?: (txns: Transaction[]) => void;
  maxHeight?: string;
}

function resolveCatColor(categoryName: string, categories: Category[] = []): string {
  const found = categories.find((c) => c.name === categoryName);
  return found?.color || FALLBACK_COLORS[categoryName] || "#94a3b8";
}

const ROW_HEIGHT = 52;

function TransactionTable({
  transactions, onEdit, onDelete, categories = [], accounts = [], creditCards = [],
  selectable = false, selectedIds = new Set(), onToggleSelect, onToggleSelectAll,
  maxHeight = "calc(100vh - 320px)",
}: TransactionTableProps) {
  const allAccounts = [...accounts, ...creditCards];
  const parentRef = useRef<HTMLDivElement>(null);

  const virtualizer = useVirtualizer({
    count: transactions.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => ROW_HEIGHT,
    overscan: 10,
  });

  if (!transactions?.length) {
    return (
      <div className="text-center py-12 text-muted-foreground">
        <p className="text-base mb-1">No transactions yet</p>
        <p className="text-sm">Add your first transaction to get started</p>
      </div>
    );
  }

  const allSelected = transactions.length > 0 && transactions.every((t) => selectedIds.has(t.id));

  return (
    <div className="overflow-hidden rounded-lg border border-border">
      {/* Sticky header */}
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead className="bg-muted/30 sticky top-0 z-10">
            <tr className="border-b border-border text-muted-foreground">
              {selectable && (
                <th className="py-3 px-2 w-10">
                  <input type="checkbox" checked={allSelected} onChange={() => onToggleSelectAll?.(transactions)} className="w-4 h-4 rounded cursor-pointer accent-brand" />
                </th>
              )}
              <th className="text-left py-3 px-4 text-[11px] font-semibold uppercase tracking-wider w-[100px]">Date</th>
              <th className="text-left py-3 px-4 text-[11px] font-semibold uppercase tracking-wider">Category</th>
              <th className="text-left py-3 px-4 text-[11px] font-semibold uppercase tracking-wider">Payment</th>
              <th className="text-left py-3 px-4 text-[11px] font-semibold uppercase tracking-wider">Account</th>
              <th className="text-left py-3 px-4 text-[11px] font-semibold uppercase tracking-wider">Notes</th>
              <th className="text-right py-3 px-4 text-[11px] font-semibold uppercase tracking-wider w-[120px]">Amount</th>
              <th className="text-right py-3 px-4 text-[11px] font-semibold uppercase tracking-wider w-[100px]">Actions</th>
            </tr>
          </thead>
        </table>
      </div>

      {/* Virtualized body */}
      <div ref={parentRef} className="overflow-auto" style={{ maxHeight }}>
        <div style={{ height: `${virtualizer.getTotalSize()}px`, position: "relative" }}>
          {virtualizer.getVirtualItems().map((virtualRow) => {
            const txn = transactions[virtualRow.index];
            const catColor = resolveCatColor(txn.category, categories);
            const isTransfer = txn.payment_type === "Self Transfer" || txn.category === "Transfer";
            const isChecked = selectedIds.has(txn.id);
            const linkedAccount = allAccounts.find((a) => a.id === txn.account_id);
            const isCreditCard = linkedAccount && creditCards.some((c) => c.id === linkedAccount.id);

