                      <button onClick={() => onDelete(txn.id)} className="text-xs px-2 py-1 rounded-md text-danger/70 hover:text-danger hover:bg-danger/10 transition-colors">Del</button>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

