"use client";

import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useMemo,
  type ReactNode,
} from "react";
import { db } from "@/lib/firebase";
import {
  collection,
  doc,
  onSnapshot,
  query,
  orderBy,
  limit,
  writeBatch,
} from "firebase/firestore";
import { useAuth } from "@/providers/AuthProvider";
import { getFinancialCycle } from "@/utils/financialMonth";
import { setCurrencyFormat } from "@/utils/format";

interface Category {
  id: string;
  name: string;
  color: string;
}

interface Account {
  id: string;
  account_name: string;
  type: string;
  balance?: number;
  liability?: number;
  credit_limit?: number;
  shared_limit_with?: string;
}

interface Transaction {
  id: string;
  date: string;
  amount: number;
  type: string;
  category: string;
  account_id: string;
  description?: string;
  notes?: string;
  payment_type?: string;
  createdAt?: string;
  cycleKey?: string;
  is_recurring?: boolean;
  recurring_frequency?: string;
}

interface RecurringItem {
  id: string;
  description: string;
  category: string;
  amount: number;
  frequency: "weekly" | "monthly" | "yearly";
  next_date: string;
  status: "active" | "paused" | "stopped";
  account_id?: string | null;
  payment_type?: string | null;
  type?: string;
  last_executed?: string | null;
  createdAt?: string;
}

interface Notification {
  id: string;
  type: string;
  title: string;
  message: string;
  read: boolean;
  createdAt: string;
}

interface SplitItem {
  id: string;
  description: string;
  total_amount: number;
  date: string;
  paid_by: string;
  participants: { name: string; share: number }[];
  settled: boolean;
  settlements: { from: string; to: string; amount: number; date?: string }[];
  createdAt?: string;
}

interface Aggregate {
  totalSpent: number;
  totalIncome: number;
  categoryBreakdown: Record<string, number>;
  transactionCount?: number;
}

interface DataContextType {
  accounts: Account[];
  transactions: Transaction[];
  categories: Category[];
  creditCards: Account[];
  recurring: RecurringItem[];
  notifications: Notification[];
  splits: SplitItem[];
  cycleStartDay: number;
  monthlySalary: number;
  currency: string;
  onboardingComplete: boolean | null;
  currentAggregate: Aggregate;
  dataReady: boolean;
  getCategoryById: (id: string) => Category | null;
  getCategoryByName: (name: string) => Category | null;
}

const DEFAULT_CATEGORIES = [
  { name: "Investment", color: "#0080ff" },
  { name: "Rent", color: "#f59e0b" },
  { name: "Home", color: "#8b5cf6" },
  { name: "Food", color: "#ef4444" },
  { name: "Travel", color: "#3b82f6" },
  { name: "Petrol", color: "#f97316" },
  { name: "Entertainment", color: "#ec4899" },
  { name: "Shopping", color: "#14b8a6" },
  { name: "Bills", color: "#64748b" },
  { name: "Utilities", color: "#eab308" },
  { name: "Subscription", color: "#06b6d4" },
  { name: "Lending", color: "#84cc16" },
  { name: "Gifts", color: "#f43f5e" },
  { name: "Income", color: "#10b981" },
  { name: "Other", color: "#94a3b8" },
];

const DataContext = createContext<DataContextType | null>(null);

export function DataProvider({ children }: { children: ReactNode }) {
  const { user } = useAuth();

  const [accounts, setAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [recurring, setRecurring] = useState<RecurringItem[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [splits, setSplits] = useState<SplitItem[]>([]);
  const [cycleStartDay, setCycleStartDay] = useState(25);
  const [monthlySalary, setMonthlySalary] = useState(0);
  const [currency, setCurrency] = useState("INR");
  const [onboardingComplete, setOnboardingComplete] = useState<boolean | null>(null);
  const [dataReady, setDataReady] = useState(false);
  const [currentAggregate, setCurrentAggregate] = useState<Aggregate>({
    totalSpent: 0,
    totalIncome: 0,
    categoryBreakdown: {},
  });

  // Subscribe to Firestore
  useEffect(() => {
    const unsubscribes: (() => void)[] = [];

    const cleanup = () => {
      unsubscribes.forEach((u) => u());
    };

    if (!user) {
      setAccounts([]);
      setTransactions([]);
      setCategories([]);
      setRecurring([]);
      setNotifications([]);
      setSplits([]);
      setCycleStartDay(25);
      setMonthlySalary(0);
      setCurrentAggregate({ totalSpent: 0, totalIncome: 0, categoryBreakdown: {} });
      return cleanup;
    }

    const uid = user.uid;

    // Profile (cycleStartDay, monthlySalary, currency, onboardingComplete)
    unsubscribes.push(
      onSnapshot(doc(db, `users/${uid}`), (snap) => {
        if (snap.exists()) {
          const data = snap.data();
          setCycleStartDay(data.cycleStartDay || 25);
          setMonthlySalary(data.monthlySalary || 0);
          setCurrency(data.currency || "INR");
          // Existing users without the field are treated as already onboarded
          setOnboardingComplete(data.onboardingComplete !== false);
        } else {
          // Doc doesn't exist = brand new user, show onboarding
          setOnboardingComplete(false);
        }
      })
    );

    // Accounts
    unsubscribes.push(
      onSnapshot(collection(db, `users/${uid}/accounts`), (snap) => {
        setAccounts(snap.docs.map((d) => ({ id: d.id, ...d.data() } as Account)));
        setDataReady(true);
      })
    );

    // Transactions (latest 500)
    const txQuery = query(
      collection(db, `users/${uid}/transactions`),
      orderBy("date", "desc"),
      limit(500)
    );
    unsubscribes.push(
      onSnapshot(txQuery, (snap) => {
        const fetched = snap.docs.map((d) => ({ id: d.id, ...d.data() } as Transaction));
        fetched.sort((a, b) => {
          const dateCmp = b.date.localeCompare(a.date);
          if (dateCmp !== 0) return dateCmp;
          return (b.createdAt || "").localeCompare(a.createdAt || "");
        });
        setTransactions(fetched);
      })
    );

    // Categories ΓÇö seed defaults if empty
    const categoriesRef = collection(db, `users/${uid}/categories`);
    unsubscribes.push(
      onSnapshot(categoriesRef, async (snap) => {
        if (snap.empty) {
          const batch = writeBatch(db);
          DEFAULT_CATEGORIES.forEach((cat) => {
            const slug = cat.name.toLowerCase().replace(/[^a-z0-9]/g, "-");
            const docRef = doc(db, `users/${uid}/categories/${slug}`);
            batch.set(docRef, { ...cat, createdAt: new Date().toISOString() });
          });
          await batch.commit();
        } else {
          setCategories(snap.docs.map((d) => ({ id: d.id, ...d.data() } as Category)));
        }
      })
    );

    // Recurring transaction templates
    unsubscribes.push(
      onSnapshot(collection(db, `users/${uid}/recurring`), (snap) => {
        setRecurring(snap.docs.map((d) => ({ id: d.id, ...d.data() } as RecurringItem)));
      })
    );

    // Notifications (last 50, ordered by createdAt desc)
    const notifQuery = query(
      collection(db, `users/${uid}/notifications`),
      orderBy("createdAt", "desc"),
      limit(50)
    );
    unsubscribes.push(
      onSnapshot(notifQuery, (snap) => {
        setNotifications(
          snap.docs.map((d) => {
            const data = d.data();
            return {
              id: d.id,
              type: data.type || "info",
              title: data.title || "",
              message: data.message || "",
              read: data.read || false,
              createdAt: data.createdAt?.toDate?.()?.toISOString() || new Date().toISOString(),
            } as Notification;
          })
        );
      })
    );

    // Splits
    unsubscribes.push(
      onSnapshot(
        query(collection(db, `users/${uid}/splits`), orderBy("createdAt", "desc"), limit(100)),
        (snap) => {
          setSplits(snap.docs.map((d) => ({ id: d.id, ...d.data() } as SplitItem)));
        }
      )
    );

    return cleanup;
  }, [user]);

  // Sync currency format globally
  useEffect(() => {
    setCurrencyFormat(currency);
  }, [currency]);

  // Re-subscribe to aggregates when cycleStartDay changes
  useEffect(() => {
    if (!user) return;
    const uid = user.uid;
    const cycle = getFinancialCycle(new Date(), cycleStartDay);
    const unsub = onSnapshot(
      doc(db, `users/${uid}/aggregates/${cycle.cycleKey}`),
      (snap) => {
        if (snap.exists()) setCurrentAggregate(snap.data() as Aggregate);
        else setCurrentAggregate({ totalSpent: 0, totalIncome: 0, categoryBreakdown: {} });
      }
    );
    return () => unsub();
  }, [user, cycleStartDay]);

  const getCategoryById = useCallback(
    (id: string) => categories.find((c) => c.id === id) || null,
    [categories]
  );

  const creditCards = useMemo(() => accounts.filter((a) => a.type === "credit"), [accounts]);

  const getCategoryByName = useCallback(
    (name: string) => categories.find((c) => c.name === name) || null,
    [categories]
  );

  const value = useMemo(
    () => ({
      accounts,
      transactions,
      categories,
      creditCards,
      recurring,
      notifications,
      splits,
      cycleStartDay,
      monthlySalary,
      currency,
      onboardingComplete,
      currentAggregate,
      dataReady,
      getCategoryById,
      getCategoryByName,
    }),
    [accounts, transactions, categories, creditCards, recurring, notifications, splits, cycleStartDay, monthlySalary, currency, onboardingComplete, currentAggregate, dataReady, getCategoryById, getCategoryByName]
  );

  return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
}

export function useData() {
  const ctx = useContext(DataContext);
  if (!ctx) throw new Error("useData must be used within DataProvider");
  return ctx;
}

